-- Poems batch 339
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c0eadddb-e01f-4451-ab95-7e408dd8487d','呂司空壽','李復','宋','宋诗','song-poetry','','[]','飄飄仙馭出蓬萊，時節新陽動琯灰。',64,'全唐诗/poet.song.61000.json','["飄飄仙馭出蓬萊，時節新陽動琯灰。", "慶閥拱魁三象近，祥源引派九天回。", "磻溪龍虎家璜在，申國風雲舊嶽開。", "聞說清臺占異事，弧南星步入中台。"]'),
('dcf56af2-6015-4270-babc-5e1a28ba4542','贈吳德秀隠士用來韵','李復','宋','宋诗','song-poetry','','[]','不計無成與有成，但能償足百年心。',64,'全唐诗/poet.song.61000.json','["不計無成與有成，但能償足百年心。", "喜營美釀多栽秫，廣蓄奇書盡散金。", "三代遺文鐘鼎古，五湖秋意畫圖深。", "超然真趣誰能識，目送孤鴻撫素琴。"]'),
('cba58b96-8c76-4d11-bc49-b7aadfbc09db','答人見贈','李復','宋','宋诗','song-poetry','','[]','形影何嘗問主賓，真風滿戶養頹齡。',64,'全唐诗/poet.song.61000.json','["形影何嘗問主賓，真風滿戶養頹齡。", "不從田父迷迴駕，但有漁人笑獨醒。", "閑攝高雲遊沆瀣，靜收浮氣借光靈。", "出門無事誰相喜，只對秋山滿眼青。"]'),
('bf690b59-6bc4-4098-a488-4bd54204ff05','答范軻','李復','宋','宋诗','song-poetry','','[]','綏城古語刻兜鞬，何事求犀近水燃。',64,'全唐诗/poet.song.61000.json','["綏城古語刻兜鞬，何事求犀近水燃。", "鄉里後生輕宿學，朝廷新詔急遺賢。", "風回夜月開重暈，驪睡神珠出九淵。", "今日秋臯聞鶴唳，茂先方議斸龍泉。"]'),
('cb50ffce-7ff3-484e-bcfe-e7094a28a987','答李成季','李復','宋','宋诗','song-poetry','','[]','山川錯莫不逢春，京洛空多滿馬塵。',64,'全唐诗/poet.song.61000.json','["山川錯莫不逢春，京洛空多滿馬塵。", "李渤請歸聊見志，魯褒著論久知神。", "懷沙曾愧垂綸客，擊磬興嗟荷蕢人。", "向老愈憐筋力弱，空傷涸轍泣窮鱗。"]'),
('04b47ada-4db6-4c3e-8035-db2ff517843d','答李公藴','李復','宋','宋诗','song-poetry','','[]','臘前曾約走新春，春到無端絕塞行。',64,'全唐诗/poet.song.61000.json','["臘前曾約走新春，春到無端絕塞行。", "戍卒催完燈下甲，急烽連入雪中城。", "萬夫擾擾爭分餉，一飯匆匆豈暇羹。", "自嘆東西求斗祿，兵戈已過十年生。"]'),
('cef8df5b-a13a-47d2-b09a-3ae165bf44c6','答彭同年勸應賢科','李復','宋','宋诗','song-poetry','','[]','早歲逢予嘆陸沉，東風還更枉華音。',64,'全唐诗/poet.song.61000.json','["早歲逢予嘆陸沉，東風還更枉華音。", "五蹄一角必殊相，八跪二螯多躁心。", "衆惜伏轅傷駿骨，自慚躍冶匪祥金。", "摶風敢效垂天翼，但樂孤巢寄舊林。"]'),
('b140094d-345d-44dc-8d15-e8f79d5886c8','答李晝宣德示詩卷','李復','宋','宋诗','song-poetry','','[]','志學長年患小成，五言今喜繼家聲。',64,'全唐诗/poet.song.61000.json','["志學長年患小成，五言今喜繼家聲。", "因君筆墨多新語，滿路雲山得美名。", "才業未堪高卧顯，篇章自欲以文鳴。", "歸時正是春風好，擁轡應教取次行。"]'),
('46075d70-fc00-4f57-b35d-e91fbf413ba8','哀秦金部','李復','宋','宋诗','song-poetry','','[]','少年書卷是生涯，白屋清朝自起家。',64,'全唐诗/poet.song.61000.json','["少年書卷是生涯，白屋清朝自起家。", "數上封章思有補，一生悃愊靜無華。", "初瞻玉節星軺下，俄見銘旌粉篆斜。", "天理冥冥誰可度，但傷零落掩淮沙。"]'),
('4e5cbfe3-e8b4-469e-ae56-69812556dfdc','王夫人輓詞  其一','李復','宋','宋诗','song-poetry','','[]','家聲昔冠秦中望，婦學今傳潁上風。',64,'全唐诗/poet.song.61000.json','["家聲昔冠秦中望，婦學今傳潁上風。", "百歲流光方過半，新春逝水忽馳東。", "丹山鳳泣歸巢冷，寒月烏啼反哺空。", "他日拂絃悲舊曲，應將哀恨寄孤桐。"]'),
('a56af273-8c91-45d2-8279-6bc4d499da06','王夫人輓詞  其二','李復','宋','宋诗','song-poetry','','[]','鬰鬰佳城潁水涯，素旌今見出重扉。',64,'全唐诗/poet.song.61000.json','["鬰鬰佳城潁水涯，素旌今見出重扉。", "不逢玉鼎仙丹轉，忍見春風畫翣歸。", "馬鬣起封占鶴表，錦書賜邑得烏衣。", "須知千古芳魂在，漠漠孤雲嶺上飛。"]'),
('4f425e30-850a-4d35-889b-46e32abd26f2','弔朱給事','李復','宋','宋诗','song-poetry','','[]','筮仕西州佐邑時，高才不厭簿書卑。',64,'全唐诗/poet.song.61000.json','["筮仕西州佐邑時，高才不厭簿書卑。", "清修與衆初難合，真節當朝晚始知。", "諫苑塵埃多舊藁，佛宮粉繪有生祠。", "與君家世重重契，祖奠靈車涕滿頤。"]'),
('ab4fb5c9-2124-4beb-93b0-0942c29c08cd','棣華齋','李復','宋','宋诗','song-poetry','','[]','真長世譽賢兄弟，棠棣名齋爲學詩。',64,'全唐诗/poet.song.61000.json','["真長世譽賢兄弟，棠棣名齋爲學詩。", "華厦何妨因舊址，春風不老是仙枝。", "攀條漸見傳芳遠，和氣先從近本知。", "顧我彫零長弔影，感今徒益鬢如絲。"]'),
('48934004-6253-40af-822f-8d04edbf6db0','託人求田','李復','宋','宋诗','song-poetry','','[]','綠遶隨城潏水流，百年那免問菟裘。',64,'全唐诗/poet.song.61000.json','["綠遶隨城潏水流，百年那免問菟裘。", "泉甘易汲能蠲疾，土沃翻耕每報秋。", "欲託高人論地券，共期他日老漁舟。", "歸身未到心先到，得此餘無一事求。"]'),
('cd9eea94-fabc-49d0-a7c9-0181cada8ebb','殘編','李復','宋','宋诗','song-poetry','','[]','殘編斷簡事寥寥，購輯成書匪一朝。',64,'全唐诗/poet.song.61000.json','["殘編斷簡事寥寥，購輯成書匪一朝。", "韋述投山藏舊史，肩吾去國失宮謠。", "須知孔壁遺文在，豈逐秦燔烈焰銷。", "博學多聞予所仰，喜君携笈過衡茅。"]'),
('28069162-686b-472c-86ba-043637c9bd9c','青布道人','李復','宋','宋诗','song-poetry','','[]','逸意閒雲野鶴孤，藥苗山葉綴衣裾。',64,'全唐诗/poet.song.61000.json','["逸意閒雲野鶴孤，藥苗山葉綴衣裾。", "新蒸石卵將留飯，戲酌銅盤便得魚。", "療疾但分庵畔草，吐言不出世間書。", "五年密密求真訣，始露三元御氣車。"]'),
('adef8efe-6bba-4224-b760-26fa22601d67','道士李得柔行太乙法曾傳御容','李復','宋','宋诗','song-poetry','','[]','處世能求出世心，石壇深夜禮星辰。',64,'全唐诗/poet.song.61000.json','["處世能求出世心，石壇深夜禮星辰。", "徧遊五岳求真訣，獨向三清有主人。", "妙筆曾開天日曉，懸壺常鎖洞山春。", "不知何事飛符動，又見荒林聚鬼神。"]'),
('963335ad-d747-4379-b18d-032a70166198','予昔爲河東漕屬吏部郎中呂得和出總漕計與予情均兄弟後開府荆渚惠書有人生難得相知之語予後官守鎮京兆聞呂之訃因發篋得舊詩感而作此','李復','宋','宋诗','song-poetry','','[]','三年發篋墨猶新，蹤跡雖疏意更親。',64,'全唐诗/poet.song.61000.json','["三年發篋墨猶新，蹤跡雖疏意更親。", "雲霧渚宮迷遠夢，兵戈青海困飛塵。", "飄零劍外參謀客，愴惻山陽感舊人。", "今古交情如覆水，爲君涕淚灑新春。"]'),
('4781d182-b9c9-481a-af26-3c1c9e188c58','李毅師載出塞歸熟食日邀客湖上有詩求和遂用其韵','李復','宋','宋诗','song-poetry','','[]','新知劍外朱兼阮，舊侶江邊白與張。',96,'全唐诗/poet.song.61000.json','["新知劍外朱兼阮，舊侶江邊白與張。", "去國杜翁爲客久，傳詩韓老遇春忙。", "一年喜競清明日，千里歸從戰伐場。", "山寺雪消雲已暖，湖亭冰盡水生光。", "半生幾見逢三雅，此舉無辭略百觴。", "莫負高名興苦歎，靜中閱盡喜難忘。"]'),
('390b454b-3e49-4e5b-879f-6b0778f6aa93','宿興德寺','李復','宋','宋诗','song-poetry','','[]','東峰霽月出，林叢寒露明。',24,'全唐诗/poet.song.61000.json','["東峰霽月出，林叢寒露明。", "夜久風漸息，深院無人聲。"]'),
('312eb715-3b70-4768-9a23-c7dfad4cefc5','登後峽寨北山','李復','宋','宋诗','song-poetry','','[]','薄落山前菊未開，鬰孤水畔獨登臺。',32,'全唐诗/poet.song.61000.json','["薄落山前菊未開，鬰孤水畔獨登臺。", "明朝匹馬衝霜去，直到鳴沙北始回。"]'),
('5724827c-ed10-4ce1-9576-27908b810239','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其一','李復','宋','宋诗','song-poetry','','[]','柔桑葉菀暗東岡，山下亂石如羣羊。',32,'全唐诗/poet.song.61000.json','["柔桑葉菀暗東岡，山下亂石如羣羊。", "舊沙漸高行路斷，馬蹄踏散飛星光。"]'),
('79710e7f-a724-404d-8443-bc9f40d2b845','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其二','李復','宋','宋诗','song-poetry','','[]','繰絲宛轉聽車聲，車聲忽斷心暗驚。',32,'全唐诗/poet.song.61000.json','["繰絲宛轉聽車聲，車聲忽斷心暗驚。", "舊機虛張未滿幅，新絲更短織不成。"]'),
('55617896-c3c6-434f-a841-901720d4142c','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其三','李復','宋','宋诗','song-poetry','','[]','東來健兒身手長，不隨伍籍習弓鎗。',32,'全唐诗/poet.song.61000.json','["東來健兒身手長，不隨伍籍習弓鎗。", "何須官廩請租稅，白晝衣食出道傍。"]'),
('5d05fcf5-40e9-4e5f-a584-9be8ef0da069','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其四','李復','宋','宋诗','song-poetry','','[]','短衫窄袖上馬輕，空手常喜烟塵行。',32,'全唐诗/poet.song.61000.json','["短衫窄袖上馬輕，空手常喜烟塵行。", "論功何須問弓劍，自有主將知姓名。"]'),
('294a7e6b-7c7d-499d-85de-329382a29a7a','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其五','李復','宋','宋诗','song-poetry','','[]','牛車欲住更催行，官要刻日到新城。',32,'全唐诗/poet.song.61000.json','["牛車欲住更催行，官要刻日到新城。", "軍有嚴期各努力，秋田無種何須耕。"]'),
('170cde15-7441-4a6b-9b63-4a97cc6b78cd','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其六','李復','宋','宋诗','song-poetry','','[]','蕃兵入市爭賣田，漢人要田蕃無錢。',32,'全唐诗/poet.song.61000.json','["蕃兵入市爭賣田，漢人要田蕃無錢。", "有田賣盡走蕃去，却引生羌來寇邊。"]'),
('9bca397f-17e0-455a-999d-db0439cd25ed','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其七','李復','宋','宋诗','song-poetry','','[]','白羌紛紛急攻城，羌酋却走殺漢民。',32,'全唐诗/poet.song.61000.json','["白羌紛紛急攻城，羌酋却走殺漢民。", "漢民當前死不惜，甌脫更有殺來人。"]'),
('bd5bbb79-2678-4b00-ba0a-54886dbd00bd','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其八','李復','宋','宋诗','song-poetry','','[]','隴山連峰入無際，天畫封疆限華裔。',32,'全唐诗/poet.song.61000.json','["隴山連峰入無際，天畫封疆限華裔。", "如何谽谺忽中裂，西通風來動邊氣。"]'),
('66e36cd2-4d6d-4657-b8d6-15416501aa41','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其九','李復','宋','宋诗','song-poetry','','[]','鳴鳳山西五里坂，未渡汧河山漸淺。',32,'全唐诗/poet.song.61000.json','["鳴鳳山西五里坂，未渡汧河山漸淺。", "東來行人漸長嘆，已覺秦川不在眼。"]'),
('34d3e24e-469a-4571-9306-e4052c2c54f4','予往來秦熙汧隴間不啻十數年時聞下里之歌遠近相繼和高下掩抑所謂其聲嗚嗚也皆含思宛轉而有餘意其辭甚陋因其調寫道路所聞見猶昔人竹枝紇羅之曲以補秦之樂府云  其一○','李復','宋','宋诗','song-poetry','','[]','垂白東西幾田父，林間偶坐忘巾履。',32,'全唐诗/poet.song.61000.json','["垂白東西幾田父，林間偶坐忘巾履。", "共說乾餱付遠人，六月長丁猶築戍。"]'),
('b4d6eea4-4900-4959-b64a-b9088ece131c','予幼侍先人作邑夏陽元豐五年來攝是邑過瀵泉題其亭壁','李復','宋','宋诗','song-poetry','','[]','井邑依然舊物華，行穿溪樹踏溪沙。',32,'全唐诗/poet.song.61000.json','["井邑依然舊物華，行穿溪樹踏溪沙。", "路傍故老遥驚認，十七年前縣令家。"]'),
('44137941-09ef-4b2c-8a3c-ea807c197c40','再授雲臺觀過華陰題此','李復','宋','宋诗','song-poetry','','[]','脫身西去度函關，踏雪重過阿對泉。',32,'全唐诗/poet.song.61000.json','["脫身西去度函關，踏雪重過阿對泉。", "又作蓮花峰上客，祥飈高御紫虛天。"]'),
('2ce0e908-4343-44a9-ba20-d7d505780b5c','過方山驛','李復','宋','宋诗','song-poetry','','[]','驚塵拂面三千里，走馬東西不識春。',32,'全唐诗/poet.song.61000.json','["驚塵拂面三千里，走馬東西不識春。", "忽見長堤新柳色，一時聊慰倦行人。"]'),
('13be107a-cfab-4ec7-9b83-6deaf6dfb9c2','飛泉','李復','宋','宋诗','song-poetry','','[]','銀河一道下天來，蒼壁衝雲萬仞開。',32,'全唐诗/poet.song.61000.json','["銀河一道下天來，蒼壁衝雲萬仞開。", "白浪駕風千石轉，四時不斷響驚雷。"]'),
('a2729de6-0e92-4983-81b9-e688e135dd16','卧龍院','李復','宋','宋诗','song-poetry','','[]','杲日珠光照舊都，試從雞足躡蓮趺。',32,'全唐诗/poet.song.61000.json','["杲日珠光照舊都，試從雞足躡蓮趺。", "橫身何用論明暗，果是能揮寶劍無。"]'),
('89c116d0-2493-4035-a08b-7660c6ee9a85','留題北禪院','李復','宋','宋诗','song-poetry','','[]','偶到叢林訪可休，南山依舊滿晴樓。',32,'全唐诗/poet.song.61000.json','["偶到叢林訪可休，南山依舊滿晴樓。", "垂鈎漫有深潭興，徧滿乾坤是即收。"]'),
('46aaaf1b-783a-4d3b-a2ff-4143ee189a39','隴州神泉鋪後池','李復','宋','宋诗','song-poetry','','[]','山腰綠映女郎祠，祠下泉通竹下池。',32,'全唐诗/poet.song.61000.json','["山腰綠映女郎祠，祠下泉通竹下池。", "時有游鯈自來去，祗應曾見理鈎絲。"]'),
('03973eb9-ef22-4fa2-a1ac-a7aaacde49cf','題甘茂祠','李復','宋','宋诗','song-poetry','','[]','奮身孤旅相秦王，欲去憂讒論樂羊。',32,'全唐诗/poet.song.61000.json','["奮身孤旅相秦王，欲去憂讒論樂羊。", "不有私金助公賞，可能明日拔宜陽。"]'),
('0ce18eda-3f46-4f44-8b3c-3e31f1ffb23c','王導','李復','宋','宋诗','song-poetry','','[]','鄒人羞比管夷吾，可復中原盡羯胡。',32,'全唐诗/poet.song.61000.json','["鄒人羞比管夷吾，可復中原盡羯胡。", "郊壘連雲困衣食，縱高練布得充無。"]'),
('c9743ebe-010f-4be2-af25-05cbde9801df','曹參廟','李復','宋','宋诗','song-poetry','','[]','百戰皆收第一功，幾回旁嘆泣良弓。',32,'全唐诗/poet.song.61000.json','["百戰皆收第一功，幾回旁嘆泣良弓。", "白頭始識人間事，歸向東州問蓋公。"]'),
('64bc0a3d-9081-4d87-bf21-e9169bb6e8aa','王翦','李復','宋','宋诗','song-poetry','','[]','少李輕兵去不回，荆人勝氣鼓如雷。',32,'全唐诗/poet.song.61000.json','["少李輕兵去不回，荆人勝氣鼓如雷。", "將軍料敵元非怯，能使君王促駕來。"]'),
('bad8256e-04d7-4ac0-9f74-4dc2a7383a1d','孟嘉','李復','宋','宋诗','song-poetry','','[]','不將得失供談笑，此語宜爲盛德人。',32,'全唐诗/poet.song.61000.json','["不將得失供談笑，此語宜爲盛德人。", "千里同風皆默契，褚裒故識坐中身。"]'),
('b305aea1-8a36-49eb-ad53-6d4583d920fc','陶淵明','李復','宋','宋诗','song-poetry','','[]','接輿歌鳳溺沮耕，獨往何堪與世親。',32,'全唐诗/poet.song.61000.json','["接輿歌鳳溺沮耕，獨往何堪與世親。", "投紱歸來眠北牖，高風自是葛天民。"]'),
('e3097bc5-85e0-4920-b694-e2448ae39525','二月五日柳溪遇風','李復','宋','宋诗','song-poetry','','[]','狂風擺撼未肯休，直須枯枿生新柔。',32,'全唐诗/poet.song.61000.json','["狂風擺撼未肯休，直須枯枿生新柔。", "老松倚雲不關意，開落曾閱幾春秋。"]'),
('38db122c-8d30-4d00-8d7e-3634b584bad2','秋庭夜閒步','李復','宋','宋诗','song-poetry','','[]','高秋夜氣聲驚竹，寒月徘徊影趁人。',32,'全唐诗/poet.song.61000.json','["高秋夜氣聲驚竹，寒月徘徊影趁人。", "此境靜觀如啖蔗，後來細嚼味尤真。"]'),
('5d2f4d74-a335-4279-b98d-a521e9f83ef8','答安陽叔兩絕  其一','李復','宋','宋诗','song-poetry','','[]','春風吹園雜花開，漸老逢春能幾回。',32,'全唐诗/poet.song.61000.json','["春風吹園雜花開，漸老逢春能幾回。", "不嫌野外無供給，一杯一杯復一杯。"]'),
('83e66801-6215-467d-bb62-5c4d05bc55cf','答安陽叔兩絕  其二','李復','宋','宋诗','song-poetry','','[]','兩人對酌山花開，青天露坐始此回。',32,'全唐诗/poet.song.61000.json','["兩人對酌山花開，青天露坐始此回。", "嗟我與君皆老矣，且盡尊前有限杯。"]'),
('5d844fb5-e89d-465a-9a71-8e11760ecbef','謁詩僧慧益不遇','李復','宋','宋诗','song-poetry','','[]','晝公昔在雲門寺，曾笑陳丘久不歸。',32,'全唐诗/poet.song.61000.json','["晝公昔在雲門寺，曾笑陳丘久不歸。", "草坐麻衣今不見，獨來林下釣寒磯。"]'),
('65520ed2-a0b5-43eb-89ef-bbf4fc6f061d','和崔珙望子嶺觀梅','李復','宋','宋诗','song-poetry','','[]','高枝疏淡小花頭，開向殘春破客愁。',32,'全唐诗/poet.song.61000.json','["高枝疏淡小花頭，開向殘春破客愁。", "點墨空山慰寒晚，却如何遜在揚州。"]'),
('1e193b7d-c1f5-482d-8b34-cf4f2a2dee73','崔珙推官話王園再如昔年爲梅下之會并示絕句和來韵','李復','宋','宋诗','song-poetry','','[]','王家梅樹春常早，露坐曾侵月影來。',32,'全唐诗/poet.song.61000.json','["王家梅樹春常早，露坐曾侵月影來。", "聞道去年還得意，新花還似舊時開。"]'),
('07f3f61e-ccda-46b2-b86a-ffdaefd00dc6','閻先復朝議園牡丹一本四月始開予與李成季同往觀閻求詩遂書絕句於其壁','李復','宋','宋诗','song-poetry','','[]','淺蘂凡葩不自持，紛紛競鬭早春時。',32,'全唐诗/poet.song.61000.json','["淺蘂凡葩不自持，紛紛競鬭早春時。", "高情獨負無人識，落盡羣花晚始知。"]'),
('11740595-600b-4c8a-8ab8-a7956eb4a212','戲書德公軒後桃花  其一','李復','宋','宋诗','song-poetry','','[]','百葉仙桃倚故臺，劉郎去後幾時栽。',32,'全唐诗/poet.song.61000.json','["百葉仙桃倚故臺，劉郎去後幾時栽。", "紅塵拂面人來看，只有靈雲放眼開。"]'),
('29e702bc-d5d2-4797-92ab-48bf53c9736f','戲書德公軒後桃花  其二','李復','宋','宋诗','song-poetry','','[]','花發雙林七寶臺，出門是草不須栽。',32,'全唐诗/poet.song.61000.json','["花發雙林七寶臺，出門是草不須栽。", "東風一夜都收去，爲問仙桃甚處開。"]'),
('b0df32ad-cdb6-42d2-ac2d-7c4ec9dd350e','和張總管菊  其一','李復','宋','宋诗','song-poetry','','[]','雲裏霓裳閑儼雅，霜前黄鵠獨軒昂。',32,'全唐诗/poet.song.61000.json','["雲裏霓裳閑儼雅，霜前黄鵠獨軒昂。", "不從春意裝褫巧，却被秋風漏泄香。"]'),
('6f269aaf-4155-4030-9364-e1b9d55923e1','和張總管菊  其二','李復','宋','宋诗','song-poetry','','[]','開落紛紛不自知，春秋莫較後先期。',32,'全唐诗/poet.song.61000.json','["開落紛紛不自知，春秋莫較後先期。", "清霜滿地凋零急，正是黄花得意時。"]'),
('50556c20-8c59-406e-a6aa-1b0ac2d6462a','和呂吏部觀延慶院李唐畫山水  其一','李復','宋','宋诗','song-poetry','','[]','道人曾去禮清凉，幻出臺山翠壁光。',32,'全唐诗/poet.song.61000.json','["道人曾去禮清凉，幻出臺山翠壁光。", "聞說幻師能幻幻，烟雲草樹攝他方。"]'),
('4f74e46f-fd17-4e31-932a-cac3b4db356e','和呂吏部觀延慶院李唐畫山水  其二','李復','宋','宋诗','song-poetry','','[]','遊戲仙人出道場，寶山珠樹發神光。',32,'全唐诗/poet.song.61000.json','["遊戲仙人出道場，寶山珠樹發神光。", "坐間舉手分天界，移入毗耶一室方。"]'),
('b729ec98-e7d1-4949-a0bb-ca66d0fc958b','和呂吏部觀延慶院李唐畫山水  其三','李復','宋','宋诗','song-poetry','','[]','深蒨雲嵐遠意蒼，寶伽猶带海波光。',32,'全唐诗/poet.song.61000.json','["深蒨雲嵐遠意蒼，寶伽猶带海波光。", "須知應感神通力，舉步相隨徧十方。"]'),
('753918e8-dea9-49c2-9112-4733dfc764f2','題畫馬圖','李復','宋','宋诗','song-poetry','','[]','龍種天駒産渥洼，五雲毛色散成花。',32,'全唐诗/poet.song.61000.json','["龍種天駒産渥洼，五雲毛色散成花。", "瑶池一去無消息，只許丹青紙上誇。"]'),
('6bae28c4-bd75-47b2-9887-cb15a8f204ae','題嚴賢良東山集','李復','宋','宋诗','song-poetry','','[]','謝公高志渺浮雲，對弈從容靜世紛。',32,'全唐诗/poet.song.61000.json','["謝公高志渺浮雲，對弈從容靜世紛。", "坐客偶然談小草，無言徒媿郝參軍。"]'),
('dd39f652-74ab-44aa-a00e-b24d26a44520','項城主簿趙岍求書惹雲亭爲系二絕  其一','李復','宋','宋诗','song-poetry','','[]','東西飄忽本無心，留礙危簷便不禁。',32,'全唐诗/poet.song.61000.json','["東西飄忽本無心，留礙危簷便不禁。", "向晚前山風力薄，等閒相引作輕陰。"]'),
('5c707e68-3357-4382-9ccd-1256532a6682','項城主簿趙岍求書惹雲亭爲系二絕  其二','李復','宋','宋诗','song-poetry','','[]','白雲曾與閒人約，爲怪貪忙久不來。',32,'全唐诗/poet.song.61000.json','["白雲曾與閒人約，爲怪貪忙久不來。", "飛過孤亭訪消息，也還遮莫未能回。"]'),
('72f3e639-33cf-4c09-8ec1-14d4586a25a5','和人觀木戲','李復','宋','宋诗','song-poetry','','[]','百尺高竿巧捷身，竿頭立定鬭尖新。',32,'全唐诗/poet.song.61000.json','["百尺高竿巧捷身，竿頭立定鬭尖新。", "更呈失脚翻身樣，平地旁觀亦損神。"]'),
('73ba20d9-5f19-4e8c-b6f5-9b2be6c19fe0','樂章五曲  其一','李復','宋','宋诗','song-poetry','','[]','南山深，雲冥冥。',101,'全唐诗/poet.song.61000.json','["南山深，雲冥冥。", "蒼松長，寒楓陰。", "紫檀椒堂白玉庭，千年桂樹落子青。", "吉日矣辰良，浴蘭兮佩芳。", "穆將愉兮神君，沛荃旗而來翔。", "青霓叩額通綠章，鴻龍開門宮中香。", "望君御兮前渚，再拜兮起舞。", "時不可兮再得，聊徜徉而容與。"]'),
('97aa726d-f58a-45f5-bc80-aa43742aa19c','樂章五曲  其二','李復','宋','宋诗','song-poetry','','[]','海日上天破苦霧，散香釃酒巫進舞，神在琵琶弦上語。',128,'全唐诗/poet.song.61000.json','["海日上天破苦霧，散香釃酒巫進舞，神在琵琶弦上語。", "載鸞旂，伐鼉鼓，驅豐隆，笑玉女，小雨班班點飛土。", "駕文螭兮張翠羽，蘭爲旌兮桂爲斧。", "神車出兮青山空，留應龍兮守山宮。", "古烟蒼蒼封寒松，流水濺濺山重重。", "促前導兮走輕雷，駐清馭兮雲低回。", "石壇漠漠風幃開，鄉人奠拜神君來。"]'),
('be138902-645a-440d-8201-bb58af727138','樂章五曲  其三','李復','宋','宋诗','song-poetry','','[]','霧光散兮曈曈，蘪蕪青兮椒紅。',110,'全唐诗/poet.song.61000.json','["霧光散兮曈曈，蘪蕪青兮椒紅。", "石上菖蒲生紫茸，曲嶼蘋長絲影重。", "雉鷕鷕兮鹿伎伎，圓鱗金光出寒水。", "碧鼎收香養雲子，三脊白茅斷爲委。", "平壺玉酒清於空，開壺芳新破曉風。", "罍前洗爵奠當中，海南沉水烟濛濛。", "人有誠，神有靈，幽明通，薦芳馨。"]'),
('6fd9058a-fa36-49f7-a84d-20347b60e9ed','樂章五曲  其四','李復','宋','宋诗','song-poetry','','[]','刻花圓楹青玉趺，高堂䡾䡾雲錦舒。',124,'全唐诗/poet.song.61000.json','["刻花圓楹青玉趺，高堂䡾䡾雲錦舒。", "兩階納陛先登巫，近前神喜巫歌呼。", "揚桴兮拊鼓，金鳴兮竹語。", "長絲哀怨雁移步，堂上聲歌堂下舞。", "工祝濯柳灑庭戶，神君功多人有主。", "風清氣微散時雨，上無螟蛉下無鼠。", "川滿秔兮陸滿黍，少婦窗間弄機杼。", "鄉人相勸醉場圃，敬拜神君芘吾土。"]'),
('019b6c24-60f3-497a-ad2b-df46ca5e4f12','樂章五曲  其五','李復','宋','宋诗','song-poetry','','[]','鼓急兮收舞影，火銷兮膏燼冷。',118,'全唐诗/poet.song.61000.json','["鼓急兮收舞影，火銷兮膏燼冷。", "鄉人出門女巫醉，日下西山起陰暝。", "荇葉光，青幡長。", "壇前旗影動回風，飛電忽轉雷隆隆。", "玉劍蓮花碧珠佩，喜雲低來有酒氣。", "浮空皓皓從歸轡，千騎無聲去如水。", "龍車獸鬼不踏塵，迅霆一擊開山門。", "神兮神兮愛吾人，千年置社樂神君。"]'),
('347c69a5-b181-4292-a832-b8332a897080','叢臺歌','賀鑄','宋','宋诗','song-poetry','','[]','累土三百尺，流火二千年。',189,'全唐诗/poet.song.61000.json','["累土三百尺，流火二千年。", "人生物數不相待，摧頹故址秋風前。", "武靈舊壠今安在，禿樹無陰困樵采。", "玉簫金鏡未銷沈，幾見耕夫到城賣。", "君不見叢臺全盛時，綺羅成市遊春暉。", "一從琱輦閉荒草，蕭散行雲無復歸。", "韶魂想像風流在，晴華露蔓猶依稀。", "盤紆棘逕撩人衣，禾黍晚成貊貉肥。", "層簷碧瓦碎平地，夢作鴛鴦相伴飛。", "登臨弔古將語誰，城郭人民今是非。", "指君看取故時物，南有清流西翠微。", "彷徨華表不忍去，豈獨遼東丁令威。"]'),
('cab39526-62a6-41bf-a42f-efcaf3947182','黄樓歌','賀鑄','宋','宋诗','song-poetry','','[]','君不見熙寧丁巳秋，靈平未塞河橫流。',197,'全唐诗/poet.song.61000.json','["君不見熙寧丁巳秋，靈平未塞河橫流。", "澶漫勢欲浮東州，斯人坐有爲魚憂。", "當時賢守維蘇侯，厭術不取三犀牛。", "跨城岧嶢起黄樓，五行相推土勝水，鼉作黿驚走鞭箠。", "三丈渾流變清泚，南來船車鷁銜尾。", "使君登覽興如何，舞劍吟箋賓從多。", "水平照影見雁下，山空答響聞漁歌。", "樓下汀洲長芳草，一麾南出彭門道。", "昨日春遊詠白蘋，後夜秋風悲鵩鳥。", "黄岡汝海心悠哉，青衫白髮多塵埃。", "采菱伎女今何在，騎竹兒童望不來。", "望不來，碧雲明月長裴徊。"]'),
('b61d1a5c-e2c7-4e70-8afb-1a03ca9982e5','彭城三詠 戲馬臺歌','賀鑄','宋','宋诗','song-poetry','','[]','秦蛇已中斷，劉項方龍戰。',139,'全唐诗/poet.song.61000.json','["秦蛇已中斷，劉項方龍戰。", "叱咤沮風雲，睢盱走霆電。", "鴻溝一畫天地開，楚王洗劍東歸來。", "新都形勝控淮泗，籠山絡谷營高臺。", "重瞳登覽何爲者，不知招賢知戲馬。", "上如激矢下投丸，蘭筋霜腕便回盤。", "半夜悲歌騅不逝，明日陰陵行路難。", "騋牝三千歸漢閑，粟豆尤聞蠹縣官。", "君不見華山之陽古坰牧，春風吹草年年綠。"]'),
('cda16143-270d-40c0-a3a9-5ade492ef7d9','彭城三詠 斬蛇澤歌','賀鑄','宋','宋诗','song-poetry','','[]','君不聞泗濱亭長送徒如咸陽，徒夫懷歸多道亡。',149,'全唐诗/poet.song.61000.json','["君不聞泗濱亭長送徒如咸陽，徒夫懷歸多道亡。", "澤中置酒飲相訣，吾亦從此奔芒碭。", "陰風蕭蕭導者懼，前有脩蛇怒橫路。", "酒酣拔劍肯留行，劃斷蜿蜒不回顧。", "河明月出人踵來，彼媼何冤號且哀。", "謂遭赤帝屠吾子，語竟莫知安在哉。", "真人聞此自心許，茫茫四海吾其主。", "虎變龍飛十二年，馘項梟英蓋狐鼠。", "半夜雄鋩飛上天，幾見長陵一抔土。"]'),
('dabdfcdc-7ebf-4a8b-909a-544e9ced2eec','彭城三詠 歌風臺詞','賀鑄','宋','宋诗','song-poetry','','[]','漢祖高風百尺臺，千年客土生蒿萊。',131,'全唐诗/poet.song.61000.json','["漢祖高風百尺臺，千年客土生蒿萊。", "何窮人事水東去，如故地形山四來。", "江淮猶沸鯨鯢血，八十一車枉歸轍。", "白叟逢迎皆故人，牢酒歡呼惜將別。", "崤澠迢遥非我鄉，死生此地何能忘。", "酒闌鳴筑動雲物，青衿兒曹隨抑揚。", "爾時可無股肱良，端思猛士守四方。", "君不聞淮陰就縛何慨慷，解道鳥盡良弓藏。"]'),
('9023e922-6c32-40c8-a401-cdc9064b49aa','漁歌','賀鑄','宋','宋诗','song-poetry','','[]','嚴公桐江上，呂父清渭濱。',88,'全唐诗/poet.song.61000.json','["嚴公桐江上，呂父清渭濱。", "出處兩能事，寥寥乎若人。", "擁蓑芘笠吳儂子，身偶一竿生寄水。", "侯庖富饌美鰣鱸，寸鬣分鱗辱刀机。", "吾將一鈎懸十犍，笑倚扶桑不計年。", "鯤鯨懷餌脫相得，坐使東南飫食鮮。"]'),
('7ad4b1ce-3b41-4c11-8c3f-516db8d9575b','江南曲','賀鑄','宋','宋诗','song-poetry','','[]','遊倡搴杜若，別浦鴛鴦落。',56,'全唐诗/poet.song.61000.json','["遊倡搴杜若，別浦鴛鴦落。", "向晚鯉魚風，客檣千里泊。", "當時桃葉是新聲，千載長餘隔水情。", "烏衣巷裏人誰在，白鷺洲邊草自生。"]'),
('8b73928e-a43c-42d2-804e-e504cd3face9','三鳥詠 提壺引','賀鑄','宋','宋诗','song-poetry','','[]','綠野带江春漠漠，露溼花蔫朝暮薄。',165,'全唐诗/poet.song.61000.json','["綠野带江春漠漠，露溼花蔫朝暮薄。", "年芳婉娩欲辭人，啼鳥殷勤勸行樂。", "提壺真起予，十千美酒當賸沽。", "金龜寶貂家所無，持底可過黄公壚。", "調官東來今幾日，謂有公田宜種秫。", "朝廷未除私釀律，安得一試焦革術。", "提壺鳥，嘆吾與爾皆悠悠。", "君不見長安兩市多高樓，大書酒旆招貴遊。", "脫聞提壺鳴樹頭，論槽買甕更獻酬。", "庶幾此聲知所投，胡爲南鄉長滯留，端使北宗狂客羞。"]'),
('0ce856d5-0e0e-40b2-a5a8-1e8e0bde53ae','三鳥詠 竹雞詞','賀鑄','宋','宋诗','song-poetry','','[]','東南澤國陂塘闊，旱歲少逢晴五月。',211,'全唐诗/poet.song.61000.json','["東南澤國陂塘闊，旱歲少逢晴五月。", "田間蛙喜雨冥冥，竹下雞啼泥滑滑。", "而予不耕陂下田，田皋驅馬揮長鞭。", "稻塍微茫絕復連，如躡鏡面流鮫涎。", "植蹄沮洳不敢前，何暇顧惜青蓮乾。", "竹雞鳥，汝幸飛翔羅罻外，安知此塗吁可畏。", "雄雌更鳴方自慰，汝不能言意爲對。", "君不見日圍赫赫是長安，大明宮闕開雲端。", "雞人唱漏辰三刻，左右相君朝謁還。", "前騶誰敢干，後乘不可攀。", "飄颻青蓋望已遠，綠槐陰下沙隄閑。", "長隄千步沙漫漫，風不驚塵雨亦乾。", "君能馳騖此其所，何事江鄉行路難。"]'),
('12f727ce-57ff-48e6-90de-76f17c4493cc','三鳥詠 子規行','賀鑄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江靡迤山坡陀，旅竹荒松蒙蔦蘿。',154,'全唐诗/poet.song.61000.json','["長江靡迤山坡陀，旅竹荒松蒙蔦蘿。", "蠶初眠起風日暖，梅弄黄時烟雨多。", "山間有徑行逶迤，倦客據鞍生睡魔，奈爾思歸啼鳥何。", "子規鳥，不如歸去好。", "誰家西北最高樓，幾爲王孫怨芳草。", "子規憐爾解歸飛，我獨何心長不歸。", "十年迹絕蘇門道，夢裏舊遊知是非。", "一官竊食官倉米，十口之家飽而已。", "金印錦衣耀閭里，少年此心今老矣，問舍求田從此始。"]'),
('6002927b-8d06-47bf-a978-8b24e678dfbf','東華馬上懷寄清凉和公兼簡社中王拙居士','賀鑄','宋','宋诗','song-poetry','','[]','雞鳴紞五鼓，驅馬東華路。',128,'全唐诗/poet.song.61000.json','["雞鳴紞五鼓，驅馬東華路。", "月落潮上時，雲披日生處。", "搖搖漁艇子，挂席淩江去。", "送目思悠悠，橫槊聊一賦。", "鴻雁南飛江北流，亭亭雙塔是昇州。", "前朝物色今何見，白鷺平沙接石頭。", "石頭城上清凉國，中有彌天大比丘。", "右軍遠孫傲時者，巾鉢久從蓮社遊。", "吾亦明年及瓜代，一庵見寄外何求。"]'),
('d75eb160-f213-44ad-9c0b-b6763fcbb219','廣四愁寄李譓','賀鑄','宋','宋诗','song-poetry','','[]','夜如何其夜未央，斗星燦兮河蒼凉。',252,'全唐诗/poet.song.61000.json','["夜如何其夜未央，斗星燦兮河蒼凉。", "微月入牖窺曲房，候蟲刺促鳴我牀。", "離憂欻來煎人腸，夜如何其夜何長。", "綠琴在薦兮，擬楚奏之沈湘。", "朱絃溼露兮，聲戾指而不揚。", "屏琴浩歌兮，屑涕泗之浪浪。", "我有所思兮，在河之陽。", "僾而不見兮，衷難弭忘。", "騄驥騰躍兮，鴻鵠翱翔。", "明璫玉案兮，爾不我將。", "緘誠結惠兮，久莫汝償。", "永如牛女兮，南北相望。", "昔燕處兮，靈芸之堂。", "紉蘭爲珮兮，集芰爲裳。", "西風淒緊兮，淩百草以殞黄。", "蘭萎芰裂兮，恐被服之不芳。", "念汝玉立兮，賤組繡之文章。", "玄節日厲兮，奈慘慄之冰霜。", "胡不乘白雲兮，歸來乎帝鄉。", "尚何所徯兮，畢永歲而彷徉。"]'),
('c1103393-8c20-4bef-847c-33363e4c95e0','舟次金陵懷寄歷陽王掾相','賀鑄','宋','宋诗','song-poetry','','[]','昨時江北望江南，把酒離愁已不堪。',64,'全唐诗/poet.song.61000.json','["昨時江北望江南，把酒離愁已不堪。", "今夜江南望江北，抵掌清談安可得。", "歷湖白下非吾鄉，官身俗眼禁人狂。", "後日扁舟更西去，江北江南兩何處。"]'),
('fc7d4452-0020-419f-986d-f002f1fc1794','贈道士蹇拱辰','賀鑄','宋','宋诗','song-poetry','','[]','嘗觀妙手御風圖，想像斯人世所無。',104,'全唐诗/poet.song.61000.json','["嘗觀妙手御風圖，想像斯人世所無。", "今識黄冠葆光子，爽氣飄颻畫不如。", "岷峨東來九千里，眼飽高山與流水。", "乘春更擬訪天臺，晨肇當年偶然耳。", "葆光子，胡爲乎，鼎中龍虎煉成寶，筆下鬼神驅作奴。", "須君且置是等事，三復玄元皇帝書。"]'),
('a97e2276-0adc-44bc-a729-d84345e86a9c','艤舟秦淮雪中訪侍其瑀','賀鑄','宋','宋诗','song-poetry','','[]','北風破雨初成雪，齋舫篷窗吹紙裂。',64,'全唐诗/poet.song.61000.json','["北風破雨初成雪，齋舫篷窗吹紙裂。", "籃舁觸冷訪圓廬，得把一盃聊耳熱。", "人生自適待何時，矧君與我皆衰遲。", "會待晴天暖風日，杖藜同赴北山期。"]'),
('84a20878-e883-4dc7-b2a6-56f76f56bdd2','寄墨代書贈楊時','賀鑄','宋','宋诗','song-poetry','','[]','徂來雪壓蒼松顛，淪膏根柢蟠蜿蜒。',144,'全唐诗/poet.song.61000.json','["徂來雪壓蒼松顛，淪膏根柢蟠蜿蜒。", "樵斤剪析石火熱，曲突百步凝梢烟。", "蒲萄秋顆纍纍懸，海膠九煉堪續絃。", "力擣萬杵臼欲穿，劑成圭璧隨方圓。", "點漆比色石比堅，坐令李韋羞居前。", "陳臺潘谷老且賢，授唯識者不計錢。", "是翁解化如蛻蟬，後可繼此無聞焉。", "付君一圭款識全，保護謹密何千年。", "君家清風宜世傳，不特談玄須草玄。"]'),
('c0d5f872-f6c9-4553-af28-bdb35782f126','留別僧訥','賀鑄','宋','宋诗','song-poetry','','[]','冗從西班誰比數，牛儈馬醫猶爾汝。',96,'全唐诗/poet.song.61000.json','["冗從西班誰比數，牛儈馬醫猶爾汝。", "詩解窮人未必工，苦調酸聲效梁父。", "滎陽道人方外交，謂我有言追屈騷。", "驪珠不惜彈黄雀，狗尾何堪聯晉貂。", "秦淮潮上扁舟發，後日相思一書札。", "千里同風了了然，人閒無處無明月。"]'),
('ae7e7c4a-864b-404d-a3b3-e373df5eb041','留別道士許自然','賀鑄','宋','宋诗','song-poetry','','[]','東晉高賢許遠遊，裔孫今不墜風流。',96,'全唐诗/poet.song.61000.json','["東晉高賢許遠遊，裔孫今不墜風流。", "還有臨川王太傅，每思與語即登樓。", "浮名何啻如雲薄，鐘鼓爰居非所樂。", "漱石枕流知善謔，友月朋風差不惡。", "吾亦塵閒無所求，終期探藥棲羅浮。", "異日歸來遼海鶴，不見人民見城郭。"]'),
('ad7b270c-1a8e-4675-9df9-0a74b341167c','贈趙參軍滂','賀鑄','宋','宋诗','song-poetry','','[]','髯參軍，髯參軍，平昔相好書相聞。',122,'全唐诗/poet.song.61000.json','["髯參軍，髯參軍，平昔相好書相聞。", "妙兼八法嗤五雲，一字僅課三年勤。", "春回玉樹生蘭筋，驊騮氣壓千羸羣。", "庾家之雞安足云，君子硯漁而筆耘，桓扇兮羊裙。", "奈何不書蘂珠祕錄之真文，寶厨鈿軸緘靈芸。", "閬居清絕無世紛，誰其觀者紫陽君。", "後日人間偶流落，猶得標題持鍵鑰。"]'),
('b1ecc536-f523-44c7-90ce-2075396b7b2f','留別田晝','賀鑄','宋','宋诗','song-poetry','','[]','君家陋巷一尺泥，吾車有輪馬有蹄。',96,'全唐诗/poet.song.61000.json','["君家陋巷一尺泥，吾車有輪馬有蹄。", "犯寒踏雨重相過，明日扁舟吾遂西。", "回首邯鄲迹如掃，離索十年成潦倒。", "兔葵燕麥春日妍，蟬腹龜腸氣方飽。", "雲逵窅窅謝攀躋，長鋏與人還故棲。", "異時結駟來南畝，耕者老夫鋤者妻。"]'),
('c48939b4-9e9a-49d8-8c77-dd4d525e6c98','調北鄰劉生','賀鑄','宋','宋诗','song-poetry','','[]','荒園老牆百堵破，北鄰劉子南鄰賀。',136,'全唐诗/poet.song.61000.json','["荒園老牆百堵破，北鄰劉子南鄰賀。", "今朝兩望不相過，端怯衡陽芒屩涴。", "吾庖無魚未必餓，晏飯糠覈煩脾磨。", "吾牀何容凡物坐，書爲睡媒即牀卧。", "彼子劉子何所作，方學商聲哦楚些，細君戛琴與之和。", "相忘之樂在江湖，最靈者人情不無。", "此日可惜難再圖，秋風西來莫挽吾。", "後日相思幾千里，書不盡言徒耗紙。"]'),
('72b31617-0087-4bc3-a12b-6e4c672718d7','答靳生','賀鑄','宋','宋诗','song-poetry','','[]','軒軒陸士龍，卓卓荀鳴鶴。',162,'全唐诗/poet.song.61000.json','["軒軒陸士龍，卓卓荀鳴鶴。", "雲間日下逢，此段殊不惡。", "方君嗜狂藥，而吾窮病縛。", "相望不相過，賦詩聊爾謔。", "知君酒隠慕先賢，誰何合作飲中仙。", "金陵妙唱丹砂絃，當日新聲傳不傳。", "莫學滄波弄雲月，老鮫哆口饞流涎。", "訪吾之居在何許，春明門東大道邊。", "青鞋布襪不妨步，何待東家蹇馿乃著鞭。", "我屋真無坐客氈，蒲團檉机共蕭然。", "鬭雞走狗春風顛，付與垣東惡少年。"]'),
('cded1053-32d9-4f0e-bdde-3d807693fce5','亡女勝璋哀辭','賀鑄','宋','宋诗','song-poetry','','[]','百痾沉頓彌兩年，何圖壯女死我先。',80,'全唐诗/poet.song.61000.json','["百痾沉頓彌兩年，何圖壯女死我先。", "失聲忍號氣窒咽，淚如綆縻汲九泉。", "嗚呼尚敢尤諸天，託非其人死失所。", "父孱母囂猶棄汝，吞辛咀楚申何許。", "萎荑殞英春不主，嗚呼萬古爲冤土。"]'),
('a1c4a93f-f8b0-42c3-ab6a-e82f0afac6bf','老鶴嘆','賀鑄','宋','宋诗','song-poetry','','[]','華表華表歸來乎，出無車，食無魚。',121,'全唐诗/poet.song.61000.json','["華表華表歸來乎，出無車，食無魚。", "懿公之遇難再圖，卑棲賸啄同羣雛。", "誰謂嵇氏子不孤，强顔市井交屠沽，巨源密啟亦已疏。", "嗚呼，衛侯既不可作，道林今也則無。", "露鳴風舞何區區，夙夜供君耳目娛。", "西山二子饑相似，南國三閭放不如。", "端慮盤飧懷異味，併隨焦尾付庖厨。"]'),
('5f205b35-07cb-40bb-912e-9398a73a62b3','送王安節赴武康尉','賀鑄','宋','宋诗','song-poetry','','[]','江左風華推第一，王氏堂堂文獻出。',85,'全唐诗/poet.song.61000.json','["江左風華推第一，王氏堂堂文獻出。", "烏衣諸郎能少屈，尚執中司三尺律。", "君方色養白頭親，吳興水陸饒甘新。", "卞山之下苕溪濱，一洗長安肥馬塵。", "君不見昔人負米長勤捧檄喜，敢論州縣徒勞耳。"]'),
('f0f08318-cb92-41c6-8353-7ecdae519c31','送海陵周太守邠受代還朝','賀鑄','宋','宋诗','song-poetry','','[]','湯湯水東流，奈何載此西行舟。',172,'全唐诗/poet.song.61000.json','["湯湯水東流，奈何載此西行舟。", "紞如五鼓鳴城頭，使君去矣不可留。", "前日使君來，天子惠此州。", "傳道管城政，先聲走羣偷。", "不關外戶息吠犬，悉把鉤鋤誰带牛。", "雨暘不違禱，舄鹵數倍收。", "吏却一錢賄，獄無五木囚。", "黄堂坐嘯有餘暇，八詠新詩追隠侯。", "斯民幸使君，畢世爲吾休。", "俄及瓜時代，本朝官重內。", "舊通金門籍，行奉玉宸對。", "問君何以治海陵，但陳聖主之德臣何能，狂生有意水衡丞。"]'),
('fa99f9b3-f7bf-4f91-92bc-57a60d9e162e','送僧雲還吳興','賀鑄','宋','宋诗','song-poetry','','[]','吳興道人美風度，月下滄浪翹白鷺。',64,'全唐诗/poet.song.61000.json','["吳興道人美風度，月下滄浪翹白鷺。", "晝公詩律尚能傳，間有赤烏黄耳句。", "海角相逢一笑新，懷歸不待白蘋春。", "寄聲故國羣兒輩，潦倒塵埃賀季真。"]'),
('8fbcda3b-0bf8-4d5f-a0c3-f2d7561dc788','答許景亮','賀鑄','宋','宋诗','song-poetry','','[]','東嘉海上孕瓌怪，之子人英晦當代。',161,'全唐诗/poet.song.61000.json','["東嘉海上孕瓌怪，之子人英晦當代。", "發之辭章聊一噫，雷鼓霜鐘警聾聵。", "投吾夜光敢不拜，相期過高幸少殺。", "君家風鑒嚴簡汰，顧吾衰遲積尪瘵。", "久隠牆東慕牛儈，絕望仲華安石輩。", "老矣狂奴猶故態，清思屢遭俗子敗。", "絮衣棘徑動罥礙，京塵浼人更難奈。", "行拏一舟犯滂湃，五斗無餘雜糠稗。", "全家飫飧雲夢异常，黄鶴登臨指天外。", "燕子西飛書可待，訪吾少明安好在。"]'),
('5db1f2cc-dec3-4577-89f4-eeb89a0126e5','贈僧孚','賀鑄','宋','宋诗','song-poetry','','[]','北道交遊竇了然，手持丹訣口談禪。',160,'全唐诗/poet.song.61000.json','["北道交遊竇了然，手持丹訣口談禪。", "吾年方少不解事，貪酒放歌相助癲。", "十載驅車道梁楚，汴水之陽一環堵。", "著書直上窺鬻熊，鄭圃漆園聊爾汝。", "旋聞瞥作去鄉行，聲迹相遼掃風雨。", "我遭官縛未渠央，君割塵緣遽如許。", "扁舟三月遡長川，故人投謁俄童顛。", "周妻何肉敗吾事，成佛定輸靈運先。", "此行歷涉佳山水，隨牒不妨行樂耳。", "與君更結蓮社遊，徑取盂囊付舟尾。"]'),
('c8b06e5e-28f9-432e-9d98-1c1092ee7e8f','送章邦傑移家餘杭包家山','賀鑄','宋','宋诗','song-poetry','','[]','九江賢令尹，千載兩相望。',192,'全唐诗/poet.song.61000.json','["九江賢令尹，千載兩相望。", "昔也陶彭澤，今之章瑞昌。", "拂衣置五斗，高興挹羲皇。", "避俗陶無悔，達生吾與章。", "淵明三逕荒松菊，我携一瓢寓僧屋。", "淵明乞食踵人門，我賣神丸辦蔬粥。", "淵明爲酒接休元，我每移書謝州牧。", "淵明紙筆課兒曹，我子長歌紫芝曲。", "蕭閑門戶十三年，尚畏塵緣生處熟。", "行將卜隠包家山，誓與蒼生鍊大還。", "願君門外誅榛菅，來者勿拒容躋攀。", "鏡湖遺老老且孱，猶堪護鼎訶神姦。", "功成拔宅自仙去，唯餘井臼留人間。"]'),
('845a4fbd-a95a-4fa3-9193-0b20d5430c36','題漢陽招真亭','賀鑄','宋','宋诗','song-poetry','','[]','大別山顛清沔尾，飛亭岧嶢带雲起。',130,'全唐诗/poet.song.61000.json','["大別山顛清沔尾，飛亭岧嶢带雲起。", "清狂使君初燕喜，拍手招呼黄鶴子。", "玄津煉出太陽酥，手葺胎髮蒙頭顱。", "每誇久落北酆籍，豈意齎恨歸黄壚。", "越客登臨興何有，愁不能言病妨酒。", "殘陽雲夢窅然深，尚欲開襟吞八九。", "羽駕飄颻安在哉，使君餘跡已塵埃。", "但見庾令樓橫烟樹杪，角聲催月渡江來。"]'),
('aa2c1660-2cc3-4a17-a2ca-399647e95ddd','晚出江城聞角','賀鑄','宋','宋诗','song-poetry','','[]','古壕沮洳荷葉枯，矍鑠禿鶖行且漁。',159,'全唐诗/poet.song.61000.json','["古壕沮洳荷葉枯，矍鑠禿鶖行且漁。", "山銜日脚水關掩，孤樓引角吹單于。", "胡馬嘶風興非淺，壯圖舊迹隨塵卷。", "秋盡湖邊雁不來，流落方悲去人遠。", "十月之交五夜長，河橫斗直天蒼凉。", "蘇門故里斗杓下，豈無伯仲勤相望。", "君不見剡蓬爲矢弧弦桑，男兒落地志四方。", "履屐無根著家巷，道梁適楚猶吾鄉。", "鴝鵒不踰濟，橘渡淮爲枳。", "吾心況物未應然，隨牒官身聊爾耳。"]'),
('36a444a9-80a7-486c-961d-0918f066d417','寄漢陽趙尉沔','賀鑄','宋','宋诗','song-poetry','','[]','慶湖遺老坐詩窮，强仕之年百病攻。',166,'全唐诗/poet.song.61000.json','["慶湖遺老坐詩窮，强仕之年百病攻。", "誰謂南昌祿隠翁，伏枕呻吟四壁空。", "相思限此江西東，寄聲每託江頭風。", "斯言近俳聊一笑，江水方清饑可療。", "人生奇偶類探籌，造物豈容人數料。", "君初試吏或當然，我太半生真不調。", "昔不願起家百日登三司，今不願還家六印金纍纍。", "但願官糧辦親養，歸來尚餘三徑資。", "鄰牆晏起訪安否，爾酌我歌堯舜時。", "咄嗟此願良難必，吞聲食蘗甘如蜜。"]'),
('4a2966d6-74d2-432e-8f7f-eacef50ba789','送武庠歸隠終南','賀鑄','宋','宋诗','song-poetry','','[]','君不見南朝豪儁有郗生，自厭出身時網嬰。',296,'全唐诗/poet.song.61000.json','["君不見南朝豪儁有郗生，自厭出身時網嬰。", "樂聞栖遁去人者，傾金累百贈其行。", "關西武郎將家種，心實慕儒官冗從。", "春走巴東歲暮還，逢迎偶在江南夢。", "過門把酒豁清襟，行將歸隠南山陰。", "終焉之計咄嗟辦，願賦一詩輕百金。", "吾聞自古咸秦稱陸海，六印可求田莫買。", "別墅三千畝上腴，將軍部曲猶多在。", "未應親手把鉤鋤，歲事經營付家宰。", "一官換得今是翁，昔何所縛今誰解。", "携琴領鶴白雲鄉，身世相遼自兩忘。", "北窗仰枕安足道，未知何者爲羲皇。", "豈不勝俛首塵埃百僚底，南北推遷隨尺紙。", "摩肩接武半臺輿，誰謂淮陰非噲比。", "君家鼎甲盛先唐，兩都朱邸森相望。", "天道惡盈幾赤族，當時頼有安平王。", "慶牒蟬聯今幾代，雲孫庠繼遊方外。", "他時野史逸民篇，鑄也磨鉛跂而待。"]'),
('2d503256-1cc8-423f-a324-4de4abd35665','送鄂州刑獄掾王懋元功罷官還海陵兼簡金陵和上人','賀鑄','宋','宋诗','song-poetry','','[]','暖雲芳草橫塘路，送客何之官鄂渚。',130,'全唐诗/poet.song.61000.json','["暖雲芳草橫塘路，送客何之官鄂渚。", "江皋暑淫氣如蒸，別來何之還海陵。", "海陵鄂渚非吾土，每後君來先我去。", "人無根蔕本悠悠，況指滄波是舟路。", "君方少健我衰遲，跼蹙轅間不自持。", "因行寄聲雁門遠，歲暮敢忘林下期。", "好去將無同語掾，行見春風花滿縣。", "隠顯它年不我遺，爲續白蓮社中十八傳。"]'),
('ddde4207-c76c-41a5-be4f-5bbe0a4fc91e','玉鉤環歌','賀鑄','宋','宋诗','song-poetry','','[]','良工得玉藍溪窟，相璞命形心匠出。',160,'全唐诗/poet.song.61000.json','["良工得玉藍溪窟，相璞命形心匠出。", "螳蜋倔彊疑有骨，頸繫一環猶莫屈。", "鏡湖老狂厭袍笏，素裰纁縚須此物。", "價比連城不容乞，王孫輟好人所難。", "何以報之明月盤，薰爐波面山巑岏。", "吾鄉美笴鵾雞翰，閩瓷兔碗霜毛寒。", "稱是頭貢雙龍團，聊送公齋增冗長。", "短歌粗可評珍貺，吾方野裝事遊放。", "跼步臞顔曳藜杖，薄暮微吟江漢上。", "彼漁丈人誤相訪，謂似三閭大夫樣。"]'),
('20af84db-afa5-42d1-8545-b6f66397445f','南樓歌送武昌慎太守還朝','賀鑄','宋','宋诗','song-poetry','','[]','君不見鄂渚山環少城半，高牙之衝仰飛觀。',213,'全唐诗/poet.song.61000.json','["君不見鄂渚山環少城半，高牙之衝仰飛觀。", "裴回華月天一隅，縹緲青山江兩岸。", "題榜南樓非昔時，今人可復識元規。", "唯餘在得昔時月，與此江山長住持。", "公堂坐嘯無留事，清夜登臨誰辨此。", "流風逸響殆千年，初見東吳貴公子。", "剸繁健手付方州，迎刃未始逢全牛。", "潢池小兒歸田疇，田無高下乃多收。", "每尋不淺胡牀興，更有歌人行酒籌。", "明日雲颿望嶢闕，鏡湖老生愁欲絕。", "一錢何敢浼劉公，送行聊以南樓月。", "照見金閨待漏時，結珮正冠勤曉謁。", "公乎莫負鱸魚菰菜期，衣錦東還使持節。"]'),
('0ad10d35-c3c0-48e2-8519-f34112ea1d7c','題黄岡東坡潘氏亦顔齋','賀鑄','宋','宋诗','song-poetry','','[]','東坡有田誰料理，黧面蒼毛潘氏子。',140,'全唐诗/poet.song.61000.json','["東坡有田誰料理，黧面蒼毛潘氏子。", "結茅題榜亦顔齋，農隙把書聊自喜。", "潘乎潘乎信是顔之徒，終日何所論難真如愚。", "世無孔父四科友，猶辦簞食瓢飲陋巷環牆居。", "百畝之收粒可數，天南有待東坡主。", "更輸什一補官倉，餘勺幾何供雀鼠。", "會須不改其樂媚而翁，力田水旱由天公。", "大勝心迹相違阮校尉，東西南北哭途窮。"]'),
('f37ce968-54a1-4128-abed-c301767d40cc','故鄴','賀鑄','宋','宋诗','song-poetry','','[]','魏武昔恢圖，北平譚尚孽。',240,'全唐诗/poet.song.61000.json','["魏武昔恢圖，北平譚尚孽。", "卜鄴築新都，非徒三狡穴。", "將行遷鼎志，遽有分香訣。", "落日繐帷空，奠終歌舞闋。", "旋聞瀍洛上，載起蒼龍闕。", "四葉不歸東，苔花馳道絕。", "食槽讖終驗，挂飯期先决。", "擾攘百年間，覆車尋此轍。", "山川氣象變，朝市繁華歇。", "白露復青蕪，茫茫換時節。", "陰風吹葛屨，燐火走兵血。", "木葉下西陵，寒蟲助騷屑。", "當時陪葬骨，馬鬣猶環列。", "隧碣仆縱橫，鎸文久殘缺。", "帛砧與柱礎，螭首隨分裂。", "指此一抔間，賢愚兩何別。", "悠悠鳳漳水，寂寂雀臺月。", "千古配英魂，未隨埃燼滅。", "田皋訪遺老，謂有興亡說。", "但聽黍離篇，叱牛耕不輟。"]'),
('866d7785-fa98-4ecf-be71-178b1d3aea97','喜雨','賀鑄','宋','宋诗','song-poetry','','[]','終春久旱暵，涉夏俄溽暑。',156,'全唐诗/poet.song.61000.json','["終春久旱暵，涉夏俄溽暑。", "垢汗浼衣襟，梅津蒸柱礎。", "黄霾閉赤景，測候錯辰午。", "沙燕逐風鳶，翻飛遡來雨。", "紛紛白羽箭，齊發萬牛弩。", "落瓦復鳴階，浮漚如沸煮。", "崇朝已沛浹，枯渴頓清瘉。", "田父喜過從，迎門好相語。", "蠶桑薄可具，豚酒與簫鼓。", "擇吉謝叢祠，巫娘罷狂舞。", "晨炊飽丁壯，庇笠耕舄鹵。", "少緩麥租期，庶將秋稼補。", "輸入太倉中，蕃肥任黄鼠。"]'),
('c7e922e8-0bd5-4e2f-9c55-7969b1120828','老槐','賀鑄','宋','宋诗','song-poetry','','[]','老樹久枯禿，俯臨清路塵。',96,'全唐诗/poet.song.61000.json','["老樹久枯禿，俯臨清路塵。", "曾無席地陰，庇暍及斯民。", "梟巢與狐穴，兇怪相憑親。", "嗥嘯屬陰黑，驚搖旁近人。", "周環築級壇，立社祠秋春。", "既享不材壽，濫當有土神。", "勿惑巫婦言，請揮樵者斤。", "猶疑終竊據，復作後來薪。"]'),
('056343ad-1f3d-408c-b754-5f6ba5748a9e','過鼂掾端智','賀鑄','宋','宋诗','song-poetry','','[]','西風吹晚雨，饑雀噪寒叢。',96,'全唐诗/poet.song.61000.json','["西風吹晚雨，饑雀噪寒叢。", "文舉對談客，坐慙觴豆空。", "咄嗟宦遊子，貧病略相同。", "斗俸折腰得，醉錢常不供。", "君看北里兒，高堂燕歌鐘。", "雖誇酒無算，飽德何由豐。", "吾豈乞墦者，不爲妻妾容。", "永懷冰蘗操，未媿屠酤雄。"]'),
('efa8a920-cdea-4cd7-976d-d7350811829f','春行','賀鑄','宋','宋诗','song-poetry','','[]','風俗喜嘉辰，行樂東城春。',48,'全唐诗/poet.song.61000.json','["風俗喜嘉辰，行樂東城春。", "人歌芍藥章，馬度楊柳津。", "田畝久枯渴，麥芒棲暗塵。", "焦心戴白叟，日望西郊雲。"]'),
('dceb4986-b1c0-4768-bb6a-e05b07ab2723','對酒','賀鑄','宋','宋诗','song-poetry','','[]','白駒不可駐，尺璧非所珍。',72,'全唐诗/poet.song.61000.json','["白駒不可駐，尺璧非所珍。", "獨挹一樽酒，悲歌送徂春。", "歌闌酒亦盡，回首迹已陳。", "自笑十年仕，尚迷天下津。", "豈無濯纓水，奈爾長路塵。", "命也復何道，今人猶昔人。"]'),
('0505d5e6-bc1c-4129-b875-efae8e4841e0','閑情二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','青窗隠夕曛，玉甃紫苔春。',48,'全唐诗/poet.song.61000.json','["青窗隠夕曛，玉甃紫苔春。", "佳人久不見，翠被銷檀薰。", "長巾拂綠綺，上有三年塵。", "聊彈別燕弄，寄謝陽臺雲。"]'),
('dd2eb79b-619d-44b6-95cc-f94c3f3bf15c','閑情二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','秋風動朱箔，流塵污鴛綺。',48,'全唐诗/poet.song.61000.json','["秋風動朱箔，流塵污鴛綺。", "念昔合歡人，兩心今萬里。", "冰霜變松竹，況復如桃李。", "欲寓相思文，無多右軍紙。"]'),
('8a388d52-b5a4-4570-91b8-7bc19b37c541','題巫山圖','賀鑄','宋','宋诗','song-poetry','','[]','巫山彼美神，秀色發朝雲。',48,'全唐诗/poet.song.61000.json','["巫山彼美神，秀色發朝雲。", "絢麗不可挹，飄颻去無痕。", "楚夢一夕後，蒼山秋復春。", "目斷腸亦斷，往來今古人。"]'),
('ad926318-2c0d-4203-a839-58f9269ca1eb','詛蚊','賀鑄','宋','宋诗','song-poetry','','[]','公舍踞陰溝，維蚊得所在。',168,'全唐诗/poet.song.61000.json','["公舍踞陰溝，維蚊得所在。", "朝昕滅聲迹，曛暮相期會。", "挾是黨與繁，豈資軀力大。", "饑心過狼貪，毒喙甚蜂蠆。", "侜張巧中人，勇悍將何奈。", "貧無綃葛裯，拙計燃蕭艾。", "徒自取熏蒸，舉家更嚏咳。", "烟銷尚鼓箑，夜久禦益懈。", "坦腹恣交攻，煩癢如搔疥。", "神疲復夢悸，少不容清快。", "如何造物工，種此生民害。", "安得長風驅，投諸四荒外。", "斷之嚴霜誅，併命不可貸。", "醜類儻一遺，餘孽行當再。"]'),
('0b11635b-2306-49c4-b394-9fb6fd52275a','燭蛾','賀鑄','宋','宋诗','song-poetry','','[]','鬼蛾來翩翩，慕此堂上燭。',48,'全唐诗/poet.song.61000.json','["鬼蛾來翩翩，慕此堂上燭。", "附炎竟何功，自取焚如酷。", "感彼萬動微，保生在無欲。", "不見青林蟬，飲風聊自足。"]'),
('9da8767d-48c0-4980-9624-306c01cf22ef','病暑','賀鑄','宋','宋诗','song-poetry','','[]','旱夏景延永，烈日天中央。',144,'全唐诗/poet.song.61000.json','["旱夏景延永，烈日天中央。", "欻欻燎原野，中人如探湯。", "病肺苦焦渴，吐舌生喉瘡。", "蔗漿與茗飲，未易蘇膏肓。", "稍驚氣象變，雲物來冥茫。", "仰枕視簷際，浩浩浮滄江。", "忽得灌頂偈，灑然心地凉。", "雷公未鼓怒，風伯何猖狂。", "掃蕩太宇空，萬影纔斜陽。", "俯辭楚臺上，拱立齊鼎旁。", "一介命螻蟻，敢干私雨暘。", "田夫信無罪，觸熱正驅蝗。"]'),
('2a58baea-a40c-42f6-bb03-d62b02de8275','暑夜','賀鑄','宋','宋诗','song-poetry','','[]','渴蟬鳴中夜，木葉凝無風。',48,'全唐诗/poet.song.61000.json','["渴蟬鳴中夜，木葉凝無風。", "襟苧不加带，猶如被蒙茸。", "三庚信可畏，一扇曾何功。", "安得解民慍，蒼梧理古桐。"]'),
('ad8457f9-94cc-4f41-9773-86d2c26905c7','問內','賀鑄','宋','宋诗','song-poetry','','[]','庚伏厭蒸暑，細君弄鍼縷。',96,'全唐诗/poet.song.61000.json','["庚伏厭蒸暑，細君弄鍼縷。", "烏綈百結裘，茹繭加彌補。", "勞問汝何爲，經營特先期。", "婦工乃我職，一日安敢墮。", "嘗聞古俚語，君子毋見嗤。", "癭女將有行，始求然艾醫。", "須衣待僵凍，何異斯人癡。", "蕉葛此時好，冰霜非所宜。"]'),
('c6a65f8b-95c8-4089-af77-2a08db7e7eee','食芡實作','賀鑄','宋','宋诗','song-poetry','','[]','錢侯官舍旁，走水來方塘。',180,'全唐诗/poet.song.61000.json','["錢侯官舍旁，走水來方塘。", "暑雨過初伏，斜陽生晚凉。", "風翻芡盤卷，萬觜爭低昂。", "猶疑秦雞暴，擅此六國場。", "下榻延密客，開樽薦新嘗。", "金刀剝老蚌，玉沙磨夜光。", "殷勤煩飣餖，未咀悲生腸。", "引領鄘衛西，百泉乃吾鄉。", "水産富此物，數錢論斗量。", "朝餐取饜飽，無復炊黄粱。", "貪嗜比羊棗，況乎惟味良。", "十年去國仕，遇得纔微芒。", "季鷹思蓴羹，拂衣謝齊王。", "我亦散浪者，未許斯人狂。", "長歌定行矣，千載會相望。"]'),
('acafffc9-eb02-4220-a216-807d7a83440a','烹雞歎','賀鑄','宋','宋诗','song-poetry','','[]','膳夫縛三雞，二雌先就烹。',96,'全唐诗/poet.song.61000.json','["膳夫縛三雞，二雌先就烹。", "一雄置机上，不廢知時鳴。", "有客見之歎，人情猶物情。", "寧昌言即死，何噤口偷生。", "愚聞此客言，退思因竊評。", "雞實鼎俎資，殺身非罪聲。", "人忘樞機誡，鼓舌爲禍萌。", "宜念千金軀，與雞何重輕。"]'),
('739f5ea7-ea0f-45a3-8098-484d9c4cd07a','題華陽公主碑陰','賀鑄','宋','宋诗','song-poetry','','[]','王姬乘鳳去，春色一朝空。',96,'全唐诗/poet.song.61000.json','["王姬乘鳳去，春色一朝空。", "昔怨綺羅月，今無松柏風。", "千年見白日，狐穴入幽宮。", "玉鏡古塵滿，落梅誰復容。", "峨峨當隧碑，寶刻一何工。", "文擅色絲美，但書膏邑封。", "惜非丈夫烈，不得傳無窮。", "好在故時物，清漳流自東。"]'),
('f6087c20-af58-49c4-ad31-917b25f1e58f','題蘭陵王碑陰','賀鑄','宋','宋诗','song-poetry','','[]','齊室生武賢，蘭陵乃頗牧。',180,'全唐诗/poet.song.61000.json','["齊室生武賢，蘭陵乃頗牧。", "析瓜饗虎士，饜飫比粱肉。", "金墉免胄戰，破陣何神速。", "樂府有遺聲，當歌凱旋曲。", "盤宗既不壽，霸祚宜爾促。", "十代六百年，人間換陵谷。", "荒途接幽壠，誰復禁樵牧。", "窆石半欹摧，鉤鋤斷鼇足。", "蒼苔蝕瑑刻，仰睇眩塵目。", "操翰無愧辭，千言不爲辱。", "流湍齧馬鬣，客土日危蹙。", "霪潦併年間，彌漫即川陸。", "昔多萬兩送，今無一抔築。", "人生妄區別，共盡同草木。", "何待雍門彈，令君淚盈匊。"]'),
('fb4505ff-5372-48f2-a44e-2d839193bdc0','邯鄲郡樓晚望','賀鑄','宋','宋诗','song-poetry','','[]','新凉瀉軒檻，草木带秋聲。',96,'全唐诗/poet.song.61000.json','["新凉瀉軒檻，草木带秋聲。", "闊水倒嵐影，洗磨刀戟明。", "百蟲暮吟動，一鳥歸思輕。", "晚律駭徂景，羈懷念勞生。", "去國亦已久，己年今復庚。", "官倉容雀耗，世路忌蝸爭。", "顧我實荒浪，誤拋樵與耕。", "竹木微逕在，奚獨古人行。"]'),
('3b57e1d7-4541-49a1-b3ec-41ea8d7e425b','答杜仲觀登叢臺見寄','賀鑄','宋','宋诗','song-poetry','','[]','高風蕩河漢，白露被寒菊。',168,'全唐诗/poet.song.61000.json','["高風蕩河漢，白露被寒菊。", "下有絡緯蟲，淒酸生意促。", "華年不相待，去我何流速。", "老步失騰驤，短轅甘跼蹙。", "伊人濮陽秀，方厭折腰辱。", "仕道塞榛蕪，低徊避蚖蝮。", "邯鄲古都會，陳迹武靈築。", "興發即登臨，西南幾窮目。", "新詩琢璠琰，疊寄兩三幅。", "一聽郢中歌，陽春回草木。", "行將及瓜代，暫喜擺羈束。", "鞭馬徑相過，連朝奉遊矚。", "隻雞與斗黍，禮意未爲足。", "何以遇高陽，多營甕頭醁。"]'),
('7ca773c3-8ffa-4339-a6f6-762fdd06d988','冬夜寓直','賀鑄','宋','宋诗','song-poetry','','[]','落月半侵窗，蛩聲寒到牀。',108,'全唐诗/poet.song.61000.json','["落月半侵窗，蛩聲寒到牀。", "羈人不堪此，夢後夜仍長。", "結衣出庭戶，河漢正蒼凉。", "浮陰暝四野，來雁不知行。", "陳物悲暮節，畏途懷故鄉。", "十年泥滓賤，半生靴板忙。", "豈不志事功，筋骸難自强。", "壯毛抽寸霜，烈膽磨尺鋼。", "素尚竟誰許，行歌追楚狂。"]'),
('d4284f04-f748-4f7b-ad68-ddff01d349d8','送武桓之安陽','賀鑄','宋','宋诗','song-poetry','','[]','黄金絡征轡，之子待明發。',48,'全唐诗/poet.song.61000.json','["黄金絡征轡，之子待明發。", "樽酒少遲留，禪林見凉月。", "歌鬟結蛾黛，怨此佳期闊。", "去去柳堤風，青蟬催白髮。"]'),
('429e8909-0772-4cbb-8eda-ed89f7fbf47e','寄杜邯鄲','賀鑄','宋','宋诗','song-poetry','','[]','窮巷厭多雨，頹垣藜藿生。',132,'全唐诗/poet.song.61000.json','["窮巷厭多雨，頹垣藜藿生。", "蜩螗飽風露，晏景一何清。", "坐指歲芳歇，羈人心骨驚。", "所懷不可見，東州聞政聲。", "三年但弦歌，百里稱神明。", "風月動高興，詩章時一鳴。", "天葩落健筆，直與春工爭。", "渾河失故渠，怒水方縱橫。", "難憑束葦濟，跬步萬里程。", "夢想不知遠，笑談何可并。", "頼有西飛翰，尺紙緘馳情。"]'),
('938bd7b4-9bef-4dba-b4b5-10ce83e99a37','訪周沆郭忱','賀鑄','宋','宋诗','song-poetry','','[]','前日去薄官，驅車望城闕。',216,'全唐诗/poet.song.61000.json','["前日去薄官，驅車望城闕。", "情親周與郭，契闊多年別。", "征袍未及解，徑造郊扉謁。", "存問審安娛，芝眉尉懷渴。", "家飽具羹炙，笑我猶饕餮。", "野色夜蒼茫，松陰步微月。", "悲風應長嘯，灑面若冰雪。", "狹室燭花青，壞爐擁駝褐。", "歡呼講舊好，鄰夢憎驚聒。", "念昔初冠年，朋從事顛蹶。", "怱怱一回首，身志成老拙。", "居諸信遄邁，又值陽生節。", "春物行可期，良遊須屢結。", "婦家酒醅美，升斗容丐輟。", "斟酌挹東君，手選時芳折。", "樽前有餘樂，身外無所切。", "欲尋玉清路，難訪金丹訣。", "修短三萬朝，黄塵共埋滅。"]'),
('2f7fcc29-5a14-4ee2-b9a7-47fd421140b4','除夜歎','賀鑄','宋','宋诗','song-poetry','','[]','壯髮忽種種，華年今復窮。',204,'全唐诗/poet.song.61000.json','["壯髮忽種種，華年今復窮。", "客懷少安適，況乃京塵中。", "病肺厭斟酌，疲筋謝過從。", "閑坊稅老屋，車馬無來蹤。", "日俸纔百錢，鹽齏猶不供。", "夜榻覆龍具，晨炊熏馬通。", "出門欲貸乞，羞汗難爲容。", "安得一扁舟，浮家乘興東。", "江山此深隠，終老爲田翁。", "春秧二頃苗，秋穫期百鍾。", "稚子課樵汲，壯妻兼織舂。", "行歌滄浪清，卧快柴桑風。", "神明養內觀，憂患無旁攻。", "有客聞此言，誚余何不衷。", "茲行果勇决，誰攬冥冥鴻。", "安知祿籍間，去就如樊籠。", "微尚良自信，所悲君不同。"]'),
('d2baf8ee-b089-44b5-b327-b8c7453ed80c','寄杜仲觀','賀鑄','宋','宋诗','song-poetry','','[]','中春雨收霽，與子登叢臺。',252,'全唐诗/poet.song.61000.json','["中春雨收霽，與子登叢臺。", "形勝宛然在，太行西北來。", "無情百尺土，千載未摧頹。", "四顧發悲嘯，淒風振頤頦。", "淩高氣象變，似不容徘徊。", "下出破禪剎，斷碑生紫苔。", "嚴公賦懷古，復使後人哀。", "西尋王氏園，一徑趨城隈。", "老竹未萌筍，繁花如雪開。", "惠然丘少年，逸躅欣攀陪。", "小榭羅醼豆，開簾按俳詼。", "招呼緲縹人，晚鏡催妝梅。", "水調唱金縷，雲罍浮玉醅。", "傾觴敢惜醉，忘著接䍦回。", "明日遂分首，舊遊安在哉。", "我爲東徐官，客鬢栖塵埃。", "君調南康吏，江山役清才。", "西風吹去雁，尺紙爲君裁。", "我已困摧辱，壯心如溼灰。", "行將隠名姓，采藥孫登嵬。", "異日儻相過，衡門翦蒿萊。"]'),
('43bc6e36-e7ee-4326-bd32-f5b4aa817677','遊雲龍張氏山居','賀鑄','宋','宋诗','song-poetry','','[]','昔聞張逸民，卜築雲龍山。',264,'全唐诗/poet.song.61000.json','["昔聞張逸民，卜築雲龍山。", "東望結遐想，喜得彭城官。", "一語定襟契，宛如平生歡。", "招携屬休沐，投此蘿薜間。", "女僕候門巷，青袿雙翠鬟。", "蘇齋軒戶明，餠火焚椒蘭。", "寶墨鬼神護，清詩冰玉寒。", "森然拱簷霤，架石排琅玕。", "東趨放鶴亭，磴道披茅菅。", "指顧百村落，炊烟林莽間。", "日脚灑平陸，兩山如斷環。", "淒風振晚葉，坐怯衣裘單。", "引領紫霄極，飄颻如可干。", "緬懷眉山公，五馬來遊盤。", "酣興走顛筆，蒼崖即鑱刊。", "午年仲冬月，雪野雲彌漫。", "掃石坐舒嘯，惠泉烹鳳團。", "當時詫盛集，千古陋逵安。", "俛仰迹遂陳，斯人久泥蟠。", "我來後千日，逸躅何由攀。", "遇勝不能賦，俯尋塵路還。", "山英移未勒，時款白雲關。"]'),
('591ca071-3f34-4ea8-8d9a-25b625a5bb30','登黄樓有懷蘇眉山','賀鑄','宋','宋诗','song-poetry','','[]','登黄樓，望黄州，黄州望不見，樓下水東流。',44,'全唐诗/poet.song.61000.json','["登黄樓，望黄州，黄州望不見，樓下水東流。", "水流何可留，浮雲更悠悠。", "傷心澤畔客，憔悴楚蘭秋。"]'),
('3268aa55-dedb-4e9a-8df9-a30d961cc079','秋懷二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','室邇人尚遠，況乎千里間。',48,'全唐诗/poet.song.61000.json','["室邇人尚遠，況乎千里間。", "豈徒道路長，重水復重山。", "清霜老芳物，嘉樹不堪攀。", "欲寄隴頭信，春風殊未還。"]'),
('5a4c2688-d8fa-4811-b80b-7e9b4da6ea91','秋懷二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','蕭蕭庭木落，格格雞聲惡。',48,'全唐诗/poet.song.61000.json','["蕭蕭庭木落，格格雞聲惡。", "荒簷日影斜，饑貓捕黄雀。", "窗間養痾客，起念丘園樂。", "欲賦歸去來，西風老藜藿。"]'),
('5d73f5d5-675a-47d1-9ed8-53712fe66e7a','燕子樓','賀鑄','宋','宋诗','song-poetry','','[]','城據山川勝，千年楚故都。',204,'全唐诗/poet.song.61000.json','["城據山川勝，千年楚故都。", "高樓臨汴水，楊柳蔭芙蕖。", "唐室中多故，將軍老鎮徐。", "毬場朝戲馬，玉帳夜投壺。", "白雪徵清唱，黄金得綠珠。", "春風樓上醼，三日極歡娛。", "紅粉夢雲散，白楊兵火餘。", "當年賀厦燕，老盡幾番雛。", "曲徑擁黄葉，西風時掃除。", "寒鴟蹲老樹，睥睨女牆狐。", "有客晚登覽，徬徨思壯圖。", "荆榛閉銅雀，麋鹿遊姑蘇。", "陳迹豈足道，舊歡何日無。", "朱欄開酒場，寶勒迎官奴。", "醉袖舞鸜鵒，艷聲歌鷓鴣。", "遲留故時月，桂影來座隅。", "回首一相詫，今人如不如。"]'),
('248c838e-9b18-45d7-9acf-98e198dcfcd8','快哉亭','賀鑄','宋','宋诗','song-poetry','','[]','飛亭冠城隅，空豁延四望。',96,'全唐诗/poet.song.61000.json','["飛亭冠城隅，空豁延四望。", "夙昔兩文雄，故牀此相向。", "山川氣候美，詩酒風神王。", "彈壓許昌侯，陽春慙俚唱。", "麾車忽南北，榮辱生譽謗。", "一躐雲逵間，一落江湖上。", "我來得陳躅，伏檻徒怊悵。", "可畏此塵籠，歸哉養荒浪。"]'),
('dc5afe00-547c-4bde-aecc-9c29bdb20ace','飛鴻亭','賀鑄','宋','宋诗','song-poetry','','[]','禪林跨山脅，飛構鑿崚嶒。',180,'全唐诗/poet.song.61000.json','["禪林跨山脅，飛構鑿崚嶒。", "千里寄雙睫，百憂消一登。", "斯遊屬公暇，曉日東南升。", "霜野明練甲，雲陰垂海鵬。", "東州地陽暖，臘月川無冰。", "大艑出洪口，突去如騫騰。", "趺坐思方寂，桐魚聞飯僧。", "生臺飽馴鴿，散上浮圖層。", "矯首發長嘯，清風鼓塵膺。", "寥寥紫虛路，鴻雁正憑凌。", "仿像中散公，俯手朱絲繩。", "粉繪久零落，爽靈呼不應。", "顧余識尤寡，況復無才稱。", "行且置纓笏，庵栖宗大乘。", "二子勿多誚，有心何不能。"]'),
('be063351-ef57-4339-b068-e2ffe34cb11d','上巳後一日登快哉亭作','賀鑄','宋','宋诗','song-poetry','','[]','上巳信嘉辰，流觴傳舊俗。',96,'全唐诗/poet.song.61000.json','["上巳信嘉辰，流觴傳舊俗。", "良遊悵不遂，吏局方有屬。", "東風吹曉雨，萬竅嗥林麓。", "疑有泊舟人，狂歌河女曲。", "逾朝始澄霽，物色如新沐。", "城角趨危亭，登臨尉幽獨。", "紛華掃不見，胡蝶飛平綠。", "竚倚窮夕曛，悠哉此心目。"]'),
('4793821a-2e6e-456b-acb9-442f1745b902','讀李益詩','賀鑄','宋','宋诗','song-poetry','','[]','君虞興聖孫，詩律早專美。',168,'全唐诗/poet.song.61000.json','["君虞興聖孫，詩律早專美。", "樂府度新聲，宮酺奉天子。", "鮮風獵蘭苕，華月濯桃李。", "獨有連眉郎，才稱劣相比。", "頗聞竹窗句，流落綺紈耳。", "吏曹久失調，幕府感恩起。", "從軍五十篇，王粲慙率爾。", "胡沙動霜草，開卷得千里。", "騫翔大蓬拜，轉顧觸排毀。", "晚升八座崇，謝事知所止。", "高文茂支庶，埋滅長已矣。", "斯人今不亡，正頼數番紙。", "咄嗟齒踰壯，日就無聞恥。", "勉哉課謠吟，請自田居始。"]'),
('33a3746f-64c0-4e5c-aa3c-b2cbafa68a74','田園樂','賀鑄','宋','宋诗','song-poetry','','[]','昔我未去國，幽栖淇上村。',240,'全唐诗/poet.song.61000.json','["昔我未去國，幽栖淇上村。", "分辭俠少事，喜與農老言。", "農老孰追從，四鄰皆世婚。", "機中工織婦，籍上成丁孫。", "青駒自走磨，黄犬長候門。", "昨日春火開，逍遥望高原。", "西照牛羊下，東風花草繁。", "今朝夏雞鳴，麥熟田頭喧。", "歸來息樹蔭，課汲灌中園。", "秋賽方及辰，釀秫烹膏豚。", "叢祠響腰鼓，免杖奉神樽。", "冬雪斷門巷，蠶廬清且溫。", "地藉熊豹席，爐明荆櫪根。", "起居就安適，非復繫晨昏。", "不識百里面，不知千騎尊。", "供輸先衆期，於我何威恩。", "太上復淳古，坐超羲與軒。", "敢忘天地施，擊壤聲如塤。", "畢此百歲願，泰然長夜魂。", "避秦誰氏子，客死武陵源。"]'),
('a290f0c9-a5b7-4044-92db-0984742646e0','此日足可惜','賀鑄','宋','宋诗','song-poetry','','[]','此日足可惜，此樽何可辭。',120,'全唐诗/poet.song.61000.json','["此日足可惜，此樽何可辭。", "人生信浮寓，老境將安之。", "念昔青衿歲，九七殊未知。", "忽忽俯仰間，復見趨庭兒。", "名繫冗從籍，顧亦胡能爲。", "撫此多病軀，敢有黄髮期。", "每虞斃奔走，明哲永見嗤。", "後日賣刀劍，買牛耕故陂。", "不憚力作勤，農事有閒時。", "慨想無心子，清言真我師。"]'),
('68a216b6-43a8-4402-bbce-31129b79d2b2','部兵之狄丘道中懷寄彭城社友','賀鑄','宋','宋诗','song-poetry','','[]','駕馬出北門，徒御何遲遲。',120,'全唐诗/poet.song.61000.json','["駕馬出北門，徒御何遲遲。", "日氣方洶湧，霜陰亦紛披。", "役夫前驅行，少婦痛不隨。", "分携仰天哭，聲盡有餘悲。", "雖非遠行邁，要之爲別離。", "顧我豈無家，從公難遂私。", "且懷二三友，缺此文酒期。", "臨分各有贈，婉思見乎詞。", "吟諷一回首，烟林失城池。", "相思肯相過，斗黍爲君炊。"]'),
('f15e857c-8a77-4d71-80ed-c1f25dd96a5b','三月二十日遊南臺','賀鑄','宋','宋诗','song-poetry','','[]','晴春六十日，不與酒盃親。',180,'全唐诗/poet.song.61000.json','["晴春六十日，不與酒盃親。", "吏事豈無閒，風雨復兼旬。", "始作南城遊，時物固已陳。", "掃不見桃李，濃綠迷荆榛。", "登高暫逍遥，引目清泗濱。", "向田有交逕，俯城皆要津。", "得意屬禽魚，可愛不可馴。", "顧余千里客，眷此十日春。", "胡不念爾生，筋骸勞欠伸。", "二十起丁籍，一官初爲貧。", "侜張西復東，甑滿萊蕪塵。", "黄綬彼何物，豕苓安足珍。", "山園有芳蘭，幽珮手自紉。", "長哦白雲謠，遐想紫陽真。", "去矣南昌尉，庶幾乎若人。"]'),
('6fef69bc-d13b-41c2-b23e-b05850027100','夏夜懷寄傳道','賀鑄','宋','宋诗','song-poetry','','[]','疲筋任藜杖，行藥下僧坊。',120,'全唐诗/poet.song.61000.json','["疲筋任藜杖，行藥下僧坊。", "月出河漢白，雨餘草木凉。", "有懷社中子，引首東南望。", "高韵少諧結，何心事征商。", "泗濱六七月，萬柳鳴蜩螗。", "大艑軻峨來，迎風坐胡牀。", "投錢授赤券，豈所試君長。", "申退尚多暇，不無金玉章。", "而余方執熱，思得濯滄浪。", "雲牋儻寫寄，珍重未相忘。"]'),
('d922603d-7f2c-4172-89b0-720ec2881043','和張謀父遊石佛山觀魏太武書','賀鑄','宋','宋诗','song-poetry','','[]','中夏昔屯否，代邦天所開。',180,'全唐诗/poet.song.61000.json','["中夏昔屯否，代邦天所開。", "鴻圖屬太武，不世英雄才。", "南洗洛陽血，西盪長安灰。", "氈車十萬乘，略地驅風雷。", "一葦濟長淮，築宮瓜步隈。", "東鄰拜牢餼，走使爲婚媒。", "雲旗即歸路，覽勝此裴徊。", "俯揮鐵馬鞭，頑石同陶坏。", "劃成四大字，屹栗陰虹摧。", "淪精入崖壑，怒氣羞蟠回。", "茫茫六百年，風雨生莓苔。", "偉蹟寖銷泯，威靈安在哉。", "生存貴無上，零落等塵埃。", "君爲訪古遊，賦詩追七哀。", "人生誰不爾，莫負手中杯。"]'),
('637682fd-0663-453e-83e5-cff67efb63d7','夜行鄒縣道中遇雨作','賀鑄','宋','宋诗','song-poetry','','[]','昨日秋遂分，村村歛禾黍。',144,'全唐诗/poet.song.61000.json','["昨日秋遂分，村村歛禾黍。", "半夜宿田人，相嘑深陂雨。", "駸駸馬上客，厭浥投何所。", "暮發鄒子城，朝期飯東魯。", "據鞍思假寐，顛墜慚不武。", "俯畏道旁石，頹然如伏虎。", "遠驚蕎麥華，白水漫洲渚。", "安能叱吾馭，親闈寄西楚。", "念昔卧蘇門，夙興猶及午。", "豈謂從一官，羈離遽如許。", "歸歟惜遲暮，幽愫將誰語。", "頼爾草根蟲，助我長吟苦。"]'),
('6beda42e-d0e6-4a86-84d5-81443de8fd9f','行路難','賀鑄','宋','宋诗','song-poetry','','[]','驚飈獵榛莽，西山匿頹陽。',72,'全唐诗/poet.song.61000.json','["驚飈獵榛莽，西山匿頹陽。", "四五陰魄晚，繁星亦光芒。", "驅車何所投，却顧歸路長。", "挾轅兩羸牸，犯此豺虎場。", "安得渥洼駿，皎旦遊康莊。", "豈徒寫我憂，要使塵不揚。"]'),
('0d4ed404-f893-4667-a076-8d134cfa0b39','送寇元弼王文舉','賀鑄','宋','宋诗','song-poetry','','[]','無端嵇氏叟，早結曹家偶。',240,'全唐诗/poet.song.61000.json','["無端嵇氏叟，早結曹家偶。", "不遂龍蛇藏，翻從牛馬走。", "東西祇强顔，清鏡照人頑。", "敧枕知歸路，開屏認舊山。", "甘心折腰膂，爲飽來西楚。", "始驗釜生魚，還悲厠中鼠。", "兩君冰玉人，傾蓋許相親。", "何意塵埃地，欻游雲漢津。", "佳時第行樂，不與華年約。", "大白酒交酬，長箋詩間作。", "俄報戍期秋，扁舟去莫留。", "臺鄉淮水北，和氏玉坑頭。", "飄颻同李郭，到岸逢搖落。", "俱是長年人，得忘彌日惡。", "勞生不自知，會合復何時。", "籠鳥檻猿思，烹雞炊黍期。", "此期諒難必，幸勿忘今日。", "固有夢依依，可無書一一。", "徐國壯山河，黄樓入望多。", "後時三五夕，奈爾月明何。"]'),
('8f37babc-bdb1-49af-87c3-c7ff894e288d','人生七十稀','賀鑄','宋','宋诗','song-poetry','','[]','人生七十稀，行年今已半。',120,'全唐诗/poet.song.61000.json','["人生七十稀，行年今已半。", "事功貴及時，遲暮復何算。", "嗟吾夙多負，失怙在童丱。", "詩禮思有聞，飄颻辭祖貫。", "慈親念衰緒，猝猝營婚宦。", "名姓繫西班，星霜亟徂換。", "未築黄金臺，長歌白石爛。", "豈無同心契，相望眇雲漢。", "每虞狂飈至，摧折澗底幹。", "異日偶班輸，抱柯徒永歎。"]'),
('54791196-7a93-4a7a-b668-e82638635cd6','和杜仲觀青字詩二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','青袍少年子，獨出青門遊。',48,'全唐诗/poet.song.61000.json','["青袍少年子，獨出青門遊。", "逢人少青眼，凝笑望青樓。", "窗中青蛾女，正爲青春愁。", "心事屬青鳥，青驄能少留。"]'),
('243a29f2-24a7-4d70-8827-fc6ebcae6d6a','和杜仲觀青字詩二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','白馬青絡頭，青萍寶带鉤。',48,'全唐诗/poet.song.61000.json','["白馬青絡頭，青萍寶带鉤。", "青溪流水急，獨上青翰舟。", "佳人青雀釵，手把青荷遊。", "慕君青雲器，青髮結綢繆。"]'),
('b2c001ac-d3c3-4bbb-bc6d-6cfc56b736e2','送李主簿夷行之官河陰四首  其一','賀鑄','宋','宋诗','song-poetry','','[]','夙昔一樽酒，相從清泗濱。',48,'全唐诗/poet.song.61000.json','["夙昔一樽酒，相從清泗濱。", "回首欻四載，長安逢故人。", "交情久益淡，辭筆老加新。", "送子復西去，勞生悲重陳。"]'),
('b3d463d2-479a-49ad-bb49-be413962de43','送李主簿夷行之官河陰四首  其二','賀鑄','宋','宋诗','song-poetry','','[]','古來英特士，往往沈下僚。',48,'全唐诗/poet.song.61000.json','["古來英特士，往往沈下僚。", "念君鸞鵠姿，俛首栖蓬蒿。", "霜氣歛陂澤，伊流纔半篙。", "舟行何以尉，酌酒誦離騷。"]'),
('b3089e5a-d3cc-4752-9eed-80d83c84909d','送李主簿夷行之官河陰四首  其三','賀鑄','宋','宋诗','song-poetry','','[]','君才本高絕，流俗固難諧。',48,'全唐诗/poet.song.61000.json','["君才本高絕，流俗固難諧。", "桂生樗櫟林，寧免相突排。", "勾稽諒多暇，簾箔蔽公齋。", "聖賢在黄卷，差可遣人懷。"]'),
('62dec0d2-d3dd-4d18-84d8-209e9ef35028','送李主簿夷行之官河陰四首  其四','賀鑄','宋','宋诗','song-poetry','','[]','少小縻一官，身世兩相補。',48,'全唐诗/poet.song.61000.json','["少小縻一官，身世兩相補。", "爲飽西復東，志願劣兒乳。", "不無同心友，頗壓折腰膂。", "寄語北山雲，異時吾與汝。"]'),
('12738685-6af4-4649-a246-d5382c2da088','擬南梁慧偘法師獨杵擣衣','賀鑄','宋','宋诗','song-poetry','','[]','嶧陽桐杵鳴，蓮岳石砧平。',48,'全唐诗/poet.song.61000.json','["嶧陽桐杵鳴，蓮岳石砧平。", "待誰相應節，要自不勝情。", "吹衣風稍急，弔影月微明。", "會有不眠客，聽此斷腸聲。"]'),
('de7850d0-3093-4b50-b531-7184055b6ee8','擬阮步兵夜中不能寐','賀鑄','宋','宋诗','song-poetry','','[]','夜久不成夢，張燈開故書。',48,'全唐诗/poet.song.61000.json','["夜久不成夢，張燈開故書。", "清霜屏雲物，有月來庭除。", "良時悵難再，不與佳人俱。", "掩卷長太息，望子城之隅。"]'),
('0de420dd-a384-4259-935c-5e3cf1e86225','擬鮑溶寒宵歎','賀鑄','宋','宋诗','song-poetry','','[]','孤缸照愁眠，明滅知夜久。',48,'全唐诗/poet.song.61000.json','["孤缸照愁眠，明滅知夜久。", "熒熒月落牀，摵摵風入牖。", "美人悵何許，寤言不相偶。", "心寄南征鴻，雲漢長回首。"]'),
('ef03614e-d3aa-4434-9c37-5e6bdcff4809','遊雍丘燕溪分韵作','賀鑄','宋','宋诗','song-poetry','','[]','捨轡步平陸，解襟俯清池。',48,'全唐诗/poet.song.61000.json','["捨轡步平陸，解襟俯清池。", "微風度修竹，瑟瑟生淪漪。", "梨華照晴影，暖雪正紛披。", "把酒久沈想，況與玉人期。"]'),
('cdfb98e2-1fb5-40d3-b4ad-c69a6cc0aa59','擬王少伯新興','賀鑄','宋','宋诗','song-poetry','','[]','西北雲悠悠，東南日杲杲。',48,'全唐诗/poet.song.61000.json','["西北雲悠悠，東南日杲杲。", "浪語問陰晴，懸知行雨少。", "桃蹊換青蔭，夙昔一何好。", "臨牖思茫然，微風動萱草。"]'),
('5052cf01-fc66-4fef-90d4-c26f13e442a4','送陳傳道之官下邳','賀鑄','宋','宋诗','song-poetry','','[]','昔也官彭城，日與君子親。',144,'全唐诗/poet.song.61000.json','["昔也官彭城，日與君子親。", "俱遊大梁下，不見輒兼旬。", "衣食牽迫人，汗走長街塵。", "相逢立馬語，愁面如含辛。", "朝來忽叩門，頗驚黄綬新。", "告我即東下，得官淮泗濱。", "方語病中暍，藥物苦殫貧。", "故人復捨去，此懷難重陳。", "想見經舊廬，節候屬蕭辰。", "朝尋張翁墅，暮投寇叔鄰。", "二子亦吾好，尺書坐因循。", "交情定相訪，爲話正迷津。"]'),
('dad1bda3-55c3-435b-bcff-c12d23502148','東畿舟居阻雪懷寄二三知舊三首  其一','賀鑄','宋','宋诗','song-poetry','','[]','舟路江淮永，歲寒冰雪深。',72,'全唐诗/poet.song.61000.json','["舟路江淮永，歲寒冰雪深。", "戍期良敦迫，王畿方滯淫。", "疲筋苦跧卧，行藥長川陰。", "雲物接平陸，不見西飛禽。", "風從城闕來，如聞鐘漏音。", "昕霽更東邁，區區子牟心。"]'),
('3519033a-7ea6-4b50-82c0-e1f0e79cf430','東畿舟居阻雪懷寄二三知舊三首  其二','賀鑄','宋','宋诗','song-poetry','','[]','寒洛未澌結，東趨江海深。',72,'全唐诗/poet.song.61000.json','["寒洛未澌結，東趨江海深。", "舟人驚朝鼓，歛繂逗長林。", "林端落滯雪，沙際起鳴禽。", "病客坐長歎，攝衣涕流襟。", "親朋自茲遠，可是慕山陰。", "興盡莫回檝，何人知此心。"]'),
('466c6b5b-4d01-4157-827a-ef8dff6e58c2','東畿舟居阻雪懷寄二三知舊三首  其三','賀鑄','宋','宋诗','song-poetry','','[]','沄沄清川流，冉冉浮雲陰。',72,'全唐诗/poet.song.61000.json','["沄沄清川流，冉冉浮雲陰。", "天寒日云莫，魚鳥方潛沈。", "吾豈厭安隠，東浮違宿心。", "一官未足養，老境行侵尋。", "牛歌感白石，馬骨要黄金。", "慙無子虛作，萬里懸知音。"]'),
('099b5119-f02f-4012-8307-c9d9565cd91c','留侯廟下作','賀鑄','宋','宋诗','song-poetry','','[]','文成念韓痛，破産伺强秦。',276,'全唐诗/poet.song.61000.json','["文成念韓痛，破産伺强秦。", "千金募健士，椎斷屬車塵。", "東去變名姓，浮游淮泗濱。", "忍恥奉遺履，得書何老人。", "十年風雲會，赤帝資經綸。", "鴻門禍端結，一言即解紛。", "英彭既合縱，楚項提孤軍。", "偉哉借箸談，豎儒無復陳。", "分疆餌兩將，來若從龍雲。", "釋怨俾侯印，謀銷蛇豕羣。", "定都天府國，推功歸奉春。", "四老落吾術，拂巾辭隠淪。", "東朝羽翼就，楚調徒悲辛。", "出處能事畢，致君終乞身。", "豈眷萬戶封，僅與蕭酇均。", "淮陰敗晚節，顧亦非吾倫。", "願訪赤松子，逍遥雲漢津。", "强飯示終歿，爽靈方上賓。", "嚴祠鎮川湄，餘澤及斯民。", "客子老將至，低回冗從臣。", "慙無應時策，肝膈空輪囷。", "可教固無類，慨然輒求伸。", "未應終萬古，黄石獨能神。"]'),
('134032bd-270d-48da-b6f1-e9e95ec01b32','遊靈壁蘭皋園','賀鑄','宋','宋诗','song-poetry','','[]','集仙昔榮養，卜築循蘭陔。',216,'全唐诗/poet.song.61000.json','["集仙昔榮養，卜築循蘭陔。", "深徑萬株合，清池百畝開。", "飛梁蔭菡萏，攢棟跨崔嵬。", "淮海劚紅藥，瀟湘移翠栽。", "岱松珮蘿蔦，海石糊莓苔。", "車馬遠驚聒，魚鳥忘嫌猜。", "病客倦舟檝，尋春此裴徊。", "閏年物候遲，前日已聞雷。", "薄景未晞雪，東風新破梅。", "主人京洛舊，杖屨容參陪。", "指我艮隅地，方營秋月臺。", "眼明壁間字，醉墨題東萊。", "短句頗清絕，早推能賦才。", "殷勤卷白苧，爲爾拂塵埃。", "安得一携手，更傾林下盃。", "酒闌話平昔，豈復顧形骸。", "行役浸相遠，人生信悠哉。", "薄暮重回首，長哦歸去來。"]'),
('bcf18c40-0c2d-48c3-ae0a-dccc1e70a304','題楊子王輅故居清軒','賀鑄','宋','宋诗','song-poetry','','[]','卜築負南郭，褰開臨要津。',72,'全唐诗/poet.song.61000.json','["卜築負南郭，褰開臨要津。", "舟輿占集地，奈爾獨清人。", "坐上一樽酒，江南千里春。", "何須茂弘扇，何患元規塵。", "遊子感陳躅，怳如平生親。", "九原不可作，歸老復誰鄰。"]'),
('c6679eba-9a2d-40fc-bc94-478e6231f9b8','遊金陵雨花臺','賀鑄','宋','宋诗','song-poetry','','[]','迢迢朱雀航，飛蓋共淩越。',156,'全唐诗/poet.song.61000.json','["迢迢朱雀航，飛蓋共淩越。", "東風石子岡，芳草微徑絕。", "生公法堂在，清夜貯明月。", "回認城郭遊，春華爛晴雪。", "長烟動江隩，微雲泊山脅。", "連檣去遲回，白鳥屢明滅。", "江山信清麗，人物久銷歇。", "戍堡定荒凉，投身計何拙。", "塵衫與汗馬，端爲老生設。", "李侯朱門俊，許與盡時哲。", "俛首就微班，剛腸頗摧折。", "人生特眠飯，似是此身切。", "歲晚賦歸田，非君復誰結。"]'),
('8adacf19-f5e5-4313-aa41-28dc9c12ccf1','宿法惠寺','賀鑄','宋','宋诗','song-poetry','','[]','驅馬越飛澗，揚旌下回岡。',156,'全唐诗/poet.song.61000.json','["驅馬越飛澗，揚旌下回岡。", "欻見層浮圖，高風振琅璫。", "重門壯且深，老柏森然行。", "佛子出延客，投鞭步長廊。", "中庭汲新泉，一飲生清凉。", "孤坐興登覽，危梯趨上方。", "蕭蕭荒竹林，簷外如環牆。", "樵牧斷行徑，龍蛇知所藏。", "山禽喜暄暘，嘯侶何琅琅。", "子規特殷勤，使人懷故鄉。", "引領落西北，暮色來蒼茫。", "一官早見縻，微尚久未償。", "明發復東去，斯遊良不忘。"]'),
('f5e99645-39b7-4a09-a746-65e5d1ec93fe','題香社寺平痾湯泉','賀鑄','宋','宋诗','song-poetry','','[]','驪山御湯殿，歲久玉蓮傾。',96,'全唐诗/poet.song.61000.json','["驪山御湯殿，歲久玉蓮傾。", "誰謂大江北，有泉溫且清。", "相傳白雲竇，中閟丹砂英。", "澡濯浹肌骨，沉痾亟能平。", "豈特滌吾足，徑當潔吾纓。", "築廬俯源上，涵泳鳬鷗輕。", "非復罜塵網，御風朝玉京。", "賦詩投楚澤，用弔懷沙生。"]'),
('6c52d3f3-8b3f-4b07-ab44-3ecb9e945097','宿寶泉山慧日寺','賀鑄','宋','宋诗','song-poetry','','[]','日入不遑息，驅車更之東。',108,'全唐诗/poet.song.61000.json','["日入不遑息，驅車更之東。", "回蹊出蒙密，解袂迎長風。", "風從何許來，歷歷江南鐘。", "頓轡阿蘭若，虛庭月正中。", "流螢逗深竹，白鳥巢青松。", "華燈耿翠箔，瑶花擢春叢。", "絕境美清夜，怳非塵界逢。", "惜無一樽酒，幸與之子同。", "明發即南北，浮生兩飛蓬。"]'),
('7025da31-8154-4414-8ade-93ff59353bfa','曉度黄葉嶺東谷懷寄金陵王居士閑叟','賀鑄','宋','宋诗','song-poetry','','[]','陰谷不寓暑，風松朝露零。',96,'全唐诗/poet.song.61000.json','["陰谷不寓暑，風松朝露零。", "乳溪逗綠篠，琴筑聲泠泠。", "老石漬金碧，窅然沈列星。", "酌此石上泉，餌彼松下苓。", "倏欻振飛步，豈徒制頹齡。", "何須歷五嶽，即蹈神人庭。", "顧余方有役，俗駕不敢停。", "寄音采真子，來卜白雲扃。"]'),
('54299b28-b677-481e-a538-afb155dbd59a','腰疼山浮圖下作','賀鑄','宋','宋诗','song-poetry','','[]','茲山非峻極，名不載圖譜。',120,'全唐诗/poet.song.61000.json','["茲山非峻極，名不載圖譜。", "投策一攀躋，未覺病腰膂。", "蒼松带寒日，交陰層窣堵。", "儼然黄面師，粉繪色已古。", "我貪五斗米，磬折向兒乳。", "復著鞍馬勞，疲筋劇笞楚。", "此身異金石，能涉幾寒暑。", "誅茅結圓廬，宴坐此其所。", "清心日焚誦，庶拔未來苦。", "望塵彼何人，碌碌安足數。"]'),
('dd9bec54-38f6-4fcb-b8a3-2ff17dbdae4c','曉登柏子岡回望金陵懷寄鍾山泉禪師','賀鑄','宋','宋诗','song-poetry','','[]','晨征念王事，駑駕煩屢叱。',120,'全唐诗/poet.song.61000.json','["晨征念王事，駑駕煩屢叱。", "既陟崔嵬高，稍辭叢薄密。", "烏牛霑宿露，白鳥明初日。", "清川舴艋遲，綠岸浮圖出。", "緬懷秣陵遊，曾綴秦淮繂。", "曳舄白下門，供香金粟室。", "得聞四句偈，如奉三尺律。", "損益非所知，婚嫁行且畢。", "庶幾追老龐，薄暮徼萬一。", "誓將遷枳根，待變江南橘。"]'),
('402c856f-a28b-4b8a-9db1-40e5dc102066','歷陽十詠 厤湖','賀鑄','宋','宋诗','song-poetry','','[]','昔也萬家邑，今爲無底淵。',48,'全唐诗/poet.song.61000.json','["昔也萬家邑，今爲無底淵。", "城郭泯遺迹，人民安得全。", "弔古一回首，薄暮愁風煙。", "拯溺不無意，吾生後千年。"]'),
('76c291b7-8c29-4404-a49e-53848587ffb3','歷陽十詠 雞籠山','賀鑄','宋','宋诗','song-poetry','','[]','楚姥昔奔迸，餘生脫沈淪。',48,'全唐诗/poet.song.61000.json','["楚姥昔奔迸，餘生脫沈淪。", "家禽不忍置，信謂婦人仁。", "空籠欻變化，千載高嶙峋。", "可待厤湖水，復生桑下塵。"]'),
('3d3143ff-87c0-4d5f-a621-76fd404f32bb','歷陽十詠 濡須塢','賀鑄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','孫郎昔鷹揚，曹瞞方虎視。',48,'全唐诗/poet.song.61000.json','["孫郎昔鷹揚，曹瞞方虎視。", "敢忘板築勤，遠挫兵鋒銳。", "俄聞青蓋謠，無復金陵氣。", "六代迭傾亡，長江亦平地。"]'),
('7e7e49ff-1a9b-49e2-ac3f-2b0babaff7b6','歷陽十詠 遏胡城','賀鑄','宋','宋诗','song-poetry','','[]','狂胡昔憑凌，闊步長淮外。',48,'全唐诗/poet.song.61000.json','["狂胡昔憑凌，闊步長淮外。", "難此百雉城，萬甲屯要害。", "時平一登望，江山互襟带。", "想像文獻公，清風宛如在。"]'),
('d64d277e-b3fa-48b1-869f-e95f360bb218','歷陽十詠 當利港','賀鑄','宋','宋诗','song-poetry','','[]','龍驤乘上游，銳氣吞敵境。',48,'全唐诗/poet.song.61000.json','["龍驤乘上游，銳氣吞敵境。", "風便趨吳京，收功在俄頃。", "平生負雄圖，晚歲方獲騁。", "何必傳鼎彝，江山與之永。"]'),
('61cad3f6-abba-401a-9364-ba1c0a684dbb','歷陽十詠 天門山','賀鑄','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','天門束箭流，北注據牛弩。',48,'全唐诗/poet.song.61000.json','["天門束箭流，北注據牛弩。", "淩高駐翠華，舟師燿威武。", "當時侍帷幄，誰復徵往古。", "虞舜有苗征，端爲兩階舞。"]'),
('abb450b6-119f-4b72-849e-dddb26bf8c57','歷陽十詠 采石磯','賀鑄','宋','宋诗','song-poetry','','[]','東西采石磯，山水兩清絕。',48,'全唐诗/poet.song.61000.json','["東西采石磯，山水兩清絕。", "漁舠與商舶，今古幾沿越。", "飄颻翰林主，長笑弄明月。", "難訪物外游，飛雲眇天末。"]'),
('652694bb-fcc0-4a8e-88f9-d8290cf2d86e','歷陽十詠 百福寺','賀鑄','宋','宋诗','song-poetry','','[]','文昌西郭居，修竹閉環堵。',48,'全唐诗/poet.song.61000.json','["文昌西郭居，修竹閉環堵。", "琴樽不復存，青蓮開梵宇。", "塵紛晦遺像，粉繪才可睹。", "拜奠愧無言，長哦君樂府。"]'),
('c37b7acd-ba08-423c-863a-fa76994ec9ea','歷陽十詠 桃花塢','賀鑄','宋','宋诗','song-poetry','','[]','種樹臨谿流，開亭望城郭。',48,'全唐诗/poet.song.61000.json','["種樹臨谿流，開亭望城郭。", "當年孟張輩，載酒來行樂。", "斯人久埃滅，節物今猶昨。", "看取不言華，春風自相約。"]'),
('2500fee7-5d7a-4a7f-9afd-75ee24d5e27b','歷陽十詠 平痾湯','賀鑄','宋','宋诗','song-poetry','','[]','文礎護清漪，炯若涵冰玉。',48,'全唐诗/poet.song.61000.json','["文礎護清漪，炯若涵冰玉。", "澡滌起沈痾，功參靈劑速。", "荒唐桑氏經，瑣碎桐君錄。", "利物本無窮，何須塵簡牘。"]'),
('3db3f66c-3cf1-416f-9e86-1c9e34e33058','三山','賀鑄','宋','宋诗','song-poetry','','[]','南朝鳳皇臺，置酒昔高會。',216,'全唐诗/poet.song.61000.json','["南朝鳳皇臺，置酒昔高會。", "酒酣望三山，宛在青天外。", "長哦謫仙吟，如啖鯨鯢鱠。", "明日信東風，孤帆出其背。", "荒戍接江濆，開門適相對。", "鼎足跱長川，不爲舟檝礙。", "雨暘雲吞吐，早晏潮進退。", "萬古免浮沈，曾微抃鰲戴。", "伊余厭塵坌，閉目何可奈。", "爽氣豁襟靈，山乎吾有頼。", "嘗聞晉阿童，萬艫飛戈快。", "徑造此山陲，滄波爲之隘。", "顧我疲軟姿，功名讓前輩。", "玄暉昔憑眺，物色頗有在。", "他時挂武冠，刀劍行且賣。", "山價略可酬，庵栖謝當代。", "遠持三山磯，况彼七里瀨。", "猶得傲狂奴，吾無故人待。"]'),
('e17ec92f-b256-4aaf-9866-edd8c3534a7d','望夫石','賀鑄','宋','宋诗','song-poetry','','[]','亭亭思婦石，下閱幾人代。',96,'全唐诗/poet.song.61000.json','["亭亭思婦石，下閱幾人代。", "蕩子長不歸，山椒久相待。", "微雲蔭髮彩，初日煇蛾黛。", "秋雨疊苔衣，春風舞蘿带。", "宛然姑射子，矯首塵冥外。", "陳迹遂亡窮，嘉期從莫再。", "脫如魯秋氏，妄結桑中愛。", "玉質委淵沙，悠悠復安在。"]'),
('a52d055c-5d5a-4a66-8373-ab8ad6270295','題烏江湯泉寄老庵','賀鑄','宋','宋诗','song-poetry','','[]','西庵松竹深，薄暮更微雨。',60,'全唐诗/poet.song.61000.json','["西庵松竹深，薄暮更微雨。", "山禽不畏人，嘲哳方對語。", "而余倦宦者，罷日今可數。", "京邑夙所懷，其如惡塵土。", "行復念斯遊，回頭悵何許。"]'),
('20e4494a-7812-43d4-a98b-8be62269c398','罷官有期懷寄歷陽朋好','賀鑄','宋','宋诗','song-poetry','','[]','迅雨蕩闌暑，層飈披滯雲。',120,'全唐诗/poet.song.61000.json','["迅雨蕩闌暑，層飈披滯雲。", "澄川繚楚甸，新陽麗秋旻。", "物候豈不嘉，中懷愴離羣。", "親朋滿城邑，繫滯此江濆。", "及瓜信匪遥，遂作河梁分。", "何人具供帳，樽酒展慇勤。", "一聆雪兒歌，載悽遊子魂。", "津鼓驚朝夢，□烟生夕曛。", "所悲紫蘭纓，復染京洛塵。", "春風有歸雁，報我相思文。"]'),
('3b09f49b-dba6-43f6-8946-c4b248d5707a','檥舟秦淮雨中寄侍其服之','賀鑄','宋','宋诗','song-poetry','','[]','篷卑每礙幘，倉狹纔容席。',96,'全唐诗/poet.song.61000.json','["篷卑每礙幘，倉狹纔容席。", "悽酸擁膝吟，奈此風雨夕。", "欣聞鐘漏旦，懷彼南城客。", "欲往從之遊，塞塗沒吾屐。", "方君慕栖遁，顧己淹行役。", "後夜歲云除，畸辰良足惜。", "何當斥氛閉，新暘被東陌。", "壺觴殿兩驂，聊取一日適。"]'),
('5eda2054-586b-4d0c-b743-414544932ac3','金山遊','賀鑄','宋','宋诗','song-poetry','','[]','輕舠放中𤃩，岸遠春風壯。',144,'全唐诗/poet.song.61000.json','["輕舠放中𤃩，岸遠春風壯。", "檝師俯仰呼，天水爭簸蕩。", "吾方扣其舷，聊賡小海唱。", "梢回即東麓，側磴聯屨杖。", "危剎表層巔，疲筋躡牽强。", "斜廊繚複殿，魚脊分背向。", "放目四垠寬，秋毫入吾望。", "侵雲鐵甕壘，崛起去緣傍。", "映日海門山，不蔕滄波上。", "吾雖百石吏，平昔有微尚。", "俄得金仙徒，翦蘿開岫幌。", "誓投桑榆年，浮玉翁自況。"]'),
('767362e3-2050-4444-b28c-602bf718dbf2','金山化成閣望焦山作','賀鑄','宋','宋诗','song-poetry','','[]','朝登化成閣，寫睇滄江東。',120,'全唐诗/poet.song.61000.json','["朝登化成閣，寫睇滄江東。", "巋然痤鶴山，屏截橫流中。", "雲烟生蔽虧，水石相磨礱。", "飛構結巖腹，天龍嚴佛宮。", "初無刳木智，不與塵界通。", "曠莽天地間，勝事豈易窮。", "將謀乘興入，難此迎潮風。", "可信浮桴約，僅有由也同。", "我亦念行役，翻如征北鴻。", "他日一漁艇，悠悠浮玉翁。"]'),
('c4e8f573-2b21-49b2-8a6c-cae232828ebb','金山夜集招米芾元章不至作','賀鑄','宋','宋诗','song-poetry','','[]','芳洲擷蘭珮，清夜栖寶坊。',120,'全唐诗/poet.song.61000.json','["芳洲擷蘭珮，清夜栖寶坊。", "晚風駕飛濤，柱石搖長廊。", "微月逗簷際，助我燈燭光。", "黄童天下才，亹亹陳與章。", "狂歌間險語，捧腹屢烘堂。", "惜無盃中物，可以延楚狂。", "興闌半道去，浪學山陰王。", "明發吾將還，滄波渺相望。", "如何方外徒，漫仕煩官倉。", "端爾凉秋節，白雲來帝鄉。"]'),
('408d309d-4e3f-402d-b0b3-e2734d449eb4','廣陵山光寺夜集留別黄材昆仲','賀鑄','宋','宋诗','song-poetry','','[]','維舟山光步，却顧廣陵城。',144,'全唐诗/poet.song.61000.json','["維舟山光步，却顧廣陵城。", "十里春風外，夾津芳草生。", "漁篷銜尾來，愧爾故人情。", "更卜連牀語，神房溫且清。", "語闌夜自久，淚燭剪復明。", "撤樽兀相視，酸涕流金纓。", "我本山海士，誤遭時網嬰。", "出身兩紀餘，何等爲浮名。", "矧此一分首，幾年當合并。", "離憂如驚瀾，蕩潏未易平。", "疏親繫遠邇，斯言出荒傖。", "音郵無禁限，勤訪白雲兄。"]'),
('c9406acb-a6e2-4ef3-9b7c-830f5e11404a','題崇勝寺無心菴','賀鑄','宋','宋诗','song-poetry','','[]','老鶴依林表，孤雲寓山間。',48,'全唐诗/poet.song.61000.json','["老鶴依林表，孤雲寓山間。", "結茅窮釋子，著身如許閑。", "有心即塵紛，無心猶石頑。", "有無心併置，日暮客來還。"]'),
('24525ebd-8815-4465-b86c-45f596cf79d1','和錢適德循寓懷二首','賀鑄','宋','宋诗','song-poetry','','[]','悠悠北山雲，苒苒東門草。',96,'全唐诗/poet.song.61000.json','["悠悠北山雲，苒苒東門草。", "紛吾起故居，與爾即遠道。", "巔崖博錙銖，得不償所耗。", "寄語鄰牆翁，歲晚從吾好。", "魯酒味自薄，楚歌聲更悲。", "曾無忘憂用，安事酒歌爲。", "西風激商序，流芳迫衰遲。", "寄語鄰牆客，茲非行樂時。"]'),
('afac5146-0b04-4721-9e1e-ee739dd1ab3b','題天清寺安上人北軒','賀鑄','宋','宋诗','song-poetry','','[]','南城繁氏臺，維昔孝王築。',120,'全唐诗/poet.song.61000.json','["南城繁氏臺，維昔孝王築。", "歌吟寂無聞，萬楹聯佛屋。", "道人開北牖，俯就百喬木。", "八月鳴青蟬，槐蛾委平綠。", "客來借榻卧，吹睡俄頃足。", "疏雨隔斜陽，垂虹跨長陸。", "良遊悵遲後，回謝三庚酷。", "瘦馬尾華軒，汗顔塵一掬。", "昨非勿復道，佳約猶可續。", "載酒定何時，新黄糝庭菊。"]'),
('92c6fa56-1897-4b35-95f6-b23f642ed4f1','感庭棗','賀鑄','宋','宋诗','song-poetry','','[]','昔來華纂纂，遽許實離離。',72,'全唐诗/poet.song.61000.json','["昔來華纂纂，遽許實離離。", "西風會搖落，行復見空枝。", "歲物感流駛，事功傷暮遲。", "咄彼身後名，前人端自欺。", "書殫南山竹，奄奄定何知。", "賢哉張生翰，千載與心期。"]'),
('04c9f829-c4ba-4271-bca8-2576d0c32d24','送表姪趙子億之官滄州兼簡通守李延寧','賀鑄','宋','宋诗','song-poetry','','[]','吾昔遊浮陽，童心初辦狂。',216,'全唐诗/poet.song.61000.json','["吾昔遊浮陽，童心初辦狂。", "淩高瞰海日，徑欲窮扶桑。", "歲紀忽再周，此圖竟莫償。", "今適送子往，臨風但彷徉。", "之子公族秀，祖基維懿王。", "成吾家宅相，裂封復吾鄉。", "汝翁同谷守，視吾猶雁行。", "後生古所畏，之子未易量。", "筦庫方試吏，事役須更嘗。", "譬彼汗血駒，齒齊即騰驤。", "是宜勤夙夜，動虞三尺妨。", "勿憚川陸遥，千里如鄰牆。", "勿計弦晦餘，俛仰度三霜。", "邊朔昔云苦，今歌海隅康。", "正頼別駕賢，不減晉王祥。", "依投得吏師，行見售所長。", "爲吾語故人，曩契想未忘。", "願致雙魚封，繼以一鶚章。"]'),
('ad4c99f8-9fe1-4b15-8e9b-a31de7aafbf4','夏夜雨晴遣懷','賀鑄','宋','宋诗','song-poetry','','[]','積潦被廣陌，誰過牛儈翁。',216,'全唐诗/poet.song.61000.json','["積潦被廣陌，誰過牛儈翁。", "閉關養尪瘵，藥石收良工。", "高齋俯嘉樾，疏箔延清風。", "左右列圖史，披張俄一通。", "從嗤獺祭魚，聊學蠹書蟲。", "坐挹古人語，孰云吾道窮。", "浮生夢境間，不蔕之驚蓬。", "生死猶物化，今昔賢愚同。", "分陰賤垂棘，白日莫再中。", "薄暮紛滓澄，寥寥還太空。", "爲問此何夕，凉蟾生自東。", "荒哉西園士，聯蓋追輕鴻。", "行樂以至斯，不知息微躬。", "側聆天雞鳴，凡耳初破聾。", "吾從汗漫遊，遡景鞭垂虹。", "濯纓咸池淵，晞髮若木叢。", "親串不我忘，惠音赤鯶公。", "長哦賦來歸，閱爾世上雄。"]'),
('fa1bee2d-4f0d-4f6a-ae93-34199aa1cc96','寄題栗亭縣名嘉亭','賀鑄','宋','宋诗','song-poetry','','[]','少陵昔避地，幽栖鳳皇川。',240,'全唐诗/poet.song.61000.json','["少陵昔避地，幽栖鳳皇川。", "始願獲其所，賦詩此終焉。", "睠彼美林麓，蔭膏腴上田。", "陽坡饒垂珠，陰谷繁玉延。", "長鑱勤采劚，服食攀飛仙。", "兵祲奪和氣，力耕無善年。", "林坰開冰雪，旬浹斷庖烟。", "嗚呼歌七章，暮節西南遷。", "環堵久蕪沒，斯亭名尚傳。", "茂宰愴懷古，增崇殊過前。", "雕甍揭長簾，下容十客筵。", "嫩嵐隔春叢，清竹鳴夏蟬。", "風月有高興，寫之武城弦。", "狂客屬尪廢，駑筋難强鞭。", "何暇遠登覽，但哦鯨海篇。", "尚苦八口累，依稀同曩賢。", "餘齡寄幻境，未斷東西緣。", "江淮米價平，一舸去悠然。", "幸此歲豐樂，浮游吾所便。", "異時訪陳躅，復使後人憐。"]'),
('7223776c-9b46-42f5-af51-fdec25aa2f48','遊盱眙南山示楊介','賀鑄','宋','宋诗','song-poetry','','[]','霜曉無輕颸，長淮浄如眼。',144,'全唐诗/poet.song.61000.json','["霜曉無輕颸，長淮浄如眼。", "招携南山遊，老子興不淺。", "不從千步橋，飛度一漁舠。", "中流鼓素檝，魴鱮欻驚跳。", "禪叟延遊客，匆匆問行色。", "千里遠京關，浮驂去安適。", "長嘯指滄浪，濯纓湔我裳。", "朱門曳裾地，槐柳自成行。", "多年困靴板，未立中人産。", "沈痼迫衰遲，求田咄何晚。", "神丸儻駐延，投此寄餘年。", "鑿室鄰楊氏，然薪繫太玄。"]'),
('3e9552d4-ff63-45d7-8f9c-290b3d5e7932','酬別盱眙杜輿','賀鑄','宋','宋诗','song-poetry','','[]','君希謝太傅，築室卧東山。',96,'全唐诗/poet.song.61000.json','["君希謝太傅，築室卧東山。", "應携玉人去，爲問何時還。", "扁舟欲之東，霜落江潮慳。", "難從京口渡，且轉廣陵灣。", "與君合復離，怳若愁夢間。", "嬰疾再寒暑，醫師憐我頑。", "頹齡未遽盡，解組誓投閑。", "幽巖有芳桂，晚歲約同攀。"]'),
('f974a6ae-0d5b-4df4-ab83-fe06c7d2b4d0','留別龜山白禪老兼簡楊居士介','賀鑄','宋','宋诗','song-poetry','','[]','汴尾望龜山，人烟了可數。',144,'全唐诗/poet.song.61000.json','["汴尾望龜山，人烟了可數。", "長淮斷日風，浩若千里阻。", "舟無百石載，兩腋憂雙艣。", "鷁首盪頹波，中流幾翔舞。", "維梢迫曛暮，坎坎禪林鼓。", "曳錫辱來過，依然識眉宇。", "青熒燈火畔，再得親軟語。", "多慙晚聞道，忠義夙自許。", "剛腸憤激際，赤手搏豺虎。", "過壯纏百痾，餘生託兒乳。", "羸軀假緩死，豈復勝冠組。", "會約子雲孫，西巖兩庵主。"]'),
('aec668db-7616-4aca-9a85-c71cae83d034','題海陵開元寺棲雲菴','賀鑄','宋','宋诗','song-poetry','','[]','道人猶浮雲，發彼王屋岑。',96,'全唐诗/poet.song.61000.json','["道人猶浮雲，發彼王屋岑。", "朝見膚寸合，暮爲四海霖。", "造物一戲耳，浮雲本無心。", "永謝應龍召，深栖雙樹林。", "蒼生熱惱地，千載仰慈陰。", "皎月示弦晦，清風何古今。", "誰舉甘露頌，轟然海潮音。", "支離病居士，和以無絃琴。"]'),
('582099d1-28b5-4e13-97a7-74d0876b6cd9','寄題潯陽周氏濂溪草堂','賀鑄','宋','宋诗','song-poetry','','[]','濂溪之水清，未足濯公纓。',180,'全唐诗/poet.song.61000.json','["濂溪之水清，未足濯公纓。", "平生抱苦節，成就此溪名。", "長嘯置符傳，孤雲歸思輕。", "溪頭四壁居，溪下百畝耕。", "量汲奉晨盥，課樵共夕烹。", "希逢杖屨遊，但聽弦歌聲。", "爲客剪三徑，傳家通一經。", "雙珠交照乘，合璧倍連城。", "被褐有餘樂，問縑無隠情。", "桂林兩枝秀，借爾俗眼榮。", "昔仰名父子，今推難弟兄。", "不應文範裔，遽謂公慙卿。", "如襲带礪封，毋爲權利傾。", "地實寢丘比，有力安得并。", "勒詩高岸石，敢告後代生。"]'),
('df9cf120-2e28-4705-8507-b38eee243f0a','送周壽元翁西上','賀鑄','宋','宋诗','song-poetry','','[]','露草蔓前庭，微蟲思明月。',168,'全唐诗/poet.song.61000.json','["露草蔓前庭，微蟲思明月。", "宵分耿不寐，懷我友生別。", "舟師望箕宿，綴幔須明發。", "蠲首託歸風，安知川路闊。", "夫君青雲士，行奉紫宸謁。", "一鶚抉塵籠，騫軒應霜節。", "仰追鸞鶴駕，肯顧狐兔穴。", "越客寓荒城，卑棲慕鳩拙。", "衰遲積尪弊，未死人事缺。", "嬾製一緘書，寄聲彼朝列。", "方今百廢舉，衮職補何闕。", "每自幸餘齡，江湖傲華髮。", "躬耕固難强，五斗代薇蕨。", "摩腹遡南薰，蒼生解煩暍。"]'),
('544c6971-06ce-4379-b847-26fe18d91895','題陶靖節集後','賀鑄','宋','宋诗','song-poetry','','[]','淵明不樂仕，解組歸柴桑。',72,'全唐诗/poet.song.61000.json','["淵明不樂仕，解組歸柴桑。", "遡風北窗下，坦腹傲羲皇。", "儲粟既屢空，乞食何惶惶。", "有身即大患，斯語聞伯陽。", "顧我亦多忤，丘樊思退藏。", "慙無辟粒術，圭勺耗官倉。"]'),
('1d50e07d-5490-4ec6-9993-81884e1edcf4','補感寓詩','賀鑄','宋','宋诗','song-poetry','','[]','猛虎未出柙，擾如搏鼠貍。',108,'全唐诗/poet.song.61000.json','["猛虎未出柙，擾如搏鼠貍。", "蒼鷹方在韝，孱甚伏卵雌。", "弭戢以違禍，孰云爾無知。", "幸遭縱釋仁，返謂人可欺。", "豈復念前辱，搖尾垂翅時。", "擇肉斃儕類，戕忍猶天姿。", "吾將罪虞者，奈何生致之。", "南山有重阻，鄧林無樛枝。", "機穽與羅罻，今也將安施。"]'),
('d091e4a9-f193-42bf-a53a-b8cf77e64019','黄鶴樓','賀鑄','宋','宋诗','song-poetry','','[]','登真者誰子，昔有費公禕。',168,'全唐诗/poet.song.61000.json','["登真者誰子，昔有費公禕。", "白日玉書下，青天駕鶴飛。", "此地少留憩，神標悵依依。", "振裾謝塵濁，與爾方遠違。", "層樓寵陳迹，江山長四圍。", "登臨美商素，雨氣薄西暉。", "水落州觜嫩，風豪帆背肥。", "飄然起遐想，琳館閟巖扉。", "明月識悠闊，白雲疑是非。", "金桃未遽熟，薤露虞先晞。", "高樹兩華表，長招羽駕歸。", "靈瓢五色劑，定與遺民揮。", "自顧乏仙質，延生猶可希。", "刀圭儻不吝，如飽首陽饑。"]'),
('57b2a693-5a2e-4cfb-9d90-543734c2a895','鸚鵡洲','賀鑄','宋','宋诗','song-poetry','','[]','鸚鵡隴下鳥，能語奇羽毛。',204,'全唐诗/poet.song.61000.json','["鸚鵡隴下鳥，能語奇羽毛。", "羅罻巧相致，琱籠關鐍牢。", "長懷故園樹，烟雨落空巢。", "萬里遷澤國，舟輿□□勞。", "正平託物賦，健筆不停操。", "千載訪陳躅，晴沙葭菼高。", "珍禽不復見，慨想若人豪。", "處士起河朔，英風拔時髦。", "文章儷墳誥，俛就猶詩騷。", "兒汝命楊孔，奴兵視劉曹。", "姦雄可奈此，束之投楚郊。", "忤俗竟非命，惜哉時不遭。", "非無擇木智，天下方滔滔。", "遺幹泯魚腹，浮魂誰復招。", "近結屈平好，佩蘭雜申椒。", "遠慙子胥烈，怒氣翻秋濤。", "空餘春草碧，恨血滿江皋。"]'),
('5f473e7d-c6f5-4883-93fe-1df4a8437b16','懷寄周元翁十首  其一','賀鑄','宋','宋诗','song-poetry','','[]','周郎假沔官，我偶來沔居。',72,'全唐诗/poet.song.61000.json','["周郎假沔官，我偶來沔居。", "得閑定相過，談笑沈痾袪。", "俄聞戍樓角，曉引吹咿嗚。", "自君居湓城，怳怳一夢餘。", "復求若輩人，陶竈搜璠璵。", "誠爲天下士，豈特江漢無。"]'),
('e91e9a2a-e9b9-4f38-bf7f-ce74606b976d','懷寄周元翁十首  其二','賀鑄','宋','宋诗','song-poetry','','[]','周郎嗜茗飲，偶與吾好同。',72,'全唐诗/poet.song.61000.json','["周郎嗜茗飲，偶與吾好同。", "贈行發吾寶，紫璧琱雲龍。", "此實太官物，分甘玉堂公。", "我曹百石吏，藜菽每不充。", "詩人盍得嘗，可以驕萬鍾。", "願君間一歠，千里共清風。"]'),
('e33f6965-4e42-4d44-95c7-af43f481f53a','懷寄周元翁十首  其三','賀鑄','宋','宋诗','song-poetry','','[]','周郎塵外人，冰甃立寒玉。',72,'全唐诗/poet.song.61000.json','["周郎塵外人，冰甃立寒玉。", "去我千里餘，炯炯長在目。", "有德且有言，可採篆縑竹。", "未爲造物憐，方徇斗筲祿。", "司晨屬羣雞，安事彼鸞鵠。", "聊自況疲駑，鹽車不爲辱。"]'),
('95652ebe-8a41-4fc7-8f4c-71c7025a2929','懷寄周元翁十首  其四','賀鑄','宋','宋诗','song-poetry','','[]','周郎妙雅道，五字可人師。',72,'全唐诗/poet.song.61000.json','["周郎妙雅道，五字可人師。", "許與非不嚴，奈何取我詩。", "我詩如秋蟲，徒增長年悲。", "指疵固有望，逐臭得無嗤。", "詩鳴人必窮，我窮豈所宜。", "願君勿閡此，晚節益經奇。"]'),
('86e836d5-ffab-4405-939c-62860bed7acf','懷寄周元翁十首  其五','賀鑄','宋','宋诗','song-poetry','','[]','周郎歸濂溪，旱燥害嘉穀。',72,'全唐诗/poet.song.61000.json','["周郎歸濂溪，旱燥害嘉穀。", "仰飽百指餘，嗷然坐空屋。", "應書乞米帖，得繼朝來粥。", "行陞大夫籍，月賜萬錢祿。", "振顯屬他年，盤飧羅海陸。", "毋忘佛子言，不食大夫福。"]'),
('e6189943-a972-4983-bbb7-c42f33ccca05','懷寄周元翁十首  其六','賀鑄','宋','宋诗','song-poetry','','[]','周郎西笑時，疊寄兩函書。',72,'全唐诗/poet.song.61000.json','["周郎西笑時，疊寄兩函書。", "情親語懇到，骨肉所不如。", "妙翰騁遒放，抵突黄與蘇。", "黄癯曳羸筋，蘇厚凝腯膚。", "我於季孟間，增少損有餘。", "家雞敢復道，儲此橐中珠。"]'),
('701f2f56-867f-4647-bb5d-a75cfa3e00ae','懷寄周元翁十首  其七','賀鑄','宋','宋诗','song-poetry','','[]','周郎走王都，馬足塵翻波。',72,'全唐诗/poet.song.61000.json','["周郎走王都，馬足塵翻波。", "賀老宦江夏，無人驚雀羅。", "出處躁靜間，奈此貧病何。", "平生解指誓，晚境忽婆娑。", "迫死不得休，前言食已多。", "尚敢厭閑冷，欻爲赴火蛾。"]'),
('d3dfb112-3664-4124-9712-1e7f6f656c41','懷寄周元翁十首  其八','賀鑄','宋','宋诗','song-poetry','','[]','周郎强仕年，藥石甘苦口。',72,'全唐诗/poet.song.61000.json','["周郎强仕年，藥石甘苦口。", "得無耗天和，湯劑禦衰朽。", "空華與□色，種種竟何有。", "妄愛溫柔鄉，蕩然不回首。", "坐令松桂姿，凋脆等蒲柳。", "幸勿易斯言，前車鏡湖叟。"]'),
('10f3b8a7-6173-4d42-a18f-5b603195925d','懷寄周元翁十首  其九','賀鑄','宋','宋诗','song-poetry','','[]','周郎有史才，班馬可並驅。',72,'全唐诗/poet.song.61000.json','["周郎有史才，班馬可並驅。", "紛紛讒諂人，畏君筆削誅。", "我恨接君晚，要亦君之徒。", "沈痾積歲月，顧此留須臾。", "志我壙中石，頼君文不諛。", "庶乎陵谷變，名字見君書。"]'),
('47c61242-c86c-4489-a739-7bc95215afde','懷寄周元翁十首  其一○','賀鑄','宋','宋诗','song-poetry','','[]','周郎貫江華，而復厭湖湘。',72,'全唐诗/poet.song.61000.json','["周郎貫江華，而復厭湖湘。", "我亦非樂此，西歸計茫茫。", "頹年抱沈痼，生理豈得長。", "後期真何時，存歿兩莫忘。", "懷君輒賦詩，落筆聯十章。", "它年一掩卷，爲我涕浪浪。"]'),
('d5cdc5db-3d16-4419-94db-632582dd3705','題武昌鄭判官直節亭','賀鑄','宋','宋诗','song-poetry','','[]','開亭榜直節，寵爾青琅玕。',180,'全唐诗/poet.song.61000.json','["開亭榜直節，寵爾青琅玕。", "歲晚傲霜雪，不同天下寒。", "挺立百丈夫，被之古衣冠。", "春華白粉澤，正色莫敢干。", "越客與登覽，微吟復長嘆。", "六鼇方抃戲，雲海翻狂瀾。", "儻逢龍伯公，何憚剪一竿。", "岐山鳴鳳雛，久刷五色翰。", "何以慰朝饑，美實來加餐。", "高材陋時用，自持良獨難。", "不願裁樂管，伶倫非古官。", "浪遭野王輩，三弄爲人歡。", "願製殺青簡，燦然漆與丹。", "褒貶約魯史，終古垂不刊。", "顧此託根地，辱哉久泥蟠。"]'),
('dac91d33-d6a0-4d31-82b4-772467b8fb45','題潘大臨東軒','賀鑄','宋','宋诗','song-poetry','','[]','陳公少荒誕，一室未遽掃。',180,'全唐诗/poet.song.61000.json','["陳公少荒誕，一室未遽掃。", "事功竟何成，老魅死不早。", "潘郎治寓舍，箒禿無遺蚤。", "庭砌蒔蘭萱，未霜除惡草。", "明窗羃輕素，朝日上杲杲。", "烟蔓擢薰爐，松腴浮墨沼。", "著書析魯史，百傳見脫藁。", "賊亂久逋誅，吾方力窮討。", "不應兩觀下，僅獲少正卯。", "坐可驕素臣，俾渠眸子瞭。", "而翁晏退食，筆削日課了。", "伯仲詠南陔，餘風颯林杪。", "安知自娛適，聊尉堂上老。", "起居侍杖藜，寒燠躬煬澡。", "昏定仰屋眠，是中亦大好。"]'),
('20fc8895-4ab1-4091-9941-47e1f7d32a4f','送咸寧陳令完夫移官吳郡','賀鑄','宋','宋诗','song-poetry','','[]','蒿萊東郭居，長者車成轍。',216,'全唐诗/poet.song.61000.json','["蒿萊東郭居，長者車成轍。", "禮經尚往來，豈爲我輩設。", "臨分懷出餞，津遠舟速發。", "十月雁啼寒，滄波洒微雪。", "送君一樽酒，孤飲聊耳熱。", "會取屈平書，商聲歌九闋。", "開正到吳郡，暘暖張燈節。", "兩地見梅花，相思不同折。", "官閑羈紲□，陳迹得搜閱。", "虎去丘隧空，燕驚宮火滅。", "廊傾罷鳴屧，蘭劚香逕絕。", "逮□故時人，唯餘劍池月。", "名城見圖繪，丹墨殊滅裂。", "細與賦新詩，長封寄天末。", "老狐首丘志，客子敢忘越。", "未死定歸東，柴荆晝常閉。", "右軍領妙語，年大不堪別。", "況復魚鳥情，飛沈方此訣。"]'),
('b8f672d7-fbb8-41b0-baf6-b212378acd34','和潘豳老漢上屬目','賀鑄','宋','宋诗','song-poetry','','[]','白雲蒙山頭，清川山下流。',48,'全唐诗/poet.song.61000.json','["白雲蒙山頭，清川山下流。", "芳洲采香女，薄暮漾歸舟。", "並蒂雙荷葉，逢迎一障羞。", "持情不得語，大婦在高樓。"]'),
('18297874-af84-4526-bbf0-c4010bbf2242','雨餘晚望','賀鑄','宋','宋诗','song-poetry','','[]','相應乳鳩鳴，桑間返照平。',48,'全唐诗/poet.song.61000.json','["相應乳鳩鳴，桑間返照平。", "明津小舫度，高隴一牛耕。", "林藪歸心健，塵埃病骨輕。", "屈騷魂爽在，未許獨君清。"]'),
('3f29003a-babc-4d39-b148-967941c687d5','自訟','賀鑄','宋','宋诗','song-poetry','','[]','朝聽明鐘出，暮隨衙鼓歸。',48,'全唐诗/poet.song.61000.json','["朝聽明鐘出，暮隨衙鼓歸。", "朝朝復暮暮，是是與非非。", "跡寄升沈路，言投禍福機。", "何窮百年事，端使一心違。"]'),
('b1d95982-b0e5-42f0-aad5-eab5723501e5','待曉朝謁天慶作','賀鑄','宋','宋诗','song-poetry','','[]','望曉謁琳宮，荒庭霧氣濃。',48,'全唐诗/poet.song.61000.json','["望曉謁琳宮，荒庭霧氣濃。", "曾陪羽林仗，如待景陽鐘。", "薄宦情無幾，勞生夢不容。", "樵朋與漁伴，它日會相從。"]'),
('998af6e8-7451-4f62-a578-32fbd2834811','送李易初還汶陽','賀鑄','宋','宋诗','song-poetry','','[]','客宦愴離羣，徐方復得君。',48,'全唐诗/poet.song.61000.json','["客宦愴離羣，徐方復得君。", "青衫初試吏，白面頗能文。", "畫舸浮春水，清樽醉舞裙。", "它年會相訪，分卧北山雲。"]'),
('9959d29b-d580-4466-9ec9-2af399798b38','重送','賀鑄','宋','宋诗','song-poetry','','[]','夾岸雪初消，青青見麥苗。',48,'全唐诗/poet.song.61000.json','["夾岸雪初消，青青見麥苗。", "傳聲汶陽客，已解木蘭橈。", "春水生張澤，春風動樂郊。", "良遊知不負，回首念無聊。"]'),
('fa686bf3-6c3e-4b61-b66a-c6fc50ffb75d','春書','賀鑄','宋','宋诗','song-poetry','','[]','新蠶經浴罷，舊燕未來前。',48,'全唐诗/poet.song.61000.json','["新蠶經浴罷，舊燕未來前。", "吏局坐如夢，物華行可憐。", "藻生南浦釣，雨足東皋田。", "故國負歸約，塵埃年復年。"]'),
('203513f4-5011-49f7-86ba-ec46361a699b','擬溫飛卿','賀鑄','宋','宋诗','song-poetry','','[]','露網朱甍上，風簾翠鎖前。',144,'全唐诗/poet.song.61000.json','["露網朱甍上，風簾翠鎖前。", "宿衾熏萏菡，朝鏡拂漪漣。", "津潤銷金筆，香依撲粉綿。", "度閑雙陸子，撥恨十三絃。", "鸚鵡殷勤語，旃檀委曲烟。", "鮫綃乾玉筯，魚鑰限金蓮。", "團扇酬桃葉，烏絲代杏牋。", "朱門長窅窅，白馬自翩翩。", "難釣三珠樹，徒拋七寶鞭。", "酒闌應有待，夢破即無緣。", "信鵲新秋去，孤蟾後夜圓。", "浪言牆外地，的是洞中仙。"]'),
('44278f02-5d20-4a10-97a8-0807bce2a701','快哉亭朝暮寓目二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','夙起喜舒曠，徑趨城上樓。',48,'全唐诗/poet.song.61000.json','["夙起喜舒曠，徑趨城上樓。", "初陽動禾黍，積雨失汀洲。", "水牯負鴝鵒，山樞懸栝蔞。", "坐慙真隠子，物我兩悠悠。"]'),
('afbd1d7f-1a46-4ed0-9748-5177c9728470','快哉亭朝暮寓目二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','積潦際危堞，登臨西照中。',48,'全唐诗/poet.song.61000.json','["積潦際危堞，登臨西照中。", "苔衣罥白羽，槐蔭懸青蟲。", "不淺胡牀興，無多團扇功。", "目窮猶起羨，演漾一漁篷。"]'),
('fd32b465-a3a9-44f1-b401-674d320b3331','題張氏白雲莊','賀鑄','宋','宋诗','song-poetry','','[]','江左陶徵士，高風昔所聞。',48,'全唐诗/poet.song.61000.json','["江左陶徵士，高風昔所聞。", "應慙五株柳，難比一溪雲。", "我有乘桴約，君方植杖耘。", "悠悠竟何得，晚歲盍同羣。"]'),
('bda97400-65d7-4091-9ecf-73ed633cbfb9','賦得枕上聞雁','賀鑄','宋','宋诗','song-poetry','','[]','朔吹飄驚雁，寒聲徹枕前。',48,'全唐诗/poet.song.61000.json','["朔吹飄驚雁，寒聲徹枕前。", "遠違沙漠雪，不下汶陽田。", "客夢悲中夜，歸期隔故年。", "莓苔與菰米，何處是湘天。"]'),
('de0426d1-fd09-44b8-a9ac-86057b5afb60','和人遊白雲莊二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','原野正春風，登臨一醉同。',48,'全唐诗/poet.song.61000.json','["原野正春風，登臨一醉同。", "陰晴時未定，今古思何窮。", "山勢落還起，溪流噎復通。", "隠君方自得，可羨爾冥鴻。"]'),
('72df2b5e-6ff3-45f2-879f-d577dd6d6829','和人遊白雲莊二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','可愛白雲翁，前溪檥釣篷。',48,'全唐诗/poet.song.61000.json','["可愛白雲翁，前溪檥釣篷。", "耕樵一徑下，井臼四鄰同。", "倦宦終何得，餘生寄此中。", "預煩多種秫，毋使酒盃空。"]'),
('2ceef140-7342-4456-9c9d-1093d57a464e','早夏','賀鑄','宋','宋诗','song-poetry','','[]','吏役初無補，端令樂事妨。',48,'全唐诗/poet.song.61000.json','["吏役初無補，端令樂事妨。", "不知春遂去，但愛日何長。", "薄雨梅含核，溫風麥擢芒。", "須容退食暇，一枕夢吾鄉。"]'),
('a1bed9a7-1be4-41aa-8017-a81632a6964b','辭酒','賀鑄','宋','宋诗','song-poetry','','[]','魯酒一樽薄，吾愁萬斛多。',48,'全唐诗/poet.song.61000.json','["魯酒一樽薄，吾愁萬斛多。", "塵埃斬馬劍，涕泗飯牛歌。", "髀肉生如許，顛毛黑幾何。", "功名可復道，身世兩蹉跎。"]'),
('53fa6222-78b6-4a72-98cb-d5836ad49d7f','送陳傳道攝官雙溝','賀鑄','宋','宋诗','song-poetry','','[]','弭楫想登臨，閒雲護日陰。',48,'全唐诗/poet.song.61000.json','["弭楫想登臨，閒雲護日陰。", "青蒲泗水闊，古木漢祠深。", "應醉盃中物，誰聞澤畔吟。", "禪坊養疴客，輕別若爲心。"]'),
('5c8820d1-9e63-42ee-8929-9ccc627c36bf','遊滕縣時氏園池','賀鑄','宋','宋诗','song-poetry','','[]','珍重西園主，開門待子猷。',48,'全唐诗/poet.song.61000.json','["珍重西園主，開門待子猷。", "城隅樹交蔭，樓下水通流。", "鴝鵒鳴深竹，蜻蜓駐小舟。", "可能忘夢想，塵土滿徐州。"]'),
('1f22f7fd-674c-4520-a143-31ca2d4b10d4','自鄆還徐道中','賀鑄','宋','宋诗','song-poetry','','[]','八月過新雨，行雲弄晚凉。',48,'全唐诗/poet.song.61000.json','["八月過新雨，行雲弄晚凉。", "山川乍明晦，禾黍半青黄。", "西去真何事，東還非故鄉。", "悠悠塵土裏，無路不亡羊。"]'),
('3d4d0b07-6c1e-485f-9997-730a038e5eb0','早發王村道中寄李智父','賀鑄','宋','宋诗','song-poetry','','[]','雞鳴戒徒御，驅馬度前陂。',48,'全唐诗/poet.song.61000.json','["雞鳴戒徒御，驅馬度前陂。", "得雨人耕早，邊山日上遲。", "罷休何復道，會合邈無期。", "頼有西來水，悠悠慰我思。"]'),
('035ea592-8655-41e7-ae6c-c83d60508871','暮投葛墟馬上','賀鑄','宋','宋诗','song-poetry','','[]','旬浹走千里，塵埃如有緣。',48,'全唐诗/poet.song.61000.json','["旬浹走千里，塵埃如有緣。", "慙無季子印，可換洛陽田。", "廣澤雁行去，荒山雨脚懸。", "長亭猶未見，疲馬不勝鞭。"]'),
('3a9edf3b-501f-497d-86dd-f6cbb84a8857','汴渠夜泊示畢紹彥祖','賀鑄','宋','宋诗','song-poetry','','[]','耿耿度中夜，浩歌誰與酬。',48,'全唐诗/poet.song.61000.json','["耿耿度中夜，浩歌誰與酬。", "屋頭風罨岸，枕底浪澎舟。", "春物行飄忽，鄉心久滯留。", "須明投吏部，一醉驛西樓。"]'),
('5d34a1c6-74b6-4ac2-94ee-bbabfd833522','丙寅舟次宋城作','賀鑄','宋','宋诗','song-poetry','','[]','水館四邊村，登臨奈斷魂。',48,'全唐诗/poet.song.61000.json','["水館四邊村，登臨奈斷魂。", "黄花開小徑，紅粉哭高原。", "舟楫逢新火，松楸老故園。", "斜陽一千里，依約是蘇門。"]'),
('572080b0-26e9-4627-96d0-6da209895f34','京居感興','賀鑄','宋','宋诗','song-poetry','','[]','爲問長安客，何人識要津。',48,'全唐诗/poet.song.61000.json','["爲問長安客，何人識要津。", "長持一馬箠，浪走六街塵。", "城闕烟中曉，關河雪後春。", "故園桃李在，樽酒願相親。"]'),
('c2fd92fe-60d0-43f5-b293-a315ed4f48fa','玉津晚歸馬上','賀鑄','宋','宋诗','song-poetry','','[]','落日南城陌，東風禁火時。',48,'全唐诗/poet.song.61000.json','["落日南城陌，東風禁火時。", "醉醒皆自得，單袷正相宜。", "綠樹侵高閣，繁花淚曲池。", "未應判節物，可奈故園思。"]'),
('f670329d-ffa0-44e7-88da-63274ecf71a4','西城有懷舊遊','賀鑄','宋','宋诗','song-poetry','','[]','西郭天泉里，依依得舊遊。',48,'全唐诗/poet.song.61000.json','["西郭天泉里，依依得舊遊。", "綺羅紅芰曉，絲管萬蟬秋。", "柳礙鞦韆陌，萍枕祓禊舟。", "華年勿復道，誰爲駐東流。"]'),
('aeb8f2f9-d99f-4bdb-9126-236ecf1725db','苦竹村南馬上','賀鑄','宋','宋诗','song-poetry','','[]','楚澤薰風後，林皋夕照間。',48,'全唐诗/poet.song.61000.json','["楚澤薰風後，林皋夕照間。", "漁船沿綠岸，鳥道轉荒山。", "久負盃中樂，長偷馬上閑。", "悠悠白門路，何日杖藜還。"]'),
('5a49600c-919d-42f5-8487-2ad43e4022bc','題諸葛谼田家壁','賀鑄','宋','宋诗','song-poetry','','[]','晚度孔明谼，林間訪老農。',48,'全唐诗/poet.song.61000.json','["晚度孔明谼，林間訪老農。", "行衝落葉徑，坐聽隔江鐘。", "後舍燈猶織，前溪水自舂。", "無多遊宦興，卜隠幸相容。"]'),
('24bfe998-eb21-4a88-9ba3-42745e094942','酬桂林從叔','賀鑄','宋','宋诗','song-poetry','','[]','江到三湘盡，山圍八桂深。',48,'全唐诗/poet.song.61000.json','["江到三湘盡，山圍八桂深。", "龍蛇寒下蟄，霧露晝多陰。", "迢遞馳梅信，殷勤訪竹林。", "淮南風土美，留滯亦何心。"]'),
('7e84067d-0e7e-4659-b696-b11971e7b693','寄金陵倉官趙令毣通直','賀鑄','宋','宋诗','song-poetry','','[]','歲律倏云莫，王孫興可堪。',48,'全唐诗/poet.song.61000.json','["歲律倏云莫，王孫興可堪。", "羨雲歸日下，隨雁滯江南。", "卑溼求長健，登臨頼半酣。", "西州眼中近，早晚寄華緘。"]'),
('0479fa98-7e68-45bb-9032-9a8bc755a2a1','懷寄潘孝本兼簡其子言','賀鑄','宋','宋诗','song-poetry','','[]','春色先梅嶺，秋聲後桂林。',48,'全唐诗/poet.song.61000.json','["春色先梅嶺，秋聲後桂林。", "溪通五羊險，雲近九疑陰。", "無雁難逢信，有猿能伴吟。", "一樽燒酒美，應對阿戎斟。"]'),
('48755b1d-e4ff-4c41-b0f4-3dcf3d07f959','送張商老西上','賀鑄','宋','宋诗','song-poetry','','[]','霧氣斂陂澤，鼓聲催客航。',48,'全唐诗/poet.song.61000.json','["霧氣斂陂澤，鼓聲催客航。", "蒹葭靡宿露，鸛鶴盤朝陽。", "行役自茲遠，離愁安可忘。", "黄華一樽酒，何處望吾鄉。"]'),
('0b6ffbfe-81f8-4d83-bb03-f642676827ba','題烏江東隆山鄧氏亭','賀鑄','宋','宋诗','song-poetry','','[]','逋客今何許，空餘接隠亭。',48,'全唐诗/poet.song.61000.json','["逋客今何許，空餘接隠亭。", "舟隨潮水上，門背夕陽扃。", "兔策塵生蠹，漁蓑雨化螢。", "題詩巖下石，聊代草堂靈。"]'),
('b0f8f0fe-04a0-4370-9c7d-b4edf93e08b9','登烏江柏子岡懷潘景仁','賀鑄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','驅車柏子岡，引首東南望。',48,'全唐诗/poet.song.61000.json','["驅車柏子岡，引首東南望。", "孤戍带寒日，長江流大荒。", "故人越五嶺，旅雁留三湘。", "好待春風暖，相隨還北鄉。"]'),
('f65c6c8d-77b9-45b5-ad6a-6c98e5c47047','宿黄葉嶺田家','賀鑄','宋','宋诗','song-poetry','','[]','聚落荒山裏，畬田歲不登。',48,'全唐诗/poet.song.61000.json','["聚落荒山裏，畬田歲不登。", "牛衣障隙雪，鼠穴見鄰燈。", "愁信魚難瞑，寒凝酒亦冰。", "悵然歌白石，推枕待晨興。"]'),
('c2108560-a745-460f-bfa3-a89ac5824f55','遊六合定山真如寺','賀鑄','宋','宋诗','song-poetry','','[]','隻履西歸遠，何年此布金。',48,'全唐诗/poet.song.61000.json','["隻履西歸遠，何年此布金。", "地寒蒼檜老，歲宴白雲陰。", "燒隔溪冰斷，樵穿徑雪深。", "祖心無處問，俗駕晚駸駸。"]'),
('0bbc725a-9c8a-49dc-a924-0bb9af7dc656','同道通師之香林馬上','賀鑄','宋','宋诗','song-poetry','','[]','冰霜節候遲，淮楚早春時。',48,'全唐诗/poet.song.61000.json','["冰霜節候遲，淮楚早春時。", "白草風頭急，黄雲日脚垂。", "鳥聲投古戍，馬力倦長陂。", "吾有官箴畏，勞生爾浪爲。"]'),
('2752040a-51ac-4911-9998-d456b91c53a0','題烏江丘氏昆仲歲寒亭','賀鑄','宋','宋诗','song-poetry','','[]','新甫移根遠，蒼然對兩翁。',48,'全唐诗/poet.song.61000.json','["新甫移根遠，蒼然對兩翁。", "閉門三尺雪，仰枕一亭風。", "東郭顔何厚，西來意莫窮。", "未應輸狹小，釀酒待春叢。"]'),
('3a6b0910-b8f5-43e2-bfb3-ed9f483281b6','送左禹赴江夏尉','賀鑄','宋','宋诗','song-poetry','','[]','汎汎青翰舟，亭亭黄鶴樓。',48,'全唐诗/poet.song.61000.json','["汎汎青翰舟，亭亭黄鶴樓。", "江山信清灑，人物想風流。", "美酒遣歸思，新詩題舊遊。", "有魚知不食，端作置書郵。"]'),
('6fd72e7d-6583-4c10-b65a-6f6701cbbab3','高望道中','賀鑄','宋','宋诗','song-poetry','','[]','積雨漲陂塘，田塍插晚秧。',48,'全唐诗/poet.song.61000.json','["積雨漲陂塘，田塍插晚秧。", "遠山宜薄莫，高燕弄微凉。", "馬革非吾願，魚餐饜此鄉。", "歸期知近在，猶待菊華黄。"]'),
('00711494-4abe-4a60-9092-6f1fb20230f6','湯泉道中','賀鑄','宋','宋诗','song-poetry','','[]','青石岡西下，靈泉産藥苗。',48,'全唐诗/poet.song.61000.json','["青石岡西下，靈泉産藥苗。", "山英如有待，木客可相招。", "蟬带風移樹，塵隨馬度橋。", "颺鞭吟舊句，歸路不知遥。"]'),
('b1669a4d-5ddf-43a3-b7d7-80674a965938','留別王掾元胥','賀鑄','宋','宋诗','song-poetry','','[]','之子貫東牟，青衫試宦遊。',48,'全唐诗/poet.song.61000.json','["之子貫東牟，青衫試宦遊。", "顛非小賀比，爽自阿戎流。", "未即芸香拜，俄先瓜戍秋。", "孤蓬別夜思，霜月滿滄洲。"]'),
('0339efd9-302f-493d-91c5-1d1a1239821c','檥舟當利口待風累日懷寄城中朋遊二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','一葉寄津口，怒濤安可乘。',48,'全唐诗/poet.song.61000.json','["一葉寄津口，怒濤安可乘。", "朝風占酒旆，夜爨乞漁燈。", "牛渚逢新月，秦淮想結冰。", "故人它夕夢，歌吹滿金陵。"]'),
('bb6da46b-61e0-4720-864d-c3270c417912','檥舟當利口待風累日懷寄城中朋遊二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','離憂不可解，罷酒獨登臨。',48,'全唐诗/poet.song.61000.json','["離憂不可解，罷酒獨登臨。", "潮落江空闊，雲繁歲晏陰。", "愁鴟守漁罧，怒犬突神林。", "觸目增悽斷，聊爲澤畔吟。"]'),
('05b7424f-849b-4f56-9953-ad7ae54fb819','重別王掾','賀鑄','宋','宋诗','song-poetry','','[]','別訪難遽了，不知寒夜長。',48,'全唐诗/poet.song.61000.json','["別訪難遽了，不知寒夜長。", "回燈撤盃案，抱被宿船倉。", "載聽遠雞唱，稍分征雁行。", "臨風滿掬淚，吹落一襟霜。"]'),
('24fc7f09-b121-4307-a931-6af10498a7ab','投宿清凉寺','賀鑄','宋','宋诗','song-poetry','','[]','建業衣冠集，秦淮舟楫屯。',48,'全唐诗/poet.song.61000.json','["建業衣冠集，秦淮舟楫屯。", "東西萬里客，朝暮兩潮渾。", "何處契心賞，片時清耳根。", "僕夫浪見問，但出石城門。"]'),
('beacdcf3-b489-4136-b277-ee692fbb570a','金陵懷寄歷陽王掾','賀鑄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','征虜亭邊路，望夫山下舟。',48,'全唐诗/poet.song.61000.json','["征虜亭邊路，望夫山下舟。", "長江不隔夢，明月祇供愁。", "促席歌塵斷，閑窗醉墨留。", "惜芳橋畔柳，誰繫木蘭舟。"]'),
('60259d23-afc8-45b5-9e7c-4b7d0b1c432e','秦淮夜泊','賀鑄','宋','宋诗','song-poetry','','[]','官柳動春條，秦淮生暮潮。',48,'全唐诗/poet.song.61000.json','["官柳動春條，秦淮生暮潮。", "樓臺見新月，燈火上雙橋。", "隔岸開朱箔，臨風弄紫簫。", "誰憐遠游子，心旆正搖搖。"]'),
('ba4e1859-57b6-4807-b1c8-643218613f64','鍾山法雲彥上人留中餐罷遊草堂寺','賀鑄','宋','宋诗','song-poetry','','[]','弭楫秦淮尾，登臨殊興迴。',48,'全唐诗/poet.song.61000.json','["弭楫秦淮尾，登臨殊興迴。", "難銷蔬飯飽，更過草堂來。", "日轉喦扉暝，風披蕙帳開。", "吾非海鹽令，猿鳥莫相猜。"]'),
('6228aed9-8bff-47aa-acda-df554856d4c7','酬別法雲彥上人','賀鑄','宋','宋诗','song-poetry','','[]','將別雁門師，殷勤訪所之。',48,'全唐诗/poet.song.61000.json','["將別雁門師，殷勤訪所之。", "江湖懷北闕，鷗鳥戀南枝。", "朝隠非吾所，山英不汝欺。", "明年東下約，春水漾蘋時。"]'),
('d6c5ba98-0f41-4d8b-a7a0-374c2a6f961c','易官後呈交舊','賀鑄','宋','宋诗','song-poetry','','[]','當年筆漫投，說劍氣橫秋。',48,'全唐诗/poet.song.61000.json','["當年筆漫投，說劍氣橫秋。", "自負虎頭相，誰封龍額侯。", "聊辭噲等伍，濫作詩家流。", "少待高常侍，功名晚歲收。"]'),
('405f9868-fd7c-4abb-a0d1-d5c26ffac975','辛未興龍節日懷歷陽王掾元胥','賀鑄','宋','宋诗','song-poetry','','[]','昨歲東溪口，扁舟欲下江。',48,'全唐诗/poet.song.61000.json','["昨歲東溪口，扁舟欲下江。", "伴愁燈映幔，欺睡月侵窗。", "漫寄書連紙，誰同酒一缸。", "何當見之子，聊使我心降。"]'),
('49c97655-f396-4db7-a00e-4df2c74382c9','廣津門東馬上','賀鑄','宋','宋诗','song-poetry','','[]','津頭落帆鼓，薄暮尚蓬鼕。',48,'全唐诗/poet.song.61000.json','["津頭落帆鼓，薄暮尚蓬鼕。", "疑是秦淮口，扁舟醉夢中。", "不堪隋岸北，塵土一鞭風。", "傳語端能否，伯勞飛自東。"]'),
('a4c9b1df-45f7-4c2c-a7c8-aef130396245','久病寄二三親友','賀鑄','宋','宋诗','song-poetry','','[]','早昧攝生理，百勞戕至真。',72,'全唐诗/poet.song.61000.json','["早昧攝生理，百勞戕至真。", "藥靈翻佐病，詩癖竟窮人。", "終負黄壚恨，長違白首親。", "一囊安可得，四壁未應貧。", "燈下塵編淚，風前墓草春。", "儻忘雞酒設，腹痛勿多嗔。"]'),
('16665b66-2ae3-4f19-9d24-bfbce1f5df86','秋衣聞雨晨興偶書','賀鑄','宋','宋诗','song-poetry','','[]','故國心馳北，扁舟計漫東。',48,'全唐诗/poet.song.61000.json','["故國心馳北，扁舟計漫東。", "寒生一夜雨，病涉兩秋風。", "落泊籬根葉，幽憂屋角蟲。", "何情悲節物，聊自況衰翁。"]'),
('2c87e4ec-fc68-45bb-91d2-a96662ea0890','謝米雍丘元章見過','賀鑄','宋','宋诗','song-poetry','','[]','今古兩妙令，雍丘與太丘。',48,'全唐诗/poet.song.61000.json','["今古兩妙令，雍丘與太丘。", "當時號清白，後日想風流。", "吏鼾庭陰午，農歌野色秋。", "吾非荀氏老，愧爾德星留。"]'),
('4a9b26ff-feca-4a29-a062-557b91f91239','留別米雍丘二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','明釭通夜語，累塊寫胸中。',48,'全唐诗/poet.song.61000.json','["明釭通夜語，累塊寫胸中。", "水癖推劉令，書名浼魯公。", "忌猜悲廩鼠，逐熱賤雲鴻。", "不乏佳山水，東南著兩翁。"]'),
('7d2f03f7-0076-4ac8-a4a0-bfc7b2acfa7b','留別米雍丘二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','好住楚公子，山林何處逢。',48,'全唐诗/poet.song.61000.json','["好住楚公子，山林何處逢。", "官身須自乞，俗眼可相容。", "叔夜懶猶鍛，伯鸞傭且舂。", "多慙方祿隠，爾汝傲吳儂。"]'),
('00705d16-0cde-425b-af9e-2481867a1121','寶應野泊','賀鑄','宋','宋诗','song-poetry','','[]','伏枕漳濱後，維舟楚澤邊。',48,'全唐诗/poet.song.61000.json','["伏枕漳濱後，維舟楚澤邊。", "筋骸非壯日，節物迫窮年。", "夜雨侵牀漏，晨炊湊鼻烟。", "勞生我其分，十口亦飄然。"]'),
('a618cfe6-f832-4c3c-810b-fe7e2e083f04','題甘露寺浄名齋兼寄米元章','賀鑄','宋','宋诗','song-poetry','','[]','日出天垠露，江橫地軸分。',48,'全唐诗/poet.song.61000.json','["日出天垠露，江橫地軸分。", "馳年悲落木，羈思託孤雲。", "重掃浄名室，長招漫仕君。", "悠悠德璋輩，未辦勒移文。"]'),
('9bbfff66-e9b9-4736-ad49-318e4cec007d','龜山晚泊','賀鑄','宋','宋诗','song-poetry','','[]','春候半寒溫，維舟淮上村。',48,'全唐诗/poet.song.61000.json','["春候半寒溫，維舟淮上村。", "長林補山豁，青草際潮痕。", "久厭浮家役，重招去國魂。", "禪房欲舒寫，烟雨促黄昏。"]'),
('7dee4276-aaae-4c90-9d1b-5b0895d2f24b','歲暮舟居卧病懷寄金陵和上人','賀鑄','宋','宋诗','song-poetry','','[]','野泊歲云暮，念歸期正賒。',48,'全唐诗/poet.song.61000.json','["野泊歲云暮，念歸期正賒。", "津童爲過客，商舶是鄰家。", "雪密魚依罧，潮迴蚌委沙。", "南州人健否，不寄早梅華。"]'),
('d7ede207-a403-4bf9-9b95-c6ff32514cfe','寓泊臨淮有懷杜脩撰','賀鑄','宋','宋诗','song-poetry','','[]','幕卷歌鬟列，堂深蜜炬然。',48,'全唐诗/poet.song.61000.json','["幕卷歌鬟列，堂深蜜炬然。", "臨風鳴羯鼓，待月戲鞦韆。", "短韵吟牋出，長簷醉帽偏。", "斯人違薄俗，何減孟公賢。"]'),
('4a1107ed-17f3-44c1-bc4d-bd63e519c749','舟發金陵望歷陽作','賀鑄','宋','宋诗','song-poetry','','[]','尚識歷陽道，依然西照間。',48,'全唐诗/poet.song.61000.json','["尚識歷陽道，依然西照間。", "風烟石磧戍，林麓楚王山。", "隔水一凝佇，當年百往還。", "誰憐躍馬客，衰病再投閑。"]'),
('81f24100-57d6-488e-8ecb-8763ed0a7ae2','江行寫望','賀鑄','宋','宋诗','song-poetry','','[]','斜照侵疏箔，微凉逗小窗。',48,'全唐诗/poet.song.61000.json','["斜照侵疏箔，微凉逗小窗。", "青蒲故依渚，白鳥屢橫江。", "遣興詩三百，煎愁艣一雙。", "前舟定未遠，疊鼓聽逢逢。"]'),
('9af021d7-6b29-48f1-86c1-2d05dbf90f88','郎官湖','賀鑄','宋','宋诗','song-poetry','','[]','當年賢守令，載酒沔南遊。',96,'全唐诗/poet.song.61000.json','["當年賢守令，載酒沔南遊。", "凉月呈新霽，明湖涵素秋。", "郎官夏口使，仙客夜郎囚。", "促膝青螭舫，連觴紫綺裘。", "高驩隨雨散，餘躅想風流。", "芳草失青履，滄波浮白鷗。", "江吞百頃盡，石刻一篇留。", "宜有沈碑者，前懷陵谷憂。"]'),
('1ad09601-9b6d-45fe-a069-2391cb80dee1','題寶泉官舍壁','賀鑄','宋','宋诗','song-poetry','','[]','偶著强名字，非才但鑄金。',48,'全唐诗/poet.song.61000.json','["偶著强名字，非才但鑄金。", "不妨稱外監，況復住山陰。", "勝日聊披卷，清風故解衿。", "餘生偷祿隠，何等是升沈。"]'),
('9b52ba6d-2dda-4330-97fb-125261cacf91','江夏寓興二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','風與檣烏便，儂先塞雁來。',48,'全唐诗/poet.song.61000.json','["風與檣烏便，儂先塞雁來。", "山經七澤斷，潮自九江回。", "漁父猶知隠，騷人枉衒才。", "朋遊正相遠，梅信爲誰開。"]'),
('b87aec46-3ee8-4b6f-9d0b-e2d42c856510','江夏寓興二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','陂湖蹙坊市，江漢復縱橫。',48,'全唐诗/poet.song.61000.json','["陂湖蹙坊市，江漢復縱橫。", "沮洳莎城阽，晴暘竹瓦鳴。", "新文添鵩賦，異味識黿羹。", "豈復悲流落，官糧寓此生。"]'),
('58fe803c-4c47-4582-b899-991aa14e1a6a','九月十日寄潘邠老','賀鑄','宋','宋诗','song-poetry','','[]','明月昔如許，懷人殊不來。',48,'全唐诗/poet.song.61000.json','["明月昔如許，懷人殊不來。", "徒歌桃葉曲，又負菊華開。", "尺紙緘愁去，扁舟載夢迴。", "它年雞黍約，千里信悠哉。"]'),
('c7d66d80-b3c5-4286-97ae-9cd479e4e105','送蒲圻陳主簿彥昇歸越','賀鑄','宋','宋诗','song-poetry','','[]','好在稽山北，因君訪故園。',48,'全唐诗/poet.song.61000.json','["好在稽山北，因君訪故園。", "風流久衰歇，湖水自清渾。", "可得千秋觀，相傳百代孫。", "時聞祖行客，不減漢東門。"]'),
('a0523164-d986-4bcc-99fb-de4af0babc13','送金壇慎令瓛','賀鑄','宋','宋诗','song-poetry','','[]','清素復多聞，天涯晚得君。',48,'全唐诗/poet.song.61000.json','["清素復多聞，天涯晚得君。", "相延蒲塞饌，細演貝多文。", "世味淡如水，身謀散勝雲。", "謾爲花縣約，聊慰此臨分。"]'),
('40223340-4147-4eb0-9c74-7b24444ec333','寄題盱眙杜子師東山草堂','賀鑄','宋','宋诗','song-poetry','','[]','東山與物遠，松竹蔭茅茨。',48,'全唐诗/poet.song.61000.json','["東山與物遠，松竹蔭茅茨。", "信有冥鴻志，難藏霧豹姿。", "會招安石起，何患德璋移。", "後日岩扉下，遊人想履綦。"]'),
('6ee3eabf-f1ab-46d1-9659-163125b9a668','上巳有懷金明池游賞','賀鑄','宋','宋诗','song-poetry','','[]','西城小雨宿塵消，春水溶溶拍畫橋。',64,'全唐诗/poet.song.61000.json','["西城小雨宿塵消，春水溶溶拍畫橋。", "拾翠汀洲白蘋發，披香宮殿紫雲高。", "綵舟日晚綺羅醉，油幕風晴絲管焦。", "俠少朋遊應念我，一年佳賞負今朝。"]'),
('b454455b-ae4a-4226-89c7-fc6feab9d87f','贈張士元','賀鑄','宋','宋诗','song-poetry','','[]','夫子安貧五十年，年來生事更茫然。',64,'全唐诗/poet.song.61000.json','["夫子安貧五十年，年來生事更茫然。", "青衿稚子彼何有，白首故人誰見憐。", "霜後鶉衣寒綻線，日高魚釜凍無烟。", "冗官猶愧蘇司業，不得時時送酒錢。"]'),
('e5d5cc2a-7caf-4c1f-a465-5976612be4d9','雨晴西郊寓目','賀鑄','宋','宋诗','song-poetry','','[]','城中厭雨過清和，偶出西郊野意多。',64,'全唐诗/poet.song.61000.json','["城中厭雨過清和，偶出西郊野意多。", "蠶簇趁晴初摘繭，麥場經潤欲生蛾。", "營巢黄鳥啼深樹，引犢青牛飲暮河。", "老圃念人留竚久，挽衣沽酒願相過。"]'),
('7d06e0c8-9505-47f1-abb1-f50eea671768','寄周文清','賀鑄','宋','宋诗','song-poetry','','[]','節物驚心不我留，故人相望海邊州。',64,'全唐诗/poet.song.61000.json','["節物驚心不我留，故人相望海邊州。", "芰荷老盡池臺晚，鴻雁來多雲漢秋。", "誰共清樽尋樂事，獨將長幅寫離憂。", "明年芳草青門道，好試青衫伴俠遊。"]'),
('843364b1-63d6-4cb3-9d3f-bc24f38adc1c','寄王岐','賀鑄','宋','宋诗','song-poetry','','[]','未從名宦兩蹉跎，可但詩狂與酒魔。',64,'全唐诗/poet.song.61000.json','["未從名宦兩蹉跎，可但詩狂與酒魔。", "紫陌塵埃日馳逐，青樓燈火夜經過。", "當時豪縱年方少，今日疏慵病更多。", "唯見凭欄復敧枕，往來方寸奈情何。"]'),
('0989c1d1-e2c4-4654-a513-34a1957f9848','和答鄭郎中見寄','賀鑄','宋','宋诗','song-poetry','','[]','客子由來懷故鄉，蘇門冷落白雲旁。',64,'全唐诗/poet.song.61000.json','["客子由來懷故鄉，蘇門冷落白雲旁。", "夢隨夜月鐘前斷，詩入秋風草共荒。", "操板鎌靴遊宦厭，開樽揮麈舊歡長。", "泜川逸老應相念，爲倚闌干向夕陽。"]'),
('765f5951-7a35-447c-9520-ce11a86aa28a','和田錄事君義詠雪','賀鑄','宋','宋诗','song-poetry','','[]','千里龍沙失舊荒，四來雲物助蒼凉。',64,'全唐诗/poet.song.61000.json','["千里龍沙失舊荒，四來雲物助蒼凉。", "直疑見月應無影，未必因風始解狂。", "枉費鉛華□楚女，不禁湯餠試何郎。", "回中自是人間世，怊悵龜臺去路長。"]'),
('51fdbb71-8b48-4e63-8a7c-97e1272982d1','和田錄事新燕','賀鑄','宋','宋诗','song-poetry','','[]','新巢故國兩依依，似與春華秋葉期。',64,'全唐诗/poet.song.61000.json','["新巢故國兩依依，似與春華秋葉期。", "雨過池塘得泥近，日高臺榭卷簾遲。", "鞦韆節後初相見，祓禊人歸有所思。", "雙侶多情擬憑杖，小牋封就碧雲詩。"]'),
('f10fa2bc-abb4-4b34-95ad-d01836fb91f7','冠氏縣齋書事寄滏陽朋遊','賀鑄','宋','宋诗','song-poetry','','[]','小閣燒香麝煎濃，翠苔庭院綠陰風。',64,'全唐诗/poet.song.61000.json','["小閣燒香麝煎濃，翠苔庭院綠陰風。", "卷簾燕自雙飛去，敧枕人方半夢中。", "秋鬢先於懷縣令，春愁多似義城公。", "西園酒伴無消息，欲寄魚箋水自東。"]'),
('1a53bf3d-e035-4b7b-adef-a9e86b836830','冠氏寺居書懷','賀鑄','宋','宋诗','song-poetry','','[]','古剎荒凉晝掩門，鳴雞吠犬接西村。',64,'全唐诗/poet.song.61000.json','["古剎荒凉晝掩門，鳴雞吠犬接西村。", "窗間自記曾歸夢，樓外誰招欲斷魂。", "漫賦新詩題琬琰，少逢佳客佩蘭蓀。", "更堪愁肺經春病，負爾商歌酒一樽。"]'),
('555042db-6645-48b0-ba81-a0d148b12fe5','題彭城張氏放鶴亭','賀鑄','宋','宋诗','song-poetry','','[]','曾見君家亭上碑，東望風月動閑思。',64,'全唐诗/poet.song.61000.json','["曾見君家亭上碑，東望風月動閑思。", "昔無卜築如相待，今遂登臨是不期。", "萬頃白雲山缺處，一庭黄葉雨來時。", "許昌應負重泉恨，當日陽春枉賦詩。"]'),
('534867ee-ca78-4323-8fb5-fc1d37f1e371','九日登戲馬臺','賀鑄','宋','宋诗','song-poetry','','[]','當時節物此山川，倦客登臨獨惘然。',64,'全唐诗/poet.song.61000.json','["當時節物此山川，倦客登臨獨惘然。", "戲馬臺荒年自久，射蛇公去事空傳。", "黄華半老清霜後，白鳥孤飛落照前。", "不與興亡城下水，穩浮漁艇入淮天。"]'),
('f8de3330-2174-45f6-9c38-f171d51af315','九日呈李成父','賀鑄','宋','宋诗','song-poetry','','[]','城中霧雨曉冥冥，坐失城頭百尺亭。',64,'全唐诗/poet.song.61000.json','["城中霧雨曉冥冥，坐失城頭百尺亭。", "行樂固知非我事，苦吟猶得有君聽。", "未應白髮饒新貴，任使黄華笑獨醒。", "異日肯尋雞黍約，太行長遶故園青。"]'),
('75d09801-b25a-4de7-8e96-057ba3a4d60b','題彭城南臺寺蘇眉山詩刻後','賀鑄','宋','宋诗','song-poetry','','[]','秋風幾度老江蘺，鼎水眉峰隔夢思。',64,'全唐诗/poet.song.61000.json','["秋風幾度老江蘺，鼎水眉峰隔夢思。", "下走誤傳宣室召，上前誰進子虛辭。", "東坡麋鹿同三徑，西掖鵷鸞占一枝。", "獨有野僧違一俗，翠珉新勒舊題詩。"]'),
('a15fb9e0-aec6-461e-9f3b-c9fba5d3459f','春懷','賀鑄','宋','宋诗','song-poetry','','[]','東風吹雪陰復晴，西日冉冉林間明。',64,'全唐诗/poet.song.61000.json','["東風吹雪陰復晴，西日冉冉林間明。", "著水苔衣漸涵綠，向陽竹鞭初引萌。", "官糧得飽酒不足，春物有意人無情。", "馳書相謝五陵俠，汗板塵靴今半生。"]'),
('be5e409d-dd6e-44ff-8801-89212f195b5b','登快哉亭有屬','賀鑄','宋','宋诗','song-poetry','','[]','南浦東風拂水文，汀洲芳草綠羅裙。',64,'全唐诗/poet.song.61000.json','["南浦東風拂水文，汀洲芳草綠羅裙。", "桃花舊葉應相望，楊葉新聲我獨聞。", "酸鼻可憐香欲絕，斷腸不待酒初醺。", "斜陽歸去書窗下，一幅蠻箋賦夢雲。"]'),
('ee8e8bcc-1b0f-43eb-b7ed-5850baf2874c','和彭城王生悼歌人盼盼','賀鑄','宋','宋诗','song-poetry','','[]','東園花下記相逢，倩盼偷回一笑濃。',64,'全唐诗/poet.song.61000.json','["東園花下記相逢，倩盼偷回一笑濃。", "書簏尚緘香豆蔻，鏡奩初失玉芙蓉。", "歌闌燕子樓前月，魂斷鳳皇原上鐘。", "寄語虞卿謾多賦，九泉無路達魚封。"]'),
('bbd9c6d8-fa05-4e22-829c-adcd51b0755d','臨汴亭送客還馬上作','賀鑄','宋','宋诗','song-poetry','','[]','衮衮塵埃與願違，可堪持酒送將歸。',64,'全唐诗/poet.song.61000.json','["衮衮塵埃與願違，可堪持酒送將歸。", "壯心已服駑駘老，羈思常先鴻雁飛。", "十口無厭太倉粟，四鄰分采故山薇。", "何時偃卧柴桑里，自訟淵明昨日非。"]'),
('f5c97317-b278-4ac4-b888-0d43dc171aa3','送陳傳道攝雙溝戍商稅','賀鑄','宋','宋诗','song-poetry','','[]','牆外長川擁萬舟，門前山色入南州。',64,'全唐诗/poet.song.61000.json','["牆外長川擁萬舟，門前山色入南州。", "風來浦口客爭發，日下庭陰印未收。", "乍厭折腰從吏役，屢應回首念朋遊。", "病夫頗有東流興，預約清樽爲少留。"]'),
('df5c5a8e-829c-4943-baae-3d7b92678595','送彭城周主簿建中移黄縣令','賀鑄','宋','宋诗','song-poetry','','[]','客宦逢迎泗上州，酒籌詩卷慰淹留。',64,'全唐诗/poet.song.61000.json','["客宦逢迎泗上州，酒籌詩卷慰淹留。", "九層燈火偃王塔，四面溪山彭祖樓。", "此去君辭棲棘地，年來吾有負薪憂。", "終期一過河陽縣，相對春風話舊遊。"]'),
('9171002c-f732-4e3a-8897-2b8b732c6b27','寄題狄丘李偉官舍東齋','賀鑄','宋','宋诗','song-poetry','','[]','樹竹開窗小屋東，低簷却日竹通風。',64,'全唐诗/poet.song.61000.json','["樹竹開窗小屋東，低簷却日竹通風。", "長年馳騖欲何往，終日退藏於此中。", "未厭睡魔常有在，若思人事即無窮。", "躬耕不是悠悠計，來作蘇門鄰舍翁。"]'),
('64911ec8-1056-49b5-9bff-d20e602de5a3','病後登快哉亭','賀鑄','宋','宋诗','song-poetry','','[]','經雨清蟬得意鳴，征塵見處見歸程。',64,'全唐诗/poet.song.61000.json','["經雨清蟬得意鳴，征塵見處見歸程。", "病來把酒不知厭，夢後倚樓無限情。", "鴉带斜陽投古剎，草將野色入荒城。", "故園又負黄昏約，但覺秋風髮上生。"]'),
('0aebcbd5-6e39-4dfc-960c-408d05e99b63','送李宗古錄事謝病南歸','賀鑄','宋','宋诗','song-poetry','','[]','十旬病免謝雞羣，收得閑身付白雲。',64,'全唐诗/poet.song.61000.json','["十旬病免謝雞羣，收得閑身付白雲。", "南浦少留離別賦，北山相待敢移文。", "松舟桂楫曉將發，菰葉鱸魚秋未分。", "異日有懷長笑客，西飛燕子一相聞。"]'),
('1b563ca6-ca98-4789-b823-905823a58be2','汴上留別李智父','賀鑄','宋','宋诗','song-poetry','','[]','一馬西投汴水濱，自驚秋鬢带塵紛。',64,'全唐诗/poet.song.61000.json','["一馬西投汴水濱，自驚秋鬢带塵紛。", "秋風盡日吹黄葉，心事經年寄白雲。", "去矣尺書勤訪我，醉來樽酒强酬君。", "北窗絡緯寒聲急，明夜傷心獨自聞。"]'),
('4ddbcb09-bf2f-4de4-9360-302cd4d34041','答陳傳道','賀鑄','宋','宋诗','song-poetry','','[]','吾家季真登大蓬，我爲斗筲來寶豐。',64,'全唐诗/poet.song.61000.json','["吾家季真登大蓬，我爲斗筲來寶豐。", "公乎時以監呼我，自笑名同實不同。", "樽酒相望今夜月，鱸魚又負一秋風。", "少須婚嫁怱怱畢，會買扁舟下浙東。"]'),
('f1121850-f94a-4197-b4e8-dcf94cd0b6b2','懷寄寇元弼','賀鑄','宋','宋诗','song-poetry','','[]','君投筦庫可知非，我飽官糧又願違。',64,'全唐诗/poet.song.61000.json','["君投筦庫可知非，我飽官糧又願違。", "舊國秋高鴻雁過，長淮水落白魚肥。", "西風吹夢端相覓，南物留人也念歸。", "何日蘆軒下雙榻，滿持樽酒洗塵機。"]'),
('59f69971-763c-4b18-8c08-4d9174cc5da2','招寇元弼兼呈白雲莊張隠居','賀鑄','宋','宋诗','song-poetry','','[]','長鋏長鋏歸來乎，十口想厭淮南魚。',64,'全唐诗/poet.song.61000.json','["長鋏長鋏歸來乎，十口想厭淮南魚。", "遊宦非圖飽而已，浮生且問樂何如。", "定無佳客清樽酒，頼有古人黄卷書。", "我亦塵埃同病者，與君長愧白雲居。"]'),
('704f39cd-e913-4f4e-8455-67a588dce4eb','答王文舉','賀鑄','宋','宋诗','song-poetry','','[]','茫茫塵土欲安之，珍重吾人箇處期。',64,'全唐诗/poet.song.61000.json','["茫茫塵土欲安之，珍重吾人箇處期。", "綠野相隨一藜杖，青山正對兩茅茨。", "自憐悾惚負平昔，尚敢婆娑臨暮遲。", "第恐阿戎猶喜仕，它時不與五君詩。"]'),
('dea8d961-3f82-4dc9-9860-c497a768b1d8','題淵明軒','賀鑄','宋','宋诗','song-poetry','','[]','淵明新榜揭門眉，夫子高情俗不知。',64,'全唐诗/poet.song.61000.json','["淵明新榜揭門眉，夫子高情俗不知。", "未仰秫秔供歲計，本於松菊有心期。", "卧來不淺羲皇興，歸去何慙鄉里兒。", "窗破簷傾從此始，祇應風月解相思。"]'),
('36bddaf5-af90-4d3c-b333-022e872020d1','將發彭城作','賀鑄','宋','宋诗','song-poetry','','[]','四年吟笑老東徐，滿目溪山不負渠。',64,'全唐诗/poet.song.61000.json','["四年吟笑老東徐，滿目溪山不負渠。", "得米徑須償酒債，有田便擬卜吾廬。", "明朝門外扁舟雪，別夜燈前滿紙書。", "會問怱怱解携客，相思命駕定何如。"]'),
('af54bc8a-fa16-4eac-8866-02cf8f8e5b2e','留別張白雲謀父','賀鑄','宋','宋诗','song-poetry','','[]','三年官局冷如冰，炙手權門我未能。',64,'全唐诗/poet.song.61000.json','["三年官局冷如冰，炙手權門我未能。", "頼與白雲之隠者，不談黄卷即尋僧。", "蕭蕭簾箔風披竹，草草杯盤雪洒燈。", "塵土浮遊浸相遠，吳魚燕雁兩難憑。"]'),
('bbccde3e-ac10-4ea5-9659-7ea31926a662','留別寇定','賀鑄','宋','宋诗','song-poetry','','[]','不見步兵今一秋，年來復與仲容遊。',64,'全唐诗/poet.song.61000.json','["不見步兵今一秋，年來復與仲容遊。", "蒼顔白髮慙衰暮，縱飲狂歌作輩流。", "顧我宦情真漫浪，爲君行計幾淹留。", "能尋三月皇州約，拍手同登賣酒樓。"]'),
('6dbcced6-277e-49a4-8f82-1fae99230f48','永城邂逅周元通再索詩贈別','賀鑄','宋','宋诗','song-poetry','','[]','汎汎流萍滾滾蓬，偶然南北偶然逢。',64,'全唐诗/poet.song.61000.json','["汎汎流萍滾滾蓬，偶然南北偶然逢。", "一樽通濟橋邊酒，兩夜臨濉驛外鐘。", "行矣風波宜尚慎，歸哉塵土不相容。", "事功早立須知退，學稼它年訪老農。"]'),
('de25c6d0-4a5b-4b92-a11b-5eb48484b6bb','寄題泉南陳氏步雲亭','賀鑄','宋','宋诗','song-poetry','','[]','紫翠峰前水一灣，趣亭微徑白雲關。',64,'全唐诗/poet.song.61000.json','["紫翠峰前水一灣，趣亭微徑白雲關。", "漁樵不見携筇去，猿鶴相隨采藥還。", "晚月带潮來海上，春風吹雨到人間。", "恨君輕爲蒼生起，曾得東山幾日閑。"]'),
('8b69cf8c-57e1-4e7e-ba8a-a7f90ad12960','題永城縣園水亭','賀鑄','宋','宋诗','song-poetry','','[]','詰曲池塘碧玉流，禊亭孤占小汀洲。',64,'全唐诗/poet.song.61000.json','["詰曲池塘碧玉流，禊亭孤占小汀洲。", "長紉座上芳蘭佩，不繫簷前畫鷁舟。", "好泛羽觴脩舊事，爲書繭紙記清遊。", "季真待得東還日，初見紅蕖十畝秋。"]'),
('791b702b-7be2-422e-b38d-cf41b58606f2','同畢紹寓泊永城招李深昆仲','賀鑄','宋','宋诗','song-poetry','','[]','滿城楊柳正黄繁，幾處鞦韆出短垣。',64,'全唐诗/poet.song.61000.json','["滿城楊柳正黄繁，幾處鞦韆出短垣。", "經雨河流失清淺，带雲春色乍寒暄。", "從來嵇阮耽琴酒，況得機雲好弟昆。", "咫尺津亭望齋館，杖藜相過莫辭煩。"]'),
('9e95e057-a2a8-4a63-a861-766f1e03aae6','送畢彥祖先之京師','賀鑄','宋','宋诗','song-poetry','','[]','日日東風吹旱雲，弄鞭低帽送西曛。',64,'全唐诗/poet.song.61000.json','["日日東風吹旱雲，弄鞭低帽送西曛。", "客亭五里復十里，春物三分今二分。", "但解征衣平酒債，莫隨肥馬作塵紛。", "扁舟不及清明約，紫筍朱櫻未負君。"]'),
('3fad53cd-57f0-471b-8024-931a351fd5da','將發永城留題李氏齋壁','賀鑄','宋','宋诗','song-poetry','','[]','匹馬扁舟寄此身，可憐投老尚迷津。',64,'全唐诗/poet.song.61000.json','["匹馬扁舟寄此身，可憐投老尚迷津。", "黄塵是處隨遊子，明日相逢即故人。", "東道琴樽能惜夜，西園花絮欲傷春。", "分携後日匆匆去，燈火虹橋夢更頻。"]'),
('bbe1d327-1962-4ee8-bf4a-5931174e799a','京居春日遣懷','賀鑄','宋','宋诗','song-poetry','','[]','青梅小葉柳長條，相對春風各動搖。',64,'全唐诗/poet.song.61000.json','["青梅小葉柳長條，相對春風各動搖。", "物色依依如有待，人情忽忽自無聊。", "五陵劍俠知誰健，三徑車工不我招。", "好去廣津門下水，新秋穩送木蘭橈。"]'),
('eab4fba5-b267-4297-82b2-1adbac3ab097','送趙令畤之官陳州兼簡周文清','賀鑄','宋','宋诗','song-poetry','','[]','朱衣白面懿王孫，好去淮陽事相君。',64,'全唐诗/poet.song.61000.json','["朱衣白面懿王孫，好去淮陽事相君。", "已放扁舟下南浦，更持樽酒醉西曛。", "青雲計自此行始，明月惜從今夜分。", "擬仗短書裁不及，但傳窮達報知聞。"]'),
('e6a95276-4eaf-44cd-a509-3517216e86a2','汴上有懷李易初','賀鑄','宋','宋诗','song-poetry','','[]','何處經行特惘然，津頭曾送木蘭船。',64,'全唐诗/poet.song.61000.json','["何處經行特惘然，津頭曾送木蘭船。", "桃花春水生前夜，楊柳秋風憶故年。", "驛路尺書疑斷絕，官倉斗米愧留連。", "飄颻復作江湖計，從此長安是日邊。"]'),
('3c6e5aa1-4290-4220-92ff-c8d4bb612743','酬宗室令率惠墨','賀鑄','宋','宋诗','song-poetry','','[]','麝煤新劑黝而堅，誰謂奚生法不傳。',64,'全唐诗/poet.song.61000.json','["麝煤新劑黝而堅，誰謂奚生法不傳。", "信是文房希代寶，益知公子過人賢。", "蔡中郎老喜飛白，揚執戟窮耽草玄。", "雅意肯要瓊玖報，十丸聊以助吾顛。"]'),
('55b8d9bb-8fba-495c-bf49-0341b1f92638','陳留南城馬上簡李公年','賀鑄','宋','宋诗','song-poetry','','[]','南郭何人卜築幽，平田高樹带清溝。',64,'全唐诗/poet.song.61000.json','["南郭何人卜築幽，平田高樹带清溝。", "隔牆野鳥啼晴晝，駐馬行人照白頭。", "二頃難尋歸老計，一樽宜結探春遊。", "步兵不惜供厨費，更作東風數日留。"]'),
('b882e42e-b3fa-4bd5-9c71-c6e961b9ffe6','寓泊金陵尋王荆公陳迹','賀鑄','宋','宋诗','song-poetry','','[]','晚泊扁舟一問津，依然節物思羈人。',64,'全唐诗/poet.song.61000.json','["晚泊扁舟一問津，依然節物思羈人。", "江山月照六朝夢，桃李風吹三月春。", "宅枕謝公墩下路，詩尋蕭寺壁間塵。", "可須樽酒平生約，長望西州淚滿巾。"]'),
('c8ed4f4e-b655-47bf-b52d-41e8a63ae4ff','答孫休兼簡清凉和上人二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','聲迹相聞忽此逢，杖藜蕭散一相從。',64,'全唐诗/poet.song.61000.json','["聲迹相聞忽此逢，杖藜蕭散一相從。", "平生詩酒真吾事，何處江山不爾容。", "芳草自生南北路，孤雲難繫往來蹤。", "異時荒戍長回首，風送石城樓上鐘。"]'),
('e92fb662-af32-4886-9675-37c1681fa243','答孫休兼簡清凉和上人二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','渭北人遊楚水東，論詩說舊偶從容。',64,'全唐诗/poet.song.61000.json','["渭北人遊楚水東，論詩說舊偶從容。", "鄉關此日幾多遠，春酒與愁相勝濃。", "且免牛衣愧妻子，莫將羊酪詫吾儂。", "哀王孫頼彌天釋，肯學揚州飯後鐘。"]'),
('9ffd449b-c41d-4166-9eed-2657827b9d95','春懷有寄代同行作','賀鑄','宋','宋诗','song-poetry','','[]','未應一笑爲千金，且解樽前綠綺琴。',64,'全唐诗/poet.song.61000.json','["未應一笑爲千金，且解樽前綠綺琴。", "歸雁不將書北去，行雲長伴日西沉。", "楚蘭徑遠飛黄蝶，湘水簾空對綠陰。", "無復賞心酬節物，斷腸翻詠白頭吟。"]'),
('624beb2b-e4c6-465c-8e6f-99b0e4d90a4b','送潘景仁之官嶺外兼寄桂林從叔','賀鑄','宋','宋诗','song-poetry','','[]','夜銜舟尾晝聯檣，齊發都門到楚鄉。',64,'全唐诗/poet.song.61000.json','["夜銜舟尾晝聯檣，齊發都門到楚鄉。", "我欲塵埃投衮衮，君方湖海去茫茫。", "傷心客路逢寒食，回首家園但夕陽。", "想見步兵應訪問，仲容無復竹林狂。"]'),
('b6536169-23b1-45ab-8be4-8a6aa28498d1','同王克慎宿清凉寺兼示和上人孫安之','賀鑄','宋','宋诗','song-poetry','','[]','六代風流不可尋，石頭勝槩古猶今。',64,'全唐诗/poet.song.61000.json','["六代風流不可尋，石頭勝槩古猶今。", "疏鐘答響江山迥，啼鳥忘形松竹深。", "借問白雲誰卜築，擬要明月共登臨。", "終投逸少興公社，蔬粥麻衣事道林。"]'),
('7b961366-cc3c-48f9-8590-15e7ae04da03','答王拙見寄','賀鑄','宋','宋诗','song-poetry','','[]','好在金陵王隠君，尺書忽與我相聞。',64,'全唐诗/poet.song.61000.json','["好在金陵王隠君，尺書忽與我相聞。", "蓴鱸久負秋風約，猿鶴終尋舊日羣。", "橫笛卧吹南浦月，杖藜笑度北山雲。", "六朝陳迹何須問，一曲滄浪酒十分。"]'),
('5144414b-0c41-46d5-8e3c-918dbdc1d7bd','寄別僧芝','賀鑄','宋','宋诗','song-poetry','','[]','不見江南湯惠休，芝錢今也嗣風流。',64,'全唐诗/poet.song.61000.json','["不見江南湯惠休，芝錢今也嗣風流。", "燒香弄筆一生事，躡屐佩囊千里遊。", "乞酒未還黄菊晚，擬詩初就碧雲秋。", "臨高跂馬君行矣，從此安期始欲愁。"]'),
('cba4b426-9846-4a32-83a9-eddfc6ba1035','度黄葉嶺懷寄清凉白雲菴主','賀鑄','宋','宋诗','song-poetry','','[]','黄葉嶺頭黄葉飛，白雲菴畔白雲歸。',64,'全唐诗/poet.song.61000.json','["黄葉嶺頭黄葉飛，白雲菴畔白雲歸。", "葉隨遊子終相失，雲伴禪翁得所依。", "會解腰間斬馬劍，肯尋江上釣魚磯。", "焚香掃地雙林下，願贖今生種種非。"]'),
('d9c2caac-76fa-4a30-bd23-07578059a322','與張歷陽追懷從禽之樂因賦','賀鑄','宋','宋诗','song-poetry','','[]','宜秋門外養鷹坊，好草陂頭射雉場。',64,'全唐诗/poet.song.61000.json','["宜秋門外養鷹坊，好草陂頭射雉場。", "油幕氈廬張野飲，錦袍貂帽結戎裝。", "興闌落日黄塵斷，夢後西風白髮長。", "誰念江湖獨流寓，此情難話與漁郎。"]'),
('0626b4ff-3a70-482f-8f0a-01baf4395f32','歷陽姥磯下馬上有懷京都遊好','賀鑄','宋','宋诗','song-poetry','','[]','楚澤初冬正穫田，孤鴻欲下却翻然。',64,'全唐诗/poet.song.61000.json','["楚澤初冬正穫田，孤鴻欲下却翻然。", "人烟隠約青山郭，雲物離披小雪天。", "送別盃盤猶昨日，勞生鞍馬遂窮年。", "故人多在金閨籍，誰念心寸如斷絃。"]'),
('4abf1d2f-28d9-4f76-b35d-204cde28fbb6','烏江石跂觜晚望有懷','賀鑄','宋','宋诗','song-poetry','','[]','山色相銜類太行，江流東去亦渾黄。',64,'全唐诗/poet.song.61000.json','["山色相銜類太行，江流東去亦渾黄。", "鱸魚鱠美招來客，鴻雁書遲夢故鄉。", "五斗月支何足道，一帆風便可能忘。", "歸田有計非今日，莫把移文揭草堂。"]'),
('2ef4d8ae-b781-4d10-9f6c-1a21b216676d','登烏江寶泉寺南山望金陵作','賀鑄','宋','宋诗','song-poetry','','[]','我愛金陵望不厭，獨尋微逕躡晴嵐。',64,'全唐诗/poet.song.61000.json','["我愛金陵望不厭，獨尋微逕躡晴嵐。", "柔桑淺草三月尾，踴塔飛樓一水南。", "苒苒流雲牽仿像，遲遲艷日助醺酣。", "何須拊手歌桃葉，已覺王郎思不堪。"]'),
('8bb3d2a9-7ff6-4e01-a7e9-04eb81316af1','烏江東鄉往還馬上作二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','黄塵隨馬染征衣，十里江皋送客暉。',64,'全唐诗/poet.song.61000.json','["黄塵隨馬染征衣，十里江皋送客暉。", "廢井草荒蛙黽怒，下田沙漲芋魁肥。", "解纓拂樹弄清淺，橫榻掃雲飛翠微。", "人生事事不如意，終日念歸何日歸。"]'),
('067c22b6-6928-4626-a0f6-623410d46435','烏江東鄉往還馬上作二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','悠悠東去欲何之，草草西還可是歸。',64,'全唐诗/poet.song.61000.json','["悠悠東去欲何之，草草西還可是歸。", "殘日兩竿荒戍遠，青山滿眼故園非。", "江田經雨菰蔣熟，石路無風蠛蠓飛。", "回羨耕夫閑勝我，早收雞犬閉柴扉。"]'),
('c66b8ecd-0269-4a48-b115-92c715313ecf','送歷陽潘司戶瑶移令歸東魯','賀鑄','宋','宋诗','song-poetry','','[]','衰俗紛紛務近功，幾人心跡與君同。',64,'全唐诗/poet.song.61000.json','["衰俗紛紛務近功，幾人心跡與君同。", "低回州縣青衫列，踴躍聖賢黄卷中。", "牛渚江山空夜月，河陽桃李再春風。", "相望魯衛無多遠，異日能尋賣藥翁。"]'),
('f0234632-d81a-4867-ad72-c09a27362a81','再送潘仲寶兼寄彭城交舊','賀鑄','宋','宋诗','song-poetry','','[]','風雨扁舟幸少留，爲君持酒話徐州。',64,'全唐诗/poet.song.61000.json','["風雨扁舟幸少留，爲君持酒話徐州。", "白魚紫蟹秋初美，戲馬飛鴻夢屢遊。", "二阮年來知健否，季真老去盡歸休。", "白雲莊畔多閑地，不惜橫刀直換牛。"]'),
('af3ff698-bff7-4353-a56d-bfc7c9ae8cb2','九日懷京都舊遊','賀鑄','宋','宋诗','song-poetry','','[]','昔年九日登臨處，把酒梁王舊吹臺。',64,'全唐诗/poet.song.61000.json','["昔年九日登臨處，把酒梁王舊吹臺。", "今年九日登臨處，江上黄華殊未開。", "一川落日隨朝下，萬里西風送雁來。", "節物可驚人更老，宦情歸計兩悠哉。"]'),
('49bb98ba-6912-4999-8f5a-157c0956939e','戲答張商老','賀鑄','宋','宋诗','song-poetry','','[]','揚子江頭兩信潮，送君西去木蘭橈。',64,'全唐诗/poet.song.61000.json','["揚子江頭兩信潮，送君西去木蘭橈。", "依依暮雨鴛鴦夢，嫋嫋春風豆蔻梢。", "細字碧箋隨雁到，小簾朱戶抵天遥。", "長安觸緒牽情地，不特魂銷骨亦銷。"]'),
('38c69527-1eb9-4868-b4f8-a8248c8110f4','題定山寺法遠上人壁','賀鑄','宋','宋诗','song-poetry','','[]','支郎風味喜相親，乘興來尋雪後春。',64,'全唐诗/poet.song.61000.json','["支郎風味喜相親，乘興來尋雪後春。", "夾徑竹陰疑礙馬，隔江山色似招人。", "豈無暇日容高卧，如有閑田願卜鄰。", "預約東城二三子，歲時相過莫辭頻。"]'),
('d7601dfc-dc7f-4ab5-85f3-de52ffb99de0','自歷陽汎江至赤埭訪別曹解','賀鑄','宋','宋诗','song-poetry','','[]','我訪故人不待招，滄江謂廣纔容舠。',64,'全唐诗/poet.song.61000.json','["我訪故人不待招，滄江謂廣纔容舠。", "離城五點寒更急，著岸兩竿晴日高。", "別來書尺正坐嬾，老去鞍馬何堪勞。", "明年淮上更携手，醉步卧虹千丈橋。"]'),
('92bc2cc4-68d2-485d-873b-f249fac6e790','再由赤埭有懷曹夢得','賀鑄','宋','宋诗','song-poetry','','[]','江上顛風倒客檣，江豚舞浪卷渾黄。',64,'全唐诗/poet.song.61000.json','["江上顛風倒客檣，江豚舞浪卷渾黄。", "故人漂泊知何處，何日平安到故鄉。", "野色蒼茫春尚淺，夢魂惝怳夜仍長。", "可無百斛兵厨醖，此段離憂未易忘。"]'),
('3817a5f7-f371-494f-aa86-b5da4a3b30d4','宿芥塘佛祠','賀鑄','宋','宋诗','song-poetry','','[]','青青麰麥欲抽芒，浩蕩東風晚更狂。',64,'全唐诗/poet.song.61000.json','["青青麰麥欲抽芒，浩蕩東風晚更狂。", "微徑斷橋尋古寺，短籬高樹隔橫塘。", "開門未掃楊花雨，待曉先燒柏子香。", "底許暫忘行役倦，故人題字滿長廊。"]'),
('2e420829-2869-42e8-9b4b-e6add3182972','送畢平仲西上','賀鑄','宋','宋诗','song-poetry','','[]','吟鞭西指鳳皇州，好趁華年訪昔遊。',64,'全唐诗/poet.song.61000.json','["吟鞭西指鳳皇州，好趁華年訪昔遊。", "新樣春衫裁白苧，舊題醉墨滿青樓。", "鳴蛙雨細生梅潤，颺燕風高報麥秋。", "須念江邊桃葉女，定從今日望歸舟。"]'),
('70973871-b515-41b3-83b9-21a43e0e6e3a','烏江廣聖寺虛樂亭','賀鑄','宋','宋诗','song-poetry','','[]','避雨孤篷泊柳陰，潮回溪曲稻花深。',64,'全唐诗/poet.song.61000.json','["避雨孤篷泊柳陰，潮回溪曲稻花深。", "有時白鷺窺魚下，竟日青蛙伴我吟。", "酒敵無人情落漠，雲鄉何處老侵尋。", "誅茅擬卜終焉計，不爲清風暫解襟。"]'),
('60c8756b-541d-42ae-805f-c04a07e009e2','烏江北道中作','賀鑄','宋','宋诗','song-poetry','','[]','寒麥田疇雪糝花，暮潮洲渚水吞沙。',64,'全唐诗/poet.song.61000.json','["寒麥田疇雪糝花，暮潮洲渚水吞沙。", "鳧鷖長作漁舟伴，桑柘深藏老圃家。", "濁酒縱賢誰與醉，青山有價不容賒。", "南來學得滄浪唱，却著征衫袖馬撾。"]'),
('cb7cc225-c50e-4745-9014-b9c74bff679e','烏江泛舟寓目','賀鑄','宋','宋诗','song-poetry','','[]','滄江浩渺寄星槎，望極紛紛兩眼花。',64,'全唐诗/poet.song.61000.json','["滄江浩渺寄星槎，望極紛紛兩眼花。", "但見潮頭澍木杪，直疑山背落天涯。", "鴟夷信得平生樂，仲御尤宜抵死誇。", "傖父慙非能賦手，漁郎若箇是詩家。"]'),
('bbd501f7-cfd0-411e-9bb6-d6dde7984434','遷家歷陽江行夜泊黄泥潭懷寄馮善淵','賀鑄','宋','宋诗','song-poetry','','[]','黄泥潭口檥征篷，回指東城祗眼中。',64,'全唐诗/poet.song.61000.json','["黄泥潭口檥征篷，回指東城祗眼中。", "半夜鳧鷖先覺雨，連江葭菼自生風。", "青燈解作無眠伴，白酒難招一醉同。", "從此相思寖相遠，便憑歸櫂附詩筒。"]'),
('d00586fd-aed5-45c0-a15a-ddb519ba1b98','檥舟當利港作','賀鑄','宋','宋诗','song-poetry','','[]','爲問溪頭潮淺深，片帆長掛北歸心。',64,'全唐诗/poet.song.61000.json','["爲問溪頭潮淺深，片帆長掛北歸心。", "夜風吹雪曉尤怒，午日破雲寒復陰。", "江淮行役殊未已，京洛朋遊安事尋。", "何時穩坐飽麤飯，鼓腹東皋農父吟。"]'),
('98db3763-4eec-4c7b-ad2c-a6fb585fe1ae','放舟下江留寄王元胥','賀鑄','宋','宋诗','song-poetry','','[]','檜檝淹留已涉旬，小窗猶得酒相親。',64,'全唐诗/poet.song.61000.json','["檜檝淹留已涉旬，小窗猶得酒相親。", "寒潮不應溪流澀，病客未行舟子嗔。", "揮手便分今夜月，斷腸先見隔江春。", "鳳皇臺上長回首，何處高城與故人。"]'),
('1f8360ae-22b4-4d96-bc20-087fe77579ee','興龍節日渡江懷寄二友弟兼示同行','賀鑄','宋','宋诗','song-poetry','','[]','燕庭冠珮拜爐香，丸劍紛紛想定場。',64,'全唐诗/poet.song.61000.json','["燕庭冠珮拜爐香，丸劍紛紛想定場。", "江上烹魚猶得信，座中驚雁已離行。", "澆愁酩酊一樽酒，破睡咿啞兩艣牀。", "不特賦詩懷二仲，故呈凡韵惱支郎。"]'),
('65008d35-0a56-4678-85fd-ead76282f700','訪金陵王閑叟不遇留別','賀鑄','宋','宋诗','song-poetry','','[]','歌成五噫賃舂者，藥不二價奪牛翁。',64,'全唐诗/poet.song.61000.json','["歌成五噫賃舂者，藥不二價奪牛翁。", "衰俗何知貴公子，清貧頗有昔人風。", "君方上冢渡沔去，我適乘舟投剡中。", "差池相失重回首，好住海鷗忘塞鴻。"]'),
('ebda89dd-1949-4cb3-b12d-b4f39462945d','題金陵長干寺塔','賀鑄','宋','宋诗','song-poetry','','[]','南國長干古佛祠，浮圖鴛瓦碧參差。',64,'全唐诗/poet.song.61000.json','["南國長干古佛祠，浮圖鴛瓦碧參差。", "欲追三閣登高作，非復六朝全盛時。", "簷角西風掛星斗，牆陰寒雨嘯狐狸。", "劫灰終換人間世，石甃金棺好護持。"]'),
('2cdac1a6-d647-486e-99a6-5a67d49c0721','題金陵天慶觀鍾阜軒','賀鑄','宋','宋诗','song-poetry','','[]','霞構雲扉不著關，甍簷開處見人間。',64,'全唐诗/poet.song.61000.json','["霞構雲扉不著關，甍簷開處見人間。", "斷牆廢井連東第，白塔青松對北山。", "昨夜桂娥奔月去，經秋芝蓋御風還。", "玉虛真籍家聲在，再熟金桃願一攀。"]'),
('70527210-8963-4b59-9bdd-6aae0e6789c0','再酬訥師兼簡清凉和上人','賀鑄','宋','宋诗','song-poetry','','[]','莫謂功名是可希，定知求法不求衣。',64,'全唐诗/poet.song.61000.json','["莫謂功名是可希，定知求法不求衣。", "此身於世百無用，異日與君同所歸。", "遮眼何關黄卷在，安心更悟白牛非。", "清凉有道平如掌，豈比他方大鐵圍。"]'),
('5523c38a-d8a4-45cd-8228-8a9ad32eb225','阻風白鷺洲招訥上人','賀鑄','宋','宋诗','song-poetry','','[]','鳳皇臺下鳳皇巢，白鷺洲邊白鷺濤。',64,'全唐诗/poet.song.61000.json','["鳳皇臺下鳳皇巢，白鷺洲邊白鷺濤。", "舟未解維先望見，風能傳語更相招。", "江南春物爲誰好，淇上歸心不自聊。", "何日結茅鍾阜尾，幅巾相對一方袍。"]'),
('e6506faa-371e-4e23-bad4-a17c25a6aee7','晚泊長蘆有懷歷陽金陵朋好','賀鑄','宋','宋诗','song-poetry','','[]','犀照亭邊兩艣催，鳳栖臺下片帆開。',64,'全唐诗/poet.song.61000.json','["犀照亭邊兩艣催，鳳栖臺下片帆開。", "龍盤虎踞行遠矣，牛渚雞籠安在哉。", "無端鞍馬三年役，有意蓴鱸異日來。", "樽酒故人誰待我，故應風月尚徘徊。"]'),
('b54c73df-e1a6-4e91-9605-0f61dba41f2e','上巳晚泊龜山作','賀鑄','宋','宋诗','song-poetry','','[]','薄暮東風不滿帆，遲遲未忍去淮南。',64,'全唐诗/poet.song.61000.json','["薄暮東風不滿帆，遲遲未忍去淮南。", "故園猶在北山北，佳節可憐三月三。", "蘭葉自供遊女佩，芸編聊對故人談。", "洛橋車騎相望客，曾爲吳兒幾許慙。"]'),
('e8518046-a49b-47f1-bc13-366580a256ab','揚州敘遊','賀鑄','宋','宋诗','song-poetry','','[]','迷藏九曲屬樵耕，野草閑花故有情。',64,'全唐诗/poet.song.61000.json','["迷藏九曲屬樵耕，野草閑花故有情。", "廢苑春風遽如許，隔江山色可憐生。", "新聲度曲復誰道，古井酌泉聊獨清。", "杜紫微靈定相笑，青樓薄倖不知名。"]'),
('9d71ddd9-2805-456c-b4ad-97ccc27f83f7','和錢德循書懷','賀鑄','宋','宋诗','song-poetry','','[]','咄嗟世與我相疏，歲月推排負壯圖。',64,'全唐诗/poet.song.61000.json','["咄嗟世與我相疏，歲月推排負壯圖。", "狂客大難兼外監，方回小得勝常奴。", "胸中累塊亦何有，鬲上督郵非所須。", "徑買一舟歸自好，五雲溪接當家湖。"]'),
('55bdbc6e-c777-4161-ada0-a2b1cc335fd5','席上呈錢德循','賀鑄','宋','宋诗','song-poetry','','[]','棗華纂纂桑葉肥，老蠶起眠雛雀飛。',64,'全唐诗/poet.song.61000.json','["棗華纂纂桑葉肥，老蠶起眠雛雀飛。", "南鄰買酒勸行樂，越客廢書歌式微。", "式微式微胡不歸，明日會知今日非。", "舊溪手種水楊柳，長與秋風掃釣磯。"]'),
('36d99130-888a-4ae2-ab9e-ad50ea1043bd','壬申上元有懷金陵舊遊','賀鑄','宋','宋诗','song-poetry','','[]','瓦官大庭千步方，燈如流螢月如霜。',64,'全唐诗/poet.song.61000.json','["瓦官大庭千步方，燈如流螢月如霜。", "高僧共禮旃檀像，遊女來焚薰陸香。", "舊國破亡何物在，少年逐樂箇儂狂。", "別來白社更牢落，回首衡湘春夢長。"]'),
('6d0a3a42-bf93-4f3f-b176-c374e7dfa737','送周元通昆仲官蜀','賀鑄','宋','宋诗','song-poetry','','[]','周郎弟兄皆可人，外朗內潤連城珍。',64,'全唐诗/poet.song.61000.json','["周郎弟兄皆可人，外朗內潤連城珍。", "樽酒逢迎記梁宋，聯驂行邁度咸秦。", "寶雞道上冰雪晚，金雁江邊梅柳春。", "公暇樂遊須念我，青衫白髮倦京塵。"]'),
('f09b26a7-9670-4e3b-a9d1-82a781c6a6c0','夢遊金陵設堂故基','賀鑄','宋','宋诗','song-poetry','','[]','燕堂遺址壓西州，剪徑捫蘿出石頭。',64,'全唐诗/poet.song.61000.json','["燕堂遺址壓西州，剪徑捫蘿出石頭。", "老木駸駸太相逼，連岡衮衮欲東流。", "歌鐘誰話前朝事，風雨魂驚別夜遊。", "夢境浮生更多病，結茅歸老信悠悠。"]'),
('16e195b8-0511-4e05-a2de-33d24ecd97cc','寄清凉和上人二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','吾家無擔石之儲，朝四暮三如有餘。',64,'全唐诗/poet.song.61000.json','["吾家無擔石之儲，朝四暮三如有餘。", "北岳官糧飽妻子，南朝僧寺寓圖書。", "迎船春色情親我，坌馬京塵笑謝渠。", "莫作江東步兵待，翻然端不爲鱸魚。"]'),
('4a0c52b6-50de-4769-917a-1b91fd53f61f','寄清凉和上人二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','南國風流百不存，石頭今是給孤園。',64,'全唐诗/poet.song.61000.json','["南國風流百不存，石頭今是給孤園。", "山連雉堞猶侵路，潮送漁舟自到門。", "方丈定容居士病，貝多應待客兒翻。", "懸知後日逢迎際，桃李春風兩不言。"]'),
('e90c3dc4-c608-4c86-a71a-87384ceed237','寄李趙二友生','賀鑄','宋','宋诗','song-poetry','','[]','東風掠地百草青，顛毛餘幾今星星。',64,'全唐诗/poet.song.61000.json','["東風掠地百草青，顛毛餘幾今星星。", "長年嬰疾斷還往，無處避愁徒醉醒。", "聯馬尋芳狹斜道，銜舟待月滄浪亭。", "遥輸此興二公子，漲海未應沈一萍。"]'),
('67efb741-a792-48fe-991f-976fadfd7bc5','呈李之儀','賀鑄','宋','宋诗','song-poetry','','[]','淹卧疲筋快曉晴，屋頭相報鵓鴣鳴。',64,'全唐诗/poet.song.61000.json','["淹卧疲筋快曉晴，屋頭相報鵓鴣鳴。", "病侵老境可憐許，春入故園何似生。", "坐想蘭亭通曲水，行聞上巳接清明。", "明年强健陪嘉集，定奪三觥賦不成。"]'),
('10fed624-ad5b-449d-9a39-1e8d9b8d0812','贈張之才','賀鑄','宋','宋诗','song-poetry','','[]','夙齡垂耳慕飛黄，晚歲相逢兩漫郎。',64,'全唐诗/poet.song.61000.json','["夙齡垂耳慕飛黄，晚歲相逢兩漫郎。", "浼我青衫奈塵土，誤君白首坐文章。", "折腰僅厭米五斗，滿腹莫驕錢一囊。", "多病勞生餘有幾，買山築室願鄰牆。"]'),
('e6c18504-f528-49c8-b751-99bd26049c58','載病東歸山陰酬別京都交舊','賀鑄','宋','宋诗','song-poetry','','[]','我家湖水接山溪，載病東歸路不迷。',64,'全唐诗/poet.song.61000.json','["我家湖水接山溪，載病東歸路不迷。", "城郭依然遼海鶴，鵷鴻邈矣會稽雞。", "可須印綬懷中出，幸有珠璣袖裏携。", "行賦漁歌寄親串，春風吹渡浙江西。"]'),
('1b4ea098-6071-42d3-90b9-bf5d30bee6d6','舟次淮陰呈邑令田望','賀鑄','宋','宋诗','song-poetry','','[]','狂吟醉約昔悠悠，衰病方諧散浪遊。',64,'全唐诗/poet.song.61000.json','["狂吟醉約昔悠悠，衰病方諧散浪遊。", "蔬粥滿杯供我飽，蘭舟繫岸判君留。", "塵埃古剎尋遺篆，香火嚴祠謁故侯。", "晚具不須烹赤鯉，聊憑別後作書郵。"]'),
('9dc45616-32c9-4396-b4ad-118539316a00','高郵舟居對雪','賀鑄','宋','宋诗','song-poetry','','[]','天涯晚歲客無歡，擁鼻微吟行路難。',64,'全唐诗/poet.song.61000.json','["天涯晚歲客無歡，擁鼻微吟行路難。", "三楚浮程波淼淼，五陵歸夢雪漫漫。", "兔園授簡心猶壯，剡曲拏舟興久闌。", "病骨支離仍禁酒，漁蓑重緝待春寒。"]'),
('649c15f1-dded-44f2-9eb8-1807aad9929f','留別王景通二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','早年放樂五雲鄉，遠笑垣東俠少場。',64,'全唐诗/poet.song.61000.json','["早年放樂五雲鄉，遠笑垣東俠少場。", "憲也但貧猶未病，公乎非酒自能狂。", "塵埃輦路春遊散，燈火僧窗夜話長。", "後日相思枉緘幅，茱萸灣北付漁郎。"]'),
('3bd09168-500c-42e3-b091-aeb3c8f44c37','留別王景通二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','遊宦差池太半生，君方倥傯我伶俜。',64,'全唐诗/poet.song.61000.json','["遊宦差池太半生，君方倥傯我伶俜。", "官銜轉落百僚底，衫色渾偷兩鬢青。", "張掾官曹拋勝日，向平家事汩餘齡。", "相逢一段孟城夢，明發扁舟是浪萍。"]'),
('7f97a6ad-9a12-4caf-8691-0460555ca8f4','舟次廣陵懷寄京都交舊','賀鑄','宋','宋诗','song-poetry','','[]','朋遊冠蓋滿京華，病客東流迹自賒。',64,'全唐诗/poet.song.61000.json','["朋遊冠蓋滿京華，病客東流迹自賒。", "音驛未聞來日下，鄰牆不見亦天涯。", "尚慙斗粟煩官廩，已指扁舟是我家。", "莫謂因風無可寄，雪梅開徧臘前花。"]'),
('8c2245f0-6060-4177-be2c-085aa36f5bb0','廣陵茱萸灣晚泊','賀鑄','宋','宋诗','song-poetry','','[]','冷雲拋雪未成花，過埭東風凍著沙。',64,'全唐诗/poet.song.61000.json','["冷雲拋雪未成花，過埭東風凍著沙。", "荻浦漁歸初下雁，楓橋市散祗啼鴉。", "舊聞南國饒春事，行見東風換物華。", "老病心情亦何有，藥囊詩卷是生涯。"]'),
('446478fd-cd32-4f98-9e20-2f97d3309d73','題杜仲觀南康遺編後','賀鑄','宋','宋诗','song-poetry','','[]','高吟晚節動江關，自況孤雲豈易攀。',64,'全唐诗/poet.song.61000.json','["高吟晚節動江關，自況孤雲豈易攀。", "賦鵩一篇傳日下，騎鯨半夜去人間。", "知音誰復稱流水，招隠吾方擬小山。", "固有清風千古在，不應空伴月明閑。"]'),
('49e756e1-acc7-46ea-86e4-7c1353afcf76','感興六首  其一','賀鑄','宋','宋诗','song-poetry','','[]','雛雀學翻飛，不知毛羽微。',24,'全唐诗/poet.song.61000.json','["雛雀學翻飛，不知毛羽微。", "青鵳笑高樹，待爾飽朝饑。"]'),
('40324925-ea31-4e47-858a-049bd45a3482','感興六首  其二','賀鑄','宋','宋诗','song-poetry','','[]','青鵳噉雀雛，飫飽侮鳶烏。',24,'全唐诗/poet.song.61000.json','["青鵳噉雀雛，飫飽侮鳶烏。", "不知皂鵰力，拏殺北城狐。"]'),
('cad865b4-d211-4c44-abda-726071ba719a','感興六首  其三','賀鑄','宋','宋诗','song-poetry','','[]','皂鵰獰觜爪，飛走披肝腦。',24,'全唐诗/poet.song.61000.json','["皂鵰獰觜爪，飛走披肝腦。", "不知遊獵兒，必爾韝上老。"]'),
('3b9760b6-555f-41a9-b8a5-27a3bde477eb','感興六首  其四','賀鑄','宋','宋诗','song-poetry','','[]','獵兒燕楚俗，得意唯馳逐。',24,'全唐诗/poet.song.61000.json','["獵兒燕楚俗，得意唯馳逐。", "不知廟堂上，坐飽萬錢肉。"]'),
('46941149-8397-4be7-a024-ef3a953ee3f7','感興六首  其五','賀鑄','宋','宋诗','song-poetry','','[]','廟堂擊鮮食，日負天下責。',24,'全唐诗/poet.song.61000.json','["廟堂擊鮮食，日負天下責。", "不知五湖上，自有扁舟客。"]'),
('9c013b29-37f7-4be3-9441-1e148498c99a','感興六首  其六','賀鑄','宋','宋诗','song-poetry','','[]','扁舟彼何人，國霸始謀身。',24,'全唐诗/poet.song.61000.json','["扁舟彼何人，國霸始謀身。", "不知釣魚翁，羞作故人臣。"]'),
('1ad627eb-454f-41e2-8be2-f84d66da87c3','懷寄寇元弼王文舉十首 初別後','賀鑄','宋','宋诗','song-poetry','','[]','樽酒津亭別，還城何所投。',24,'全唐诗/poet.song.61000.json','["樽酒津亭別，還城何所投。", "無情是流水，斷送到南州。"]'),
('bca717ff-f032-4f14-af78-aa8a10cd5347','懷寄寇元弼王文舉十首 過碧蘆軒','賀鑄','宋','宋诗','song-poetry','','[]','東軒美風月，詩酒伴歡呼。',24,'全唐诗/poet.song.61000.json','["東軒美風月，詩酒伴歡呼。", "昨日牆陰過，依依見碧蘆。"]'),
('c5667d3b-2bb9-42a1-9a9b-920500786e28','懷寄寇元弼王文舉十首 出小市門','賀鑄','宋','宋诗','song-poetry','','[]','小市門南路，舊遊聯馬行。',24,'全唐诗/poet.song.61000.json','["小市門南路，舊遊聯馬行。", "祇從前日別，秋草一番生。"]'),
('f5de9da3-6c21-4b12-8ef3-e7a4b6a236f9','懷寄寇元弼王文舉十首 登飛鴻亭','賀鑄','宋','宋诗','song-poetry','','[]','南京一登眺，朔雁正來賓。',24,'全唐诗/poet.song.61000.json','["南京一登眺，朔雁正來賓。", "好去長淮北，殷勤訪故人。"]'),
('7c84b4e5-3306-436f-99e8-fbfa175ec0a9','懷寄寇元弼王文舉十首 遊百步洪','賀鑄','宋','宋诗','song-poetry','','[]','百步洪頭水，秋霖一夜渾。',24,'全唐诗/poet.song.61000.json','["百步洪頭水，秋霖一夜渾。", "相携濯纓處，無復履綦痕。"]'),
('699411ec-1683-4b07-8b8e-548369c0a71c','懷寄寇元弼王文舉十首 登黄樓','賀鑄','宋','宋诗','song-poetry','','[]','何處延明月，東城百尺樓。',24,'全唐诗/poet.song.61000.json','["何處延明月，東城百尺樓。", "故人那得見，後夜是中秋。"]'),
('c79482e7-f2c5-48cb-89c1-4be2c82266a7','懷寄寇元弼王文舉十首 局中歸','賀鑄','宋','宋诗','song-poetry','','[]','不見西街客，歸來即閉門。',24,'全唐诗/poet.song.61000.json','["不見西街客，歸來即閉門。", "胡牀面南樹，鳥鵲啅黄昏。"]'),
('dadb89d3-734d-4e5d-8fa8-7be922fdc666','懷寄寇元弼王文舉十首 招元弼','賀鑄','宋','宋诗','song-poetry','','[]','暑雨茅柴熟，秋風淮白肥。',24,'全唐诗/poet.song.61000.json','["暑雨茅柴熟，秋風淮白肥。", "留連阮校尉，何日跨馿歸。"]'),
('3a4a9bcf-aa63-4f75-b185-d084d27e5b18','懷寄寇元弼王文舉十首 招文舉','賀鑄','宋','宋诗','song-poetry','','[]','後夜溪山雪，臨門望子猷。',24,'全唐诗/poet.song.61000.json','["後夜溪山雪，臨門望子猷。", "莫因清興盡，半道却回舟。"]'),
('5a626f8c-df00-439f-96d6-7123b0088112','懷寄寇元弼王文舉十首 賦後詩','賀鑄','宋','宋诗','song-poetry','','[]','偶得悲秋句，還驚舊社空。',24,'全唐诗/poet.song.61000.json','["偶得悲秋句，還驚舊社空。", "中庭步明月，朗詠與西風。"]'),
('57f93b28-ddfd-4d4d-8394-139e39c69ca2','馬上重經舊遊六言','賀鑄','宋','宋诗','song-poetry','','[]','淺淺東流宛溪，當年罷酒分携。',28,'全唐诗/poet.song.61000.json','["淺淺東流宛溪，當年罷酒分携。", "認得橋邊楊柳，春風幾度鴉啼。"]'),
('6b258ce3-2a95-4e89-913c-fd3455ea7309','題惠崇畫扇六言二首 梅花雪雀','賀鑄','宋','宋诗','song-poetry','','[]','春雪霏霏晚梅，抱枝寒雀毰毸。',28,'全唐诗/poet.song.61000.json','["春雪霏霏晚梅，抱枝寒雀毰毸。", "隴下有人腸斷，爲銜芳信東來。"]'),
('3eea1ef7-f8f1-4dd6-9a6d-7301cd54ca14','題惠崇畫扇六言二首 秋水蘆雁','賀鑄','宋','宋诗','song-poetry','','[]','塞南秋水陂塘，蘆葉蕭蕭半黄。',28,'全唐诗/poet.song.61000.json','["塞南秋水陂塘，蘆葉蕭蕭半黄。", "直北飛來鴻雁，端疑個是瀟湘。"]'),
('44887d1c-6201-4407-bc53-1f2ee8c87f65','答陳傳道五首  其一','賀鑄','宋','宋诗','song-poetry','','[]','客子厭京塵，長街風瞇目。',24,'全唐诗/poet.song.61000.json','["客子厭京塵，長街風瞇目。", "安得卧南陽，清潭漬寒菊。"]'),
('2ed00127-93df-4eee-ab9d-1d7621ea06a2','答陳傳道五首  其二','賀鑄','宋','宋诗','song-poetry','','[]','遊梁復歸宋，南北更相送。',24,'全唐诗/poet.song.61000.json','["遊梁復歸宋，南北更相送。", "失得兩如何，勞勞不如夢。"]'),
('e0887465-789c-41b8-ac4d-370bcd5640b8','答陳傳道五首  其三','賀鑄','宋','宋诗','song-poetry','','[]','遊宦幾人達，不知强健歸。',24,'全唐诗/poet.song.61000.json','["遊宦幾人達，不知强健歸。", "未容誇晝錦，幾見化緇衣。"]'),
('c653f737-28ad-4565-9c32-71ab3bc71561','答陳傳道五首  其四','賀鑄','宋','宋诗','song-poetry','','[]','聞有高秋興，清樽醉飛鴻。',24,'全唐诗/poet.song.61000.json','["聞有高秋興，清樽醉飛鴻。", "應悲故人遠，薄晚面西風。"]'),
('0b618d4e-60a4-4d7f-8ce3-194c38dd0ffe','答陳傳道五首  其五','賀鑄','宋','宋诗','song-poetry','','[]','倒橐黄金盡，方悲行路難。',24,'全唐诗/poet.song.61000.json','["倒橐黄金盡，方悲行路難。", "桂薪炊玉粒，可是樂長安。"]'),
('a3cef0c5-0f3c-4817-8f49-a2b92011df0d','擬劉孝勝詠安仁得果','賀鑄','宋','宋诗','song-poetry','','[]','果盡猶招手，車停更起塵。',24,'全唐诗/poet.song.61000.json','["果盡猶招手，車停更起塵。", "固應持一笑，先答近轅人。"]'),
('857deda5-3e1d-4ad4-a9f8-57ae1ca27c46','和王文舉玉臺體','賀鑄','宋','宋诗','song-poetry','','[]','南城空目送，西館斷心期。',24,'全唐诗/poet.song.61000.json','["南城空目送，西館斷心期。", "懸知今夜思，明燈半下帷。"]'),
('90351b70-7e73-426d-a4c2-c984a2483332','夢後聞蛩','賀鑄','宋','宋诗','song-poetry','','[]','籠燈耿欲滅，枕下蟲聲切。',24,'全唐诗/poet.song.61000.json','["籠燈耿欲滅，枕下蟲聲切。", "底許事相關，煎人腸斷絕。"]'),
('f6fa9c86-b30c-422a-bbeb-3882c6cceca9','寒宵歎','賀鑄','宋','宋诗','song-poetry','','[]','可憐明月光，委曲照空牀。',24,'全唐诗/poet.song.62000.json','["可憐明月光，委曲照空牀。", "自是元無夢，更悲今夜長。"]'),
('b4afcb3f-7270-4cec-99a0-cd3d13d5434f','春晚樓上','賀鑄','宋','宋诗','song-poetry','','[]','楊華吹復盡，春色但茫茫。',24,'全唐诗/poet.song.62000.json','["楊華吹復盡，春色但茫茫。", "獨立西樓上，持情向夕陽。"]'),
('548cd31b-bd16-4ba5-a26f-55ad806352db','和王文舉別館初夏','賀鑄','宋','宋诗','song-poetry','','[]','薰風酣綠樹，午日思黄鸝。',24,'全唐诗/poet.song.62000.json','["薰風酣綠樹，午日思黄鸝。", "的的羅窗夢，西鄰可得知。"]'),
('5aedbca5-18b4-4fa7-8cab-ee5afb276f32','和陳傳道秋日十詠 秋雨','賀鑄','宋','宋诗','song-poetry','','[]','近砌擲鳴籤，長簷懸素綆。',24,'全唐诗/poet.song.62000.json','["近砌擲鳴籤，長簷懸素綆。", "溼翅暝鴉歸，高梧落寒井。"]'),
('820bf79e-083f-4cc0-ae3b-eb868d8a29c6','和陳傳道秋日十詠 秋晴','賀鑄','宋','宋诗','song-poetry','','[]','歸雲去悠悠，長風來獵獵。',24,'全唐诗/poet.song.62000.json','["歸雲去悠悠，長風來獵獵。", "簷角兩長楸，斜陽曬黄葉。"]'),
('0bd82aff-1517-4f5d-b6bc-1eeaeb88b5fa','和陳傳道秋日十詠 秋夜','賀鑄','宋','宋诗','song-poetry','','[]','病骨倦空林，曳杖閑庭步。',24,'全唐诗/poet.song.62000.json','["病骨倦空林，曳杖閑庭步。", "暗燭與寒蟲，迢迢思風露。"]'),
