('d03cfedf-41a1-4c32-a8e2-dc03135c676c','題贈芥堂老僧遇來','賀鑄','宋','宋诗','song-poetry','','[]','歲計江邊二頃田，不能多應世間緣。',32,'全唐诗/poet.song.62000.json','["歲計江邊二頃田，不能多應世間緣。", "閉門密竹荒松裏，杯粥爐香六十年。"]'),
('db7e1ba2-92df-47bf-b586-fb0ffe96b1c3','茅塘馬上','賀鑄','宋','宋诗','song-poetry','','[]','壯圖忽忽負當年，回羨農兒過我賢。',32,'全唐诗/poet.song.62000.json','["壯圖忽忽負當年，回羨農兒過我賢。", "水落陂塘秋日薄，仰眠牛背看青天。"]'),
('bb0f1a8c-e41f-42f8-88b3-58ca224afb78','阻風小孤山晚晴作','賀鑄','宋','宋诗','song-poetry','','[]','小孤山下晚波恬，妥墮青鬟玉鏡奩。',32,'全唐诗/poet.song.62000.json','["小孤山下晚波恬，妥墮青鬟玉鏡奩。", "借與彭郎作眉樣，西南初月正尖纖。"]'),
('a21626e9-0abf-41a1-ad95-5f502210dc50','題漢陽寓舍老桑','賀鑄','宋','宋诗','song-poetry','','[]','曾無沃若飽吳蠶，腹蠹聊供啄木饞。',32,'全唐诗/poet.song.62000.json','["曾無沃若飽吳蠶，腹蠹聊供啄木饞。", "底事殷勤喭元緒，不應有意附炎炎。"]'),
('3bcc8597-a7ba-4a05-8ff5-24413e8fd5ac','秋江晚望','賀鑄','宋','宋诗','song-poetry','','[]','黄蘆洲渚赤楓林，林外殘陽疊嶂深。',32,'全唐诗/poet.song.62000.json','["黄蘆洲渚赤楓林，林外殘陽疊嶂深。", "記得廣陵城裏市，董源橫障賣千金。"]'),
('7df752fd-517b-44be-afe9-6276a82ef624','和吳達夫見過留題','賀鑄','宋','宋诗','song-poetry','','[]','雀羅門巷不容車，杖屨相過一試茶。',32,'全唐诗/poet.song.62000.json','["雀羅門巷不容車，杖屨相過一試茶。", "後日相思會乘興，五雲溪上是儂家。"]'),
('6c4b61ad-b088-4e7c-9b6a-bc9ab580390c','題詩卷後','賀鑄','宋','宋诗','song-poetry','','[]','詩豈窮人窮者工，斯言聞諸六一翁。',32,'全唐诗/poet.song.62000.json','["詩豈窮人窮者工，斯言聞諸六一翁。", "端慙少作老更拙，不廢汝詩吾固窮。"]'),
('4ec9a470-2cd7-492b-b952-ad862ed09742','答僧訥','賀鑄','宋','宋诗','song-poetry','','[]','唐代衣冠高四姓，天宗之亞滎陽鄭。',128,'全唐诗/poet.song.62000.json','["唐代衣冠高四姓，天宗之亞滎陽鄭。", "不墜家聲五百年，桂籍相望三葉慶。", "上人猛謝區中緣，破冠投櫛還童顛。", "寸灰已滅五經笥，來入辨才無礙禪。", "我竊官糧衆人後，相逢宛是平生舊。", "一聞南國白頭吟，萬媿西風碧雲陋。", "老鶴終辭雞鶩羣，誰將斷綆絆浮雲。", "它日傳衣度梅嶺，解留何語與將軍。"]'),
('46e83187-5bd9-4063-bda3-08767e186974','登海陵齊雲樓','賀鑄','宋','宋诗','song-poetry','','[]','樓外浮雲何可攀，聊持樽酒共銷閑。',64,'全唐诗/poet.song.62000.json','["樓外浮雲何可攀，聊持樽酒共銷閑。", "歸心欻起登臨際，春色來從想像間。", "晚雪晞時見芳草，滄波盡處欠青山。", "長安桃李行應好，解笑劉郎底未還。"]'),
('4c17e18a-4cc1-4fac-bfec-cc77e9a2a766','酬別曾忱','賀鑄','宋','宋诗','song-poetry','','[]','昔年室邇歎人遐，少日相逢別日賒。',64,'全唐诗/poet.song.62000.json','["昔年室邇歎人遐，少日相逢別日賒。", "聊寄歸心天北雁，會乘高興斗邊槎。", "雷驚白晝龍蛇起，風蕩青春草木華。", "誰念渠伊獨憔悴，豈容平世賦懷沙。"]'),
('bb82ae5a-74d2-4d5e-80bd-037400671861','送張師常之官南雄','賀鑄','宋','宋诗','song-poetry','','[]','爰居蹭蹬海西頭，紫鳳求皇亦少留。',64,'全唐诗/poet.song.62000.json','["爰居蹭蹬海西頭，紫鳳求皇亦少留。", "持酒一樽明日別，題詩幾處舊年遊。", "春風白芷江南岸，暑雨黄梅嶺上州。", "却望衡陽千里遠，懸知無雁託音郵。"]'),
('b7cc2305-c313-4d99-8d75-2ac88b95d8fe','送方安行之官高密令','賀鑄','宋','宋诗','song-poetry','','[]','平世功名輸阿童，束書洗劍栖漁篷。',64,'全唐诗/poet.song.62000.json','["平世功名輸阿童，束書洗劍栖漁篷。", "晚交東武百里長，想見桐廬三拜風。", "白雪興闌吟社遠，綠槐陰合訟庭空。", "它年朱紱指東道，試訪釣鼇浮玉翁。"]'),
('acd0e043-698d-4b74-8374-fcf0fdb60677','送江與京歸山陽','賀鑄','宋','宋诗','song-poetry','','[]','山陽澤國四無山，百雉危城兩水關。',64,'全唐诗/poet.song.62000.json','["山陽澤國四無山，百雉危城兩水關。", "楊柳遥知紫極路，滄波長羨白鷗閑。", "病來藥裹爲吾累，興盡漁舟送子還。", "風月異時何限思，區區併入尺書間。"]'),
('7c987759-e8ae-4191-b6f4-2a485b309019','海陵書事','賀鑄','宋','宋诗','song-poetry','','[]','海濱流浪胡爲乎，況復支離百病餘。',64,'全唐诗/poet.song.62000.json','["海濱流浪胡爲乎，況復支離百病餘。", "三月逢梅識春色，半年無雁託歸書。", "老烏啄屋巫呼鬼，野艇橫門米換魚。", "回首揚州纔百里，畫橋風月可憐渠。"]'),
('7e406d7b-9f2f-4c97-adc0-7b1a146d55e6','聞鶑有懷故園','賀鑄','宋','宋诗','song-poetry','','[]','海陵春後雨冥冥，耳厭蛙嗥鸛齒鳴。',64,'全唐诗/poet.song.62000.json','["海陵春後雨冥冥，耳厭蛙嗥鸛齒鳴。", "何意東亭好風日，流鶑忽作故園聲。", "故園千里長牽夢，老病三年不廢情。", "想見楊花收卷盡，綠苔池院落朱櫻。"]'),
('a1f02215-fb99-42a4-b952-792a42760384','海陵西樓寓目','賀鑄','宋','宋诗','song-poetry','','[]','天涯樽酒與誰開，風外徂春挽不回。',64,'全唐诗/poet.song.62000.json','["天涯樽酒與誰開，風外徂春挽不回。", "掃地可憐花更落，卷簾無奈燕還來。", "王孫莫顧漳濱卧，漁父何知楚客才。", "强策駑筋懷故國，浮雲千里思悠哉。"]'),
('6236d4d0-8863-4cab-bf78-69b7c4780fd6','寄興化黄主簿杞','賀鑄','宋','宋诗','song-poetry','','[]','何準第五不足稱，黄童無雙非自名。',64,'全唐诗/poet.song.62000.json','["何準第五不足稱，黄童無雙非自名。", "卑栖鸞鳳安初仕，葆練龍虎希長生。", "明月高吟紫芝曲，紅塵先老白雲兄。", "莫辭一力走三舍，遽未能來頻寄聲。"]'),
('7c70a35a-6ae6-4bee-8ee7-5a7be8544157','海陵喜雨','賀鑄','宋','宋诗','song-poetry','','[]','閏年四月之相交，旱天雲物何蕭騷。',64,'全唐诗/poet.song.62000.json','["閏年四月之相交，旱天雲物何蕭騷。", "清風捲地換塵世，白雨入林翻海濤。", "殊勝農兒踏車健，少寬病夫揮扇勞。", "須晴徑買一漁艇，想見橫塘深半篙。"]'),
('eb271002-e0a4-425b-a0e0-2c8c7feebc8a','食鰣魚','賀鑄','宋','宋诗','song-poetry','','[]','雨長沙田三尺蘆，截江邏釣待嘉魚。',64,'全唐诗/poet.song.62000.json','["雨長沙田三尺蘆，截江邏釣待嘉魚。", "上鉤一尾誇先得，下筯千錢忍棄餘。", "倦客罷彈腰下鋏，故人忘寄腹中書。", "知機何獨張生翰，不俟秋風已起予。"]'),
('1794ad08-6ad3-4516-bcb5-9978a2fd4287','題海陵寓舍四首  其一','賀鑄','宋','宋诗','song-poetry','','[]','藜藿荒庭微逕通，支撐破屋古池東。',64,'全唐诗/poet.song.62000.json','["藜藿荒庭微逕通，支撐破屋古池東。", "暮凉百燕抵突雨，晝靜一蟬饕餮風。", "隠几敢希南郭久，移文方誚北山空。", "森然槐柳相差地，它日低回憶箇中。"]'),
('846c2552-2460-4c72-abc5-0301f6e943b7','題海陵寓舍四首  其二','賀鑄','宋','宋诗','song-poetry','','[]','近溼籬根歌蟪蛄，向明屋角網蜘蛛。',64,'全唐诗/poet.song.62000.json','["近溼籬根歌蟪蛄，向明屋角網蜘蛛。", "黄葵紫莧雨張王，花蚊白蟻風驅除。", "輾轉猶憎夏夜久，支離何堪春病餘。", "預愁還作舊年調，兩眼京塵懷鏡湖。"]'),
('6d56bf6a-d1d0-4e83-8b4b-847af560210e','題海陵寓舍四首  其三','賀鑄','宋','宋诗','song-poetry','','[]','倒障開窗面曲池，塵襟初喜豁然披。',64,'全唐诗/poet.song.62000.json','["倒障開窗面曲池，塵襟初喜豁然披。", "清風殊不去人遠，明月端能與我期。", "鼓吹青蛙聊自喜，歌謳白鳥漸相欺。", "紛紛利害朝昏出，閉目忘言是住持。"]'),
('827f2bed-5897-4497-8bc5-ed54da1cd0d0','題海陵寓舍四首  其四','賀鑄','宋','宋诗','song-poetry','','[]','千里家園安在哉，羈栖猶喜占池臺。',64,'全唐诗/poet.song.62000.json','["千里家園安在哉，羈栖猶喜占池臺。", "酒非從事斷年別，風是故人彌日來。", "黄鳥綿蠻紫椹熟，白鷗瀺灂綠萍開。", "頗知老子機心廢，留得渠伊興盡回。"]'),
('6d6628a4-8356-4e2c-bfe6-9f6d50247a45','聞蘇眉山謫守英州作','賀鑄','宋','宋诗','song-poetry','','[]','嶺首登臨楚粵分，披襟先喜得南薰。',64,'全唐诗/poet.song.62000.json','["嶺首登臨楚粵分，披襟先喜得南薰。", "座隅鵩鳥敢要賦，溪下鰐魚知畏文。", "酒洗黄茅瘴時雨，嘯驅碧落洞中雲。", "高才何假江山助，未擬區區詠五君。"]'),
('8604166c-ce79-4d9e-b7f2-9bc53cba0297','寄金陵和上人','賀鑄','宋','宋诗','song-poetry','','[]','舊年問米欲東流，先賦新詩寄石頭。',64,'全唐诗/poet.song.62000.json','["舊年問米欲東流，先賦新詩寄石頭。", "赤鯶久沉江上信，雜懸誤落海邊州。", "想君道眼遥相識，顧我官身可自由。", "香火因緣知有在，草菴蔬粥不他求。"]'),
('005da4e8-98f0-4469-81b0-69bda53654b1','許永席上賦','賀鑄','宋','宋诗','song-poetry','','[]','流浪江湖跨兩年，西風猶駐木蘭船。',64,'全唐诗/poet.song.62000.json','["流浪江湖跨兩年，西風猶駐木蘭船。", "可人方外二三子，與爾樽中十八仙。", "處士妄同公子議，麴生未減索郎賢。", "自憐衰病方轟飲，也在劉家幕下天。"]'),
('e2058bbf-2575-486c-b8cf-b8613b1e352b','酬別道師許自然','賀鑄','宋','宋诗','song-poetry','','[]','早慕浮雲恥繫匏，泠然風馭起三茅。',64,'全唐诗/poet.song.62000.json','["早慕浮雲恥繫匏，泠然風馭起三茅。", "青菁可種無閑地，黄鶴歸來失舊巢。", "石鼎頗傳驚俗句，醉圖未免取僧嘲。", "何須西望長安笑，誰是平生莫逆交。"]'),
('61281025-2206-4078-97b1-e06a23bf1cab','題任氏傳德集','賀鑄','宋','宋诗','song-poetry','','[]','釣魚公子學屠龍，潦倒西班八品中。',64,'全唐诗/poet.song.62000.json','["釣魚公子學屠龍，潦倒西班八品中。", "鼠目獐頭登要地，雞鳴狗盜策奇功。", "儀刑拔士無光祿，經術傳家有聖童。", "慨想斯人安可作，九原松檟幾秋風。"]'),
('0630172e-aa9c-4283-a882-fdec7c9a32a9','送周開祖出守鄱陽','賀鑄','宋','宋诗','song-poetry','','[]','三尺京塵衮衮中，略無閑地貯清風。',64,'全唐诗/poet.song.62000.json','["三尺京塵衮衮中，略無閑地貯清風。", "鱸魚菰菜經年別，皂蓋朱轓一日東。", "俗眼强分青白在，芳樽未覺聖賢空。", "鄱陽不乏江山助，高興都盧屬謝公。"]'),
('c443b810-78b1-4d9d-ba42-2b83faef07c4','贈僧彥','賀鑄','宋','宋诗','song-poetry','','[]','昔年杖舄幾相從，同遇彌天漢上翁。',64,'全唐诗/poet.song.62000.json','["昔年杖舄幾相從，同遇彌天漢上翁。", "早恨揚舲南浦別，俄驚掃地北山空。", "壯心脫落浮雲外，病骨枝梧夢境中。", "頼有西巖舊桃李，異時應許共春風。"]'),
('05903574-4d80-49fa-9546-f21d84e76083','秦淮官柳二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','秦淮兩潮西復東，淮邊楊柳酣薰風。',64,'全唐诗/poet.song.62000.json','["秦淮兩潮西復東，淮邊楊柳酣薰風。", "送春白花去漠漠，避日黄鳥啼怱怱。", "陶彭澤多倦官歎，桓琅邪今衰病翁。", "此身會復有健日，擬就綠陰橫釣篷。"]'),
('cad3e720-3292-47bd-a624-ad57c340836d','秦淮官柳二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','西來載病一扁舟，建業江山負勝遊。',64,'全唐诗/poet.song.62000.json','["西來載病一扁舟，建業江山負勝遊。", "楊柳經眠方自得，蒲帆臨掛復遲留。", "長條似舞前溪曲，卷葉宜翻出塞愁。", "想見南朝舊人物，可憐能閟樣風流。"]'),
('922b2259-12c0-4e71-9dff-3c80aa658139','和別清凉和上人','賀鑄','宋','宋诗','song-poetry','','[]','明朝解携白鷺洲，後日相望黄鶴樓。',64,'全唐诗/poet.song.62000.json','["明朝解携白鷺洲，後日相望黄鶴樓。", "建業水清供白酌，武昌魚賤足音郵。", "著身物外不無處，俛首人羣非有求。", "願報西庵落成會，待公退卧儂歸休。"]'),
('8e8e5565-4844-479c-b542-4383a0a50cbb','重別和上人','賀鑄','宋','宋诗','song-poetry','','[]','分手風波路幾千，侵尋老境百疴纏。',64,'全唐诗/poet.song.62000.json','["分手風波路幾千，侵尋老境百疴纏。", "一官得飽亦勞矣，大士忘情猶泫然。", "北道音塵長斷望，西菴香火不無緣。", "是身脫使先朝露，圖像聊依十七賢。"]'),
('af5be646-e9b0-4e77-801f-03b1004ffa2a','留別彥上人','賀鑄','宋','宋诗','song-poetry','','[]','道人臨別重留連，應念吾生汩世緣。',64,'全唐诗/poet.song.62000.json','["道人臨別重留連，應念吾生汩世緣。", "拄笏看山猶故態，量船載酒異常年。", "興來不計遠千里，休去可須持一錢。", "會作清凉老庵主，兩盂分粥對床眠。"]'),
('a0a3311e-d095-43dc-829f-8afacd7a821c','留別王閑叟','賀鑄','宋','宋诗','song-poetry','','[]','婆娑晚境未知還，邂逅故人增厚顔。',64,'全唐诗/poet.song.62000.json','["婆娑晚境未知還，邂逅故人增厚顔。", "次道志包宇宙外，子牟身寄江湖間。", "一乘妙義想冰釋，九死餘生非石頑。", "敢負清凉阿師約，西菴先辦十年閑。"]'),
('012f3cee-1253-4c28-b5fd-f5c347ac02d9','烈洲守風','賀鑄','宋','宋诗','song-poetry','','[]','張帆早發石頭城，淹泊風波百里程。',64,'全唐诗/poet.song.62000.json','["張帆早發石頭城，淹泊風波百里程。", "白芷汀洲潮進退，黄梅村落晝陰晴。", "官糧牽迫少休日，藥物扶持多半生。", "深閉船扉謝漁老，自慙塵垢滿襟纓。"]'),
('0b1cefc2-6ace-4928-ae49-8b41bbe2b858','晚泊三山懷古兼寄歷陽朋遊','賀鑄','宋','宋诗','song-poetry','','[]','三山春水拍江流，六代餘風掃地收。',64,'全唐诗/poet.song.62000.json','["三山春水拍江流，六代餘風掃地收。", "破國龍驤復安在，賦詩宣城難與酬。", "傷心遠宦北宗老，滿眼舊遊南豫州。", "寄聲好住數君子，一別相忘風馬牛。"]'),
('23aeb406-1286-41a1-a3f1-b19e2cfd3ff9','晚泊東采石磯','賀鑄','宋','宋诗','song-poetry','','[]','謝衛將軍憐苦吟，袁臨汝郎遭賞音。',64,'全唐诗/poet.song.62000.json','["謝衛將軍憐苦吟，袁臨汝郎遭賞音。", "風流人物豈如昨，形勝江關留與今。", "控鯉直思淩浩渺，然犀何假照幽深。", "莫招捉月翰林老，屈曲塵間猶陸沉。"]'),
('82d8bc0f-6449-4356-b526-1832a06ad725','檥舟姑熟溪','賀鑄','宋','宋诗','song-poetry','','[]','潮來姑熟半篙深，帆落溪口檣如林。',64,'全唐诗/poet.song.62000.json','["潮來姑熟半篙深，帆落溪口檣如林。", "謝氏青山失故井，桓郎白苧無遺音。", "良遊躡屐負登覽，衰病伏枕方呻吟。", "箇中二頃了吾事，怊悵十年懷此心。"]'),
('ea0c7dca-029b-4a97-a4d7-e6302cae82f0','蕪湖王敦城下作','賀鑄','宋','宋诗','song-poetry','','[]','斗立孤城日四圍，賊奴曾未懾天威。',64,'全唐诗/poet.song.62000.json','["斗立孤城日四圍，賊奴曾未懾天威。", "風生虎帳豺聲厲，塵犯龍顔魚服歸。", "首揭大航遺臭在，歌流樂府舊音非。", "當時不慕桓文舉，草滿中原胡馬肥。"]'),
('c9b40a78-f39c-4df5-a1cb-074a46f61d4f','題皖山北瀕江田舍','賀鑄','宋','宋诗','song-poetry','','[]','江轉皖公山北流，蕭閑人物美田疇。',64,'全唐诗/poet.song.62000.json','["江轉皖公山北流，蕭閑人物美田疇。", "一溪春水百家利，二頃夏秧千石收。", "小市竹樓張酒旆，平橋松島蔭漁舟。", "莫知農老何爲者，幾葉傳封樂國侯。"]'),
('62126b45-58a8-457d-aa64-dd3002f45d95','晚泊小孤山作','賀鑄','宋','宋诗','song-poetry','','[]','江勢東南陡折回，兩山屹立地維開。',64,'全唐诗/poet.song.62000.json','["江勢東南陡折回，兩山屹立地維開。", "顛風裂石轟雷下，駭浪澎舟卷雪來。", "捫蝨王孫初睥睨，飽魚烏鬼但毰毸。", "物情豈識忘形樂，嘯倚檣干獨快哉。"]'),
('7d1e2f59-887f-4236-a217-e65778832dd5','得周元翁蘄春道中書','賀鑄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','離離赤棗牆東林，開窗下榻依牆陰。',96,'全唐诗/poet.song.62000.json','["離離赤棗牆東林，開窗下榻依牆陰。", "杖藜相顧頼之子，隠几忘言知我心。", "晚契初逢一東野，清詩屢擲雙南金。", "官身爲米自南北，世路亡羊無古今。", "夢澤草荒孤驛遠，洞庭雨入滄江深。", "相思何以祝高韵，桂樹秋風吟玉琴。"]'),
('4fbf2ef1-7a0e-45f8-b2b2-612d95932d8e','送漢陽刑獄掾鄒永年解官歸養','賀鑄','宋','宋诗','song-poetry','','[]','高歌每憶故山薇，笑擲青衫換綵衣。',64,'全唐诗/poet.song.62000.json','["高歌每憶故山薇，笑擲青衫換綵衣。", "竟爲蒼生安石起，本來男子次君歸。", "脫冠弭櫂興非淺，戴笠乘車誓莫違。", "明日渡江聊贈別，武昌官柳尚依依。"]'),
('266d3a63-1ded-4d04-ad47-3c20e8e4c867','登頭陀寺峰頂庵','賀鑄','宋','宋诗','song-poetry','','[]','磴道淩虛挂白虹，頭陀上方黄鵠東。',64,'全唐诗/poet.song.62000.json','["磴道淩虛挂白虹，頭陀上方黄鵠東。", "滄溟五夜浴新日，老木三伏來淒風。", "北夢南雲展張闊，縱江橫漢并吞雄。", "楚鄉絕境此其一，付與微吟多病翁。"]'),
('093e6f69-765a-4d4f-b3c4-0f9d16a3068c','九日寄維揚劉明仲','賀鑄','宋','宋诗','song-poetry','','[]','揚舲瓜步背瓜洲，底處孤亭是玉鈎。',64,'全唐诗/poet.song.62000.json','["揚舲瓜步背瓜洲，底處孤亭是玉鈎。", "蠟燭有心啼別夜，布帆無恙到南州。", "黄華嘉節與何事，白髮故人分取愁。", "頼有滄江知客恨，長年西北望京流。"]'),
('f4047af0-7ee6-4da2-bfbf-e5e6003cd96a','江夏秋懷三首  其一','賀鑄','宋','宋诗','song-poetry','','[]','陳物紛然眼界中，長年何與偶書空。',64,'全唐诗/poet.song.62000.json','["陳物紛然眼界中，長年何與偶書空。", "滄浪難爲俗子唱，絡緯漫催貧女工。", "風月少容休吏役，烟波長與濟途窮。", "功成身退非吾事，猶辦扁舟東復東。"]'),
('05a8114b-92e2-48f0-9c29-f9514732ad9b','江夏秋懷三首  其二','賀鑄','宋','宋诗','song-poetry','','[]','人物駸尋迫暮遲，秋風萬里來如期。',64,'全唐诗/poet.song.62000.json','["人物駸尋迫暮遲，秋風萬里來如期。", "幽蟲切切竟何道，羈燕怱怱將安之。", "洛下微吟聊擁鼻，西山爽氣爲支頤。", "肯將翰墨悲流落，寄語三閭彼一時。"]'),
('5b6e0f29-30f9-4333-8dc5-8ff4dd7c06d1','江夏秋懷三首  其三','賀鑄','宋','宋诗','song-poetry','','[]','此身豈復繫西東，流浪江湖伴塞鴻。',64,'全唐诗/poet.song.62000.json','["此身豈復繫西東，流浪江湖伴塞鴻。", "曲突非圖三爵客，直鉤何羨六鼇翁。", "千年陳迹祇今日，萬里故園猶箇中。", "冗散偶逃人指數，未應吟嘯坐妨公。"]'),
('2f5f5bfa-bf0e-47e9-b10f-1706755092c1','書國志陳登事後','賀鑄','宋','宋诗','song-poetry','','[]','求田問舍良可嘉，元龍偶未思之耶。',64,'全唐诗/poet.song.62000.json','["求田問舍良可嘉，元龍偶未思之耶。", "黄鼠長爲太倉耗，白雲猶有青山家。", "人生欻爾待鑽石，世故紛然勞算沙。", "銷磨髀肉亦何事，竟作子陽同井蛙。"]'),
('3a3cf047-40f0-425e-afc4-784e204d019f','寄別秦觀少游','賀鑄','宋','宋诗','song-poetry','','[]','沔陽湖上小留連，疑是前時李謫仙。',64,'全唐诗/poet.song.62000.json','["沔陽湖上小留連，疑是前時李謫仙。", "流向夜郎纔半道，徑還江夏樂當年。", "箇儂生以才爲累，阿堵官于老有緣。", "待得公歸吾亦罷，春風先辦兩漁船。"]'),
('d514df38-87ca-4a7a-b5fc-22711d5be1da','潘豳老出十數詩皆有懷蘇儋州者因賦二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','人烟寂絕鬼門關，更指儋州杳莽間。',64,'全唐诗/poet.song.62000.json','["人烟寂絕鬼門關，更指儋州杳莽間。", "三四月交天漏雨，東南地盡水浮山。", "依迷春草鴒原失，響像秋風鶴馭還。", "回羨河陽賢父子，雪堂曾伴十年閑。"]'),
('3ae7bb54-2600-40f1-96dd-d6e6e40b79c7','潘豳老出十數詩皆有懷蘇儋州者因賦二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','舊隠江城東復東，堂前楊柳付春風。',64,'全唐诗/poet.song.62000.json','["舊隠江城東復東，堂前楊柳付春風。", "猶傳白雪興中曲，俄失黄粱夢後翁。", "儋耳吉音無雁使，峨眉爽氣屬狙公。", "不應更廣窮愁志，悟取平生坐底窮。"]'),
('73a04d8d-c97f-43ea-95be-29a5355509ab','有僧自峽中來持黄黔州手製茶兼能道其動靜與潘豳老賦二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','未聞東觀奏書成，俄見西南萬里行。',64,'全唐诗/poet.song.62000.json','["未聞東觀奏書成，俄見西南萬里行。", "從坐何關李都尉，補亡猶待褚先生。", "心懸黄犬沈來耗，耳慣青駒祗舊鳴。", "時節私庭差自慰，鳳將雛去雁隨兄。"]'),
('c4c67c71-3d76-40d3-9f79-6cd9fec5649f','有僧自峽中來持黄黔州手製茶兼能道其動靜與潘豳老賦二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','平生得祿僅榮親，持底天涯料理貧。',64,'全唐诗/poet.song.62000.json','["平生得祿僅榮親，持底天涯料理貧。", "夜戶不關無長物，晨炊待火乞諸鄰。", "山𤢖頗俠能來虎，水弩何知枉中人。", "少減家園舊年調，携籠先采雨前春。"]'),
('6f9cf547-4be4-4d0b-b7f3-151fb2df678b','中秋日懷寄潘邠老賦','賀鑄','宋','宋诗','song-poetry','','[]','西戍角聲清且哀，東城鼓動殷然雷。',64,'全唐诗/poet.song.62000.json','["西戍角聲清且哀，東城鼓動殷然雷。", "雨闌伏檻月可待，風橫檥舟君不來。", "得酒未容歡獨伯，把書端與睡爲媒。", "雪堂歛穀急還舍，更約頭陀黄菊開。"]'),
('18af65db-ed87-474f-94f8-0ed121e7d127','重寄潘豳老','賀鑄','宋','宋诗','song-poetry','','[]','輕舠驀水帆如弓，一伸臂頃來江東。',64,'全唐诗/poet.song.62000.json','["輕舠驀水帆如弓，一伸臂頃來江東。", "聊持美酒致吾子，方事綵衣娛汝翁。", "懸榻可容它客坐，閉關正與無月同。", "夙興行樂竟何有，醒醉陰晴皆夢中。"]'),
('ec76db9c-4f63-4877-af30-57b0b198f54e','潘豳老以長篇求假吾書以副本送之','賀鑄','宋','宋诗','song-poetry','','[]','元凱有言君盍知，借書還書皆可嗤。',64,'全唐诗/poet.song.62000.json','["元凱有言君盍知，借書還書皆可嗤。", "家傳五載亦勤矣，吾與兩雛當共之。", "吏役豈容方外駕，古人端在箇中期。", "聊分副本天隨子，輯綴來歸是一奇。"]'),
('19f509c9-70e2-4b09-8cdb-72966d0c27a0','示王泌','賀鑄','宋','宋诗','song-poetry','','[]','違離南北幾星霜，短髮蕭蕭带尺長。',64,'全唐诗/poet.song.62000.json','["違離南北幾星霜，短髮蕭蕭带尺長。", "執戟郎效官落拓，楚丘生觸緒悲凉。", "雙鳬乘雁誰比數，拉虎批熊猶健彊。", "端恨養疴妨廢酒，樽前都屬箇儂狂。"]'),
('11b3d18a-453c-489f-a63d-aabd29d6a545','答致仕吳朝請潛登黄鶴樓見招','賀鑄','宋','宋诗','song-poetry','','[]','城隅黄鶴莫登臨，端使悲翁動楚吟。',64,'全唐诗/poet.song.62000.json','["城隅黄鶴莫登臨，端使悲翁動楚吟。", "日下長安人共遠，天圍夢澤歲方陰。", "北風欲雪雁飛急，南渚始冰魚伏深。", "誰似草堂安隠客，下帷隠几不求心。"]'),
('6e1839b8-b4a3-4d36-8400-4edfeed59983','雪後同吳達夫慎獻玉登黄鶴樓','賀鑄','宋','宋诗','song-poetry','','[]','歲律崢嶸臘盡頭，風吹朔雪到南州。',64,'全唐诗/poet.song.62000.json','["歲律崢嶸臘盡頭，風吹朔雪到南州。", "三湖簸蕩鮫鼉恐，七澤迷漫狐兔愁。", "狂客定回青雀舫，獵兒初試皂貂裘。", "江樓伏檻迎新霽，羣玉峰前練带流。"]'),
('404c089c-e405-444c-b9c9-cbbf12365d3f','曹永州哀詞','賀鑄','宋','宋诗','song-poetry','','[]','老眼春風兩淚傾，繐帷樽俎異平生。',64,'全唐诗/poet.song.62000.json','["老眼春風兩淚傾，繐帷樽俎異平生。", "可驚人與琴俱絕，但見肴晞酒復清。", "相合水邊傳美政，飛來峰下啟佳城。", "翩翩五六奇男子，肯使高門墜厥聲。"]'),
('75b45b64-318b-47f7-b0e5-b8400275bcdf','登黄鶴樓懷古兼寄潘豳老昆仲','賀鑄','宋','宋诗','song-poetry','','[]','漢大將軍楚國材，半生倦韵浼塵埃。',96,'全唐诗/poet.song.62000.json','["漢大將軍楚國材，半生倦韵浼塵埃。", "徐夫人匕首安在，丁令威華表歸來。", "紫府無蹤勞彷像，白雲有待久裴徊。", "樓標空闊天垠露，川勢從橫地紐開。", "隴鳥賦成洲共永，越人歌斷櫂先回。", "會招物外二三子，長嘯披襟挹快哉。"]'),
('4c76dcd6-ec12-4c5a-8eb1-7d0a798a4002','寄武昌方令臨李尉援兼簡黄岡二潘昆仲','賀鑄','宋','宋诗','song-poetry','','[]','好在桐江三拜翁，謫仙之裔好應同。',64,'全唐诗/poet.song.62000.json','["好在桐江三拜翁，謫仙之裔好應同。", "如聞花縣兩郎子，興發能來一水東。", "共醉南樓故時月，斷無庾令浼人風。", "季真老病不堪酒，澤畔微吟懷四儂。"]'),
('66d81da4-9447-4a2d-9b6c-ff63521d45d5','二月二日席上賦','賀鑄','宋','宋诗','song-poetry','','[]','仲宣何遽向荆州，謝惠連須更少留。',64,'全唐诗/poet.song.62000.json','["仲宣何遽向荆州，謝惠連須更少留。", "二日舊傳挑菜節，一樽聊解負薪憂。", "向人草樹有佳色，带郭江山皆勝遊。", "載酒賦詩從此始，它年耆老話風流。"]'),
('c32833f4-1f83-4d5f-a736-a08cc58abfe8','斗峴山馬上','賀鑄','宋','宋诗','song-poetry','','[]','西來投策倦躋攀，晚葉寒華一逕間。',32,'全唐诗/poet.song.62000.json','["西來投策倦躋攀，晚葉寒華一逕間。", "盡日閑雲不留雨，斜陽還照隔江山。"]'),
('910e58e3-99c5-46fc-95cf-0f6f4a0c4480','登如方山','賀鑄','宋','宋诗','song-poetry','','[]','楚郊十月尚聞蟬，傍道黄華亦可憐。',32,'全唐诗/poet.song.62000.json','["楚郊十月尚聞蟬，傍道黄華亦可憐。", "特上西山最高處，長安應在夕陽邊。"]'),
('e0875f7b-592a-4f77-99ac-96bdb0e527a9','渡冷水澗投宿萬歲嶺','賀鑄','宋','宋诗','song-poetry','','[]','蕭蕭黄葉下清溝，白鳥飛來故少留。',32,'全唐诗/poet.song.62000.json','["蕭蕭黄葉下清溝，白鳥飛來故少留。", "今夜行人短亭宿，小窗風雨夢漁舟。"]'),
('92889d48-912d-408c-96e7-a55b3f6dc95e','重遊寄老庵懷僧芝','賀鑄','宋','宋诗','song-poetry','','[]','淡遊已恨失芝公，陳躅空留夢境中。',32,'全唐诗/poet.song.62000.json','["淡遊已恨失芝公，陳躅空留夢境中。", "欲問孤雲何處去，庭前雙樹自西風。"]'),
('541de5da-9482-4cd2-abcc-4ab32e8aacd7','寄有捷上人','賀鑄','宋','宋诗','song-poetry','','[]','捷也當年避畏途，寄身一葉泛隋渠。',32,'全唐诗/poet.song.62000.json','["捷也當年避畏途，寄身一葉泛隋渠。", "定須慙愧操舟子，千里風波汝渡吾。"]'),
('3fbfc0d9-0b01-47ac-8ad8-c8e1d462dc34','曉晴西郊馬上','賀鑄','宋','宋诗','song-poetry','','[]','夜雨蕭蕭徹曉聞，不應爲我掃塵紛。',32,'全唐诗/poet.song.62000.json','["夜雨蕭蕭徹曉聞，不應爲我掃塵紛。", "弄鞭十里西郊道，但見青山納白雲。"]'),
('a832c65a-d9f0-487e-b80e-f6784c9c2ec1','重遊梵行院','賀鑄','宋','宋诗','song-poetry','','[]','曉渡南岡五里松，精廬未見已聞鐘。',32,'全唐诗/poet.song.62000.json','["曉渡南岡五里松，精廬未見已聞鐘。", "門前拂地垂楊柳，掃浄秋來過馬蹤。"]'),
('976bc0fd-5b2e-4a97-95f7-e0543859e096','同張漢求宿升中院西寮','賀鑄','宋','宋诗','song-poetry','','[]','僧閤窗扉學畫船，青熒燈火對牀眠。',32,'全唐诗/poet.song.62000.json','["僧閤窗扉學畫船，青熒燈火對牀眠。", "北風带雪披簷竹，渾似瀟湘夜泊天。"]'),
('9aed28ff-da06-4d87-a3aa-39ef8a89fc04','送僧法印志因西遊京師','賀鑄','宋','宋诗','song-poetry','','[]','刻雪裁冰物外人，强隨肥馬走京塵。',32,'全唐诗/poet.song.62000.json','["刻雪裁冰物外人，强隨肥馬走京塵。", "未應無地栽桃李，江北江南一樣春。"]'),
('97db9ef9-eabd-4787-8813-c1088262dba2','重遊鍾山定林寺','賀鑄','宋','宋诗','song-poetry','','[]','破冰泉脈漱籬根，壞衲遥疑掛樹猿。',32,'全唐诗/poet.song.62000.json','["破冰泉脈漱籬根，壞衲遥疑掛樹猿。", "蠟屐舊痕尋不見，東風先爲我開門。"]'),
('d5e7e5d3-b413-4ef3-ba19-ab7fb1787592','題賈氏廢園','賀鑄','宋','宋诗','song-poetry','','[]','丞相園林半手栽，清樽曾爲幾人開。',32,'全唐诗/poet.song.62000.json','["丞相園林半手栽，清樽曾爲幾人開。", "荒榛野蔓換桃李，慙愧春風如故來。"]'),
('8ace0fd5-6980-4157-a76d-cdb378503f7a','東城馬上','賀鑄','宋','宋诗','song-poetry','','[]','綵虹橋下水關東，接畛園林狹逕通。',32,'全唐诗/poet.song.62000.json','["綵虹橋下水關東，接畛園林狹逕通。", "繁杏半開隨半落，短牆無計礙春風。"]'),
('3155739a-c7aa-44ce-a19a-fdddc0332dcd','重送曾誠之兼簡俞澹陳庾  其一','賀鑄','宋','宋诗','song-poetry','','[]','春風漠漠老江蘺，行矣騷人好自持。',32,'全唐诗/poet.song.62000.json','["春風漠漠老江蘺，行矣騷人好自持。", "半百幻身如且健，石頭城下兩茅茨。"]'),
('810e3db4-0006-4a25-bc97-f2b98d01fbc9','重送曾誠之兼簡俞澹陳庾  其二','賀鑄','宋','宋诗','song-poetry','','[]','陳顛俞散舊朋遊，樽酒相逢定少留。',32,'全唐诗/poet.song.62000.json','["陳顛俞散舊朋遊，樽酒相逢定少留。", "衰病故情猶有在，春風一夜夢揚州。"]'),
('e625b416-7303-4311-909f-20b28d2d1024','平野堂重送江茂宗','賀鑄','宋','宋诗','song-poetry','','[]','東風南浦雨瀟瀟，欲去行人不自聊。',32,'全唐诗/poet.song.62000.json','["東風南浦雨瀟瀟，欲去行人不自聊。", "誰道垂楊攀折苦，過春猶有最長條。"]'),
('356e7c6f-b9cb-4614-85fc-ed4d525cf093','追和杜仲觀詠蝶','賀鑄','宋','宋诗','song-poetry','','[]','黄蝶尋花日百回，荒庭多雨漫莓苔。',32,'全唐诗/poet.song.62000.json','["黄蝶尋花日百回，荒庭多雨漫莓苔。", "老狂能似徽之輩，借宅猶應乞竹栽。"]'),
('ba66bbab-2414-4a99-95f5-d8ab8d3370cd','題芭蕉葉','賀鑄','宋','宋诗','song-poetry','','[]','十畝荒池漲綠萍，南風不見芰荷生。',32,'全唐诗/poet.song.62000.json','["十畝荒池漲綠萍，南風不見芰荷生。", "隔窗頼有芭蕉葉，未負瀟湘夜雨聲。"]'),
('3a27a719-fcaf-4fd6-a6e5-8e260e7fd799','留別僧永','賀鑄','宋','宋诗','song-poetry','','[]','三處分携跨兩年，浮雲生計本悠然。',32,'全唐诗/poet.song.62000.json','["三處分携跨兩年，浮雲生計本悠然。", "江山勝地端相待，大有東南未盡緣。"]'),
('27a23342-c964-4335-9d9f-f191d9b558eb','折中倉觀米元章題字','賀鑄','宋','宋诗','song-poetry','','[]','銀鈎入木揜鍾王，拂眼清風識楚狂。',32,'全唐诗/poet.song.62000.json','["銀鈎入木揜鍾王，拂眼清風識楚狂。", "淮海京塵兩流落，與君大是覺身妨。"]'),
('1080ce06-a891-4c77-8db1-7014ba9309c6','放舟通津門外作','賀鑄','宋','宋诗','song-poetry','','[]','國門欲去尚遲遲，況復淒風落照時。',32,'全唐诗/poet.song.62000.json','["國門欲去尚遲遲，況復淒風落照時。", "猶有京塵坌舟尾，惱人無幾庾元規。"]'),
('888d45a4-329a-481f-a4cb-a0fbb5222c16','黄山席上別當塗僚友  其一','賀鑄','宋','宋诗','song-poetry','','[]','自昔有宇宙，便應有此山。',48,'全唐诗/poet.song.62000.json','["自昔有宇宙，便應有此山。", "如我與君者，幾輩來躋攀。", "聲迹兩磨滅，寥寥千古間。", "短生一浮漚，妄比金石頑。"]'),
('d05ec379-ca14-4b01-b1a7-e511b3fda594','黄山席上別當塗僚友  其二','賀鑄','宋','宋诗','song-poetry','','[]','五福人所願，九齡神所慳。',48,'全唐诗/poet.song.62000.json','["五福人所願，九齡神所慳。", "著身名利場，寵辱如循環。", "不見倦飛鳥，翻然亦知還。", "酒闌解袂去，老矣遂投閑。"]'),
('6a5a6200-46c8-4d4b-b118-1cf2e75b0e2b','九日雨中作','賀鑄','宋','宋诗','song-poetry','','[]','九夏赤旱百井枯，三秋積雨釜生魚。',128,'全唐诗/poet.song.62000.json','["九夏赤旱百井枯，三秋積雨釜生魚。", "淩高徑醉不易圖，問底黄葉今有無。", "願致皎白來庭除，昏瞳爛卷勤卷舒。", "管中一班聊自娛，未羨北里鳴笙竽。", "少日用壯膽力麤，六鼇可取負而趨。", "誰謂衰遲百病餘，雀鼠入屋不受驅。", "長鋏長鋏歸來乎，泥深沒脛行無車。", "咄嗟蠟屐非雙鳬，安得翩然過故都。"]'),
('0322fc98-2c8b-4894-a87b-c6a4321d7378','送何安中之官新安錄事','賀鑄','宋','宋诗','song-poetry','','[]','带郭荒山百匝牢，躋攀幾見病猿猱。',64,'全唐诗/poet.song.62000.json','["带郭荒山百匝牢，躋攀幾見病猿猱。", "官糧可數纔雞肋，吏事懸知倍馬曹。", "芸閣有書行且召，萱堂須養未容高。", "慶湖老子何堪別，隠几僧坊更寂寥。"]'),
('e6847416-8c0c-4e17-8b18-25364a286ae9','送時適歸彭城兼寄王會之并張白雲','賀鑄','宋','宋诗','song-poetry','','[]','壯年客宦樂徐州，五見黄華戲馬週。',64,'全唐诗/poet.song.62000.json','["壯年客宦樂徐州，五見黄華戲馬週。", "無復登山拋舊屐，不堪臨水送歸舟。", "東城公子猶三徑，南墅先生久一邱。", "爲話吳門非樂土，鱸魚菰黍漫淹留。"]'),
('0fd433f1-c9fd-465c-83aa-821e679454fa','方明古免喪西上山陰賀鑄方回以詩送行非敢贈言聊書美志','賀鑄','宋','宋诗','song-poetry','','[]','西上遲遲誰挽留，了君方寸慕松楸。',64,'全唐诗/poet.song.62000.json','["西上遲遲誰挽留，了君方寸慕松楸。", "三年既盡亦當起，五斗有餘非所求。", "早歲向風勞企羨，殘生指日願依投。", "得官儻近柴桑里，應許江邊著釣舟。"]'),
('af9fe1b5-c4dd-4c99-8f99-f91e3fb5c8f8','清明病中','賀鑄','宋','宋诗','song-poetry','','[]','寒食晴暘少，江南此候同。',48,'全唐诗/poet.song.62000.json','["寒食晴暘少，江南此候同。", "侵晨潑火雨，薄暮駕潮風。", "目力書籤上，生涯藥裹中。", "可憐佳節物，似不繫衰翁。"]'),
('8ecd10d6-58f6-4ed3-a0c9-e552dbb4f8ec','題葉翰林道卿手書唐人唱和集後','賀鑄','宋','宋诗','song-poetry','','[]','翰客文房萬卷餘，詵詵翻是蠹書魚。',32,'全唐诗/poet.song.62000.json','["翰客文房萬卷餘，詵詵翻是蠹書魚。", "載薰載曝徒爲爾，秦築長城錯備胡。"]'),
('c0538ff0-6036-41f2-b04c-256bc5d40a56','題項羽廟三首  其一','賀鑄','宋','宋诗','song-poetry','','[]','分張天下付羣雄，回首咸陽卷地空。',32,'全唐诗/poet.song.62000.json','["分張天下付羣雄，回首咸陽卷地空。", "六國三秦隨擾攘，錦衣何暇到江東。"]'),
('50556cd7-599a-4106-b1ca-f1ac631a6e1d','題項羽廟三首  其二','賀鑄','宋','宋诗','song-poetry','','[]','楚都陳迹久灰埃，一曲虞兮尚寄哀。',32,'全唐诗/poet.song.62000.json','["楚都陳迹久灰埃，一曲虞兮尚寄哀。", "不作偷生渡江計，可須千里更西來。"]'),
('897e9395-edc8-4af7-95e8-5455e6bc8ede','題項羽廟三首  其三','賀鑄','宋','宋诗','song-poetry','','[]','三戶睢盱竟破秦，君王武略世稱神。',32,'全唐诗/poet.song.62000.json','["三戶睢盱竟破秦，君王武略世稱神。", "途窮一夜無遺恨，挈首殷勤予故人。"]'),
('34b111d5-ff87-452a-aa7c-cbad3459b446','錢塘海潮','賀鑄','宋','宋诗','song-poetry','','[]','高岸如陵累石頑，一支漲海橫中間。',64,'全唐诗/poet.song.62000.json','["高岸如陵累石頑，一支漲海橫中間。", "九軍雷鼓震玉壘，萬里墨雲驅雪山。", "秦政維舟羞膽怯，史遷舐筆恨才慳。", "錢郎幾許英雄氣，强弩三千擬射還。"]'),
('bc09b463-a059-46b7-86b7-3d9407dfb1c0','吳門秋懷','賀鑄','宋','宋诗','song-poetry','','[]','吳門客鬢再經秋，城郭籃舁久倦遊。',32,'全唐诗/poet.song.62000.json','["吳門客鬢再經秋，城郭籃舁久倦遊。", "平靜松江三萬頃，不應無處著漁舟。"]'),
('efe20ba5-474e-4525-8534-872337992064','丹陽客舍示曾紆公衮','賀鑄','宋','宋诗','song-poetry','','[]','眼裏鉛華今日見，胸中冰炭幾時除。',32,'全唐诗/poet.song.62000.json','["眼裏鉛華今日見，胸中冰炭幾時除。", "欲知老子消懷處，靜夜青燈一卷書。"]'),
('be412f75-df03-4ff8-8e27-e2fc5c094aa3','鑄年五十八因病廢得旨休致一絕寄呈姑蘇毗陵諸友','賀鑄','宋','宋诗','song-poetry','','[]','求田問舍向吳津，欲著衰殘老病身。',32,'全唐诗/poet.song.62000.json','["求田問舍向吳津，欲著衰殘老病身。", "未拜君恩賜剡曲，歸來且醉鑑湖春。"]'),
('fb0f4037-8fba-4107-9727-c9df6d726ddd','題毗陵僧舍二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','古寺相留跨兩年，窮通出處固天然。',32,'全唐诗/poet.song.62000.json','["古寺相留跨兩年，窮通出處固天然。", "短檠燈火掩書卷，屢聽芭蕉夜雨眠。"]'),
('3fb8a78d-d799-4b4b-8d57-b67e6dce6fab','題毗陵僧舍二首  其二','賀鑄','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','秋風忽起家山意，流落天涯歎憔悴。',32,'全唐诗/poet.song.62000.json','["秋風忽起家山意，流落天涯歎憔悴。", "古寺不挂寰瀛圖，終南山翁何處至。"]'),
('e601f814-cec1-47f5-87e1-b97db1925231','和題毗陵薦福寺紅梅','賀鑄','宋','宋诗','song-poetry','','[]','一種梅生禪老家，屋簷古幹恣敧斜。',32,'全唐诗/poet.song.62000.json','["一種梅生禪老家，屋簷古幹恣敧斜。", "詩人莫訝深紅色，可勝尋常桃杏花。"]'),
('78c1c218-724f-4a5d-b948-9dba546b520d','吳江送客','賀鑄','宋','宋诗','song-poetry','','[]','送別松陵道，輕舟助客拏。',48,'全唐诗/poet.song.62000.json','["送別松陵道，輕舟助客拏。", "湖空翦葭菼，市隘集魚蝦。", "薄雨啼殘雪，新潮蝕嫩沙。", "鏡中羞沓颯，行復見春花。"]'),
('0676d7b4-e3d6-45d6-9088-81e7500f4c6d','題流香亭','賀鑄','宋','宋诗','song-poetry','','[]','秋色朝來已十分，遠山清瘦露雲根。',32,'全唐诗/poet.song.62000.json','["秋色朝來已十分，遠山清瘦露雲根。", "芙蕖昨夜驚風雨，葉葉流香有淚痕。"]'),
('2b5e18d2-0896-4526-9607-8d64fa70df3d','王迥子高挽章五首  其一','賀鑄','宋','宋诗','song-poetry','','[]','我昔官房子，長懷忠穆賢。',48,'全唐诗/poet.song.62000.json','["我昔官房子，長懷忠穆賢。", "里無行馬第，山有卧牛阡。", "當代三公後，維君五福全。", "桐棺遠歸祔，追舊幾潸然。"]'),
('005dfa56-a27c-44d2-8598-f2bf6ddae1fc','王迥子高挽章五首  其二','賀鑄','宋','宋诗','song-poetry','','[]','卓爾金閨彥，頎然玉筍班。',48,'全唐诗/poet.song.62000.json','["卓爾金閨彥，頎然玉筍班。", "周旋三友益，零落十年間。", "轣轆靈輀動，悠揚素旐還。", "暮年懷抱愛，應未辨追攀。"]'),
('01703262-6ff8-4bf0-89b3-6c54cb6005f2','王迥子高挽章五首  其三','賀鑄','宋','宋诗','song-poetry','','[]','蕭散竹林風，平生約略同。',48,'全唐诗/poet.song.62000.json','["蕭散竹林風，平生約略同。", "官班魏叔夜，年輩晉安豐。", "民詠濡須政，朝推𦚧䏰功。", "九原無復作，埋玉恨何窮。"]'),
('2fa33226-758b-4daa-a347-58f96e0d1d07','王迥子高挽章五首  其四','賀鑄','宋','宋诗','song-poetry','','[]','南浦維舟訪，東堂抵榻眠。',48,'全唐诗/poet.song.62000.json','["南浦維舟訪，東堂抵榻眠。", "後期猶指日，輕別遂終天。", "墨妙今初貴，詩鳴久已傳。", "清風知未墜，諸子更翩翩。"]'),
('fb1b6050-bee5-4aca-8fa2-478d8cb2c105','王迥子高挽章五首  其五','賀鑄','宋','宋诗','song-poetry','','[]','已矣知無憾，賢愚共此途。',48,'全唐诗/poet.song.62000.json','["已矣知無憾，賢愚共此途。", "白駒馳白日，黄髮掩黄壚。", "和氏終還趙，干將不葬吳。", "駑疴如可强，猶擬奠生芻。"]'),
('5e960091-cabf-4cf5-a3fc-beabb5c10b6e','約十客同集金山米芾元章約而不至坐中分題以元章未至分韵作詩拈鬮韵應口便作滯思即罰巨觥余得章字','賀鑄','宋','宋诗','song-poetry','','[]','九客相逢思楚狂，停歌罷鋏緩行觴。',32,'全唐诗/poet.song.62000.json','["九客相逢思楚狂，停歌罷鋏緩行觴。", "座中那更添嚴令，分韵吟詩招阿章。"]'),
('8d62c884-b61e-4a2a-86de-68d69202bea5','題秦觀少游寫真','賀鑄','宋','宋诗','song-poetry','','[]','淮海多才士，徒希馬少游。',48,'全唐诗/poet.song.62000.json','["淮海多才士，徒希馬少游。", "誰容老芸閣，自讖死藤州。", "狀貌披圖爽，陽春掩卷愁。", "湛郎長鬣爾，殊不嗣風流。"]'),
('48ba2946-d0ab-4691-821c-11db92bbcc9d','別王銍性之','賀鑄','宋','宋诗','song-poetry','','[]','吾老無北里，子能詎南來。',48,'全唐诗/poet.song.62000.json','["吾老無北里，子能詎南來。", "臨分即間訣，薄暮更徘徊。", "晚節徇微尚，方剛患多才。", "此生南與北，出處兩悠哉。"]'),
('f20841f2-db8c-4528-8595-c5baabea39fe','留題左顧亭二首  其一','賀鑄','宋','宋诗','song-poetry','','[]','餘不亭下檥歸舟，訪古懷賢百刻留。',32,'全唐诗/poet.song.62000.json','["餘不亭下檥歸舟，訪古懷賢百刻留。", "辦得千金脫元緒，此心端不爲封侯。"]'),
('e917b23a-8656-47b8-8c80-234474403039','留題左顧亭二首  其二','賀鑄','宋','宋诗','song-poetry','','[]','亭際高樅滿百圍，不無山鬼此焉依。',32,'全唐诗/poet.song.62000.json','["亭際高樅滿百圍，不無山鬼此焉依。", "咿呦爲話當年事，曾見將軍佩印歸。"]'),
('f55e5f69-5259-489f-903d-2959aaef5f6b','客有携寇萊公真挂于驛舍傍題云今作閻羅王慨然有作','賀鑄','宋','宋诗','song-poetry','','[]','凜凜英風萬世孤，忽瞻容貌涕洟俱。',64,'全唐诗/poet.song.62000.json','["凜凜英風萬世孤，忽瞻容貌涕洟俱。", "遺謀不愧生張說，異事猶煩鬼董狐。", "黑白已分歸節義，丹青長懾在奸諛。", "不煩搖扇蒼蠅去，一片寒冰挂座隅。"]'),
('008c9434-4c3c-4341-81e1-8f411825ab23','內翰出龍眠居士寫真圖','賀鑄','宋','宋诗','song-poetry','','[]','落墨龍眠品入神，橫筇一見謫仙人。',64,'全唐诗/poet.song.62000.json','["落墨龍眠品入神，橫筇一見謫仙人。", "孤雲老鶴來何處，異石清流有是身。", "瞻仰生風開鬢髮，卷舒盥手敬星辰。", "他年莫用黄金鑄，傳在人間此逼真。"]'),
('a12c6452-dc1e-4dd7-8a8d-f052541679c1','句','王文舉','宋','宋诗','song-poetry','','[]','何日面青山，相並兩茅屋。',12,'全唐诗/poet.song.62000.json','["何日面青山，相並兩茅屋。"]'),
('c9ebc9fe-5551-44ec-9131-e455ee139537','句','王有元','宋','宋诗','song-poetry','','[]','應無好夢到彭城。',8,'全唐诗/poet.song.62000.json','["應無好夢到彭城。"]'),
('3c24f45c-c6da-4ec7-94d6-95f0af6b765c','鑑湖先生未老挂冠以詩卜居于姑蘇毗陵兩郡依韵奉和','鄔柄','宋','宋诗','song-poetry','','[]','清監風流賀季真，先生端是昔人身。',32,'全唐诗/poet.song.62000.json','["清監風流賀季真，先生端是昔人身。", "如何未老催歸去，要卧烟霞兩郡春。"]'),
('0891fff0-a5f0-4065-bfa3-eb67a260c816','蓋仙山六題 仙洞','王藻','宋','宋诗','song-poetry','','[]','仙人駕鶴上三清，壇石空留萬古名。',32,'全唐诗/poet.song.62000.json','["仙人駕鶴上三清，壇石空留萬古名。", "昨夜碧天星斗爛，不聞朝禮步虛聲。"]'),
('5cd6f128-077b-459f-8e89-8471d566b529','蓋仙山六題 龍洞','王藻','宋','宋诗','song-poetry','','[]','沉沉古洞鎖雲寒，中有龍依積水蟠。',32,'全唐诗/poet.song.62000.json','["沉沉古洞鎖雲寒，中有龍依積水蟠。", "若爲蒼生作霖雨，九天飛去不爲難。"]'),
('130a635f-fd1f-4561-b943-36508a66fdce','蓋仙山六題 甘泉','王藻','宋','宋诗','song-poetry','','[]','一脈靈源來已長，色濃如醴味甘香。',32,'全唐诗/poet.song.62000.json','["一脈靈源來已長，色濃如醴味甘香。", "石龍洞處無塵染，留與仙家作玉漿。"]'),
('2baba940-005a-4bde-a624-74cd70486dc6','蓋仙山六題 水精石','王藻','宋','宋诗','song-poetry','','[]','仙留白石顯靈蹤，化出水精雲洞中。',32,'全唐诗/poet.song.62000.json','["仙留白石顯靈蹤，化出水精雲洞中。", "一片寒冰清可琢，方員成器任良工。"]'),
('4f1806b4-4857-4d44-8259-7ed10c1f2d95','蓋仙山六題 雙筍石','王藻','宋','宋诗','song-poetry','','[]','生來雙筍幾經春，直上雲霄無蘚痕。',32,'全唐诗/poet.song.62000.json','["生來雙筍幾經春，直上雲霄無蘚痕。", "若使堅剛解成竹，人應喚作兩龍孫。"]'),
('b251b930-2a69-4f12-8184-95e6ab9f9298','蓋仙山六題 石人峰','王藻','宋','宋诗','song-poetry','','[]','元氣融成知幾春，石人峰好與誰論。',64,'全唐诗/poet.song.62000.json','["元氣融成知幾春，石人峰好與誰論。", "擎天不老歲長在，捧日無言形獨尊。", "每爲頭先生雪白，何嘗口解把霞吞。", "登高望處渾疑活，自許相隨遊洞門。"]'),
('0bbe2b0f-868d-40bb-b482-3f8f91b502db','句','王藻','宋','宋诗','song-poetry','','[]','路入麕䴥亭子嶺，江圍蒲稗富川城。',16,'全唐诗/poet.song.62000.json','["路入麕䴥亭子嶺，江圍蒲稗富川城。"]'),
('c3590935-f24b-4929-add3-fd1677235652','浄土院  其一','孫大廉','宋','宋诗','song-poetry','','[]','流水元依澗，孤雲不著山。',48,'全唐诗/poet.song.62000.json','["流水元依澗，孤雲不著山。", "萬緣機慮斷，一點浄明還。", "立雪人何在，銜花鳥自閒。", "羣昏疑網破，雄論落人間。"]'),
('2cd01e94-1e7d-427b-89bc-3afcb211f4a6','浄土院  其二','孫大廉','宋','宋诗','song-poetry','','[]','白蓮開綠水，佛子舊家山。',48,'全唐诗/poet.song.62000.json','["白蓮開綠水，佛子舊家山。", "浄境無南北，塵心有去還。", "林深天籟遠，風定水雲閒。", "何日逢旌騎，重來翠巘間。"]'),
('27ae750d-20cd-4118-9527-524707c8e1de','水簾泉','毛注','宋','宋诗','song-poetry','','[]','織水簾珠未是奇，舒王留詠奪天機。',64,'全唐诗/poet.song.62000.json','["織水簾珠未是奇，舒王留詠奪天機。", "神光已比箕星列，文焰長依舜日暉。", "一沼蛟龍涎半積，兩檐鸞鶴勢雙飛。", "名山從此留傳詠，自昔因人重發揮。"]'),
('93905697-3323-468f-92f3-1437f65300a2','仙居寺','毛注','宋','宋诗','song-poetry','','[]','瀟洒仙居院，樓臺烟靄中。',48,'全唐诗/poet.song.62000.json','["瀟洒仙居院，樓臺烟靄中。", "夜泉清浸月，午鐸冷搖風。", "轉目已成昨，累名俱是空。", "一尊林下醉，此興與誰同。"]'),
('f6b51b43-4f80-4e72-8285-a91b6a90e3ce','白雲亭','吳與','宋','宋诗','song-poetry','','[]','高城頓崇岡，上與白雲遇。',156,'全唐诗/poet.song.62000.json','["高城頓崇岡，上與白雲遇。", "昔賢此登臨，懷古得佳句。", "結亭自何人，歲月更已屢。", "古篆僅存名，頹簷颯將仆。", "我來訪遺蹤，環賞愜幽趣。", "鳩工扶墊隉，選木換隳蠹。", "津梁五道人，悉力願相赴。", "經營未終月，突兀見翬翥。", "英英蒼梧雲，朝莫此屯聚。", "時從南山來，倏向高巖去。", "去來本無心，虛亭日新故。", "因之望故鄉，更識親闈處。", "南山互牽情，凭闌目空注。"]'),
('e039646a-d024-449a-9f46-388f132308b4','南樓寺','吳與','宋','宋诗','song-poetry','','[]','靈鷲飛來處，南樓敞梵宮。',48,'全唐诗/poet.song.62000.json','["靈鷲飛來處，南樓敞梵宮。", "僧歸明月下，人在白雲中。", "洗鉢泉源近，傳燈寶積通。", "坐依龍象晚，鐘磬滿松風。"]'),
('79e93f10-ff91-4327-a36d-f464a07e3cde','七星壇','吳與','宋','宋诗','song-poetry','','[]','衆山重疊勢如環，地古基平數畝寬。',64,'全唐诗/poet.song.62000.json','["衆山重疊勢如環，地古基平數畝寬。", "山客曾留雙燕履，古松猶鎖七星壇。", "深林産藥人難老，碧洞藏龍氣自寒。", "丹竈久空遺迹在，塚中曾見舊衣冠。"]'),
('59667d32-ef64-4ad4-a7f8-d8bd01cfd697','題白雲軒','余亢','宋','宋诗','song-poetry','','[]','不作從龍意，無心謾出山。',24,'全唐诗/poet.song.62000.json','["不作從龍意，無心謾出山。", "可憐一片雪，長伴主人閑。"]'),
('ff5bd1dd-8249-4fbc-9ba6-e2f30a0e9b5e','遊齊山寺','楊詢','宋','宋诗','song-poetry','','[]','金剎岧嶢挂斷霓，島雲沮洳暗窗扉。',64,'全唐诗/poet.song.62000.json','["金剎岧嶢挂斷霓，島雲沮洳暗窗扉。", "江風曉定釣人出，山月夜高禪客歸。", "徑畔芭蕉曾有喻，庭前柏樹本無機。", "我來重見當時叟，紙帳松房補衲衣。"]'),
('bb9c693c-e58b-43eb-9776-10716f391d2c','題金粟寺庵','周壽','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','清池带蒼巘，結構俯林麓。',72,'全唐诗/poet.song.62000.json','["清池带蒼巘，結構俯林麓。", "扶疏竹外山，相向隔羅縠。", "老禪謝人境，歲晚收白足。", "誰聆跫然音，息隠尚爭逐。", "道場坐千劫，不媿桑下宿。", "定中觀潮汐，絕事心已熟。"]'),
('964b672e-fc3d-45df-92e7-3ad5a5a75dbc','和鄧慎思詩呈同院諸公三首  其一','余幹','宋','宋诗','song-poetry','','[]','秋日同文館，官寮許暫依。',48,'全唐诗/poet.song.62000.json','["秋日同文館，官寮許暫依。", "衛軒留鶴住，楚澤滯鴻歸。", "木選山中勝，珍求世上稀。", "清時方物貢，寧在篋中璣。"]'),
('ff18a0ac-7e7d-4767-bfd2-c1c0c6502333','和鄧慎思詩呈同院諸公三首  其二','余幹','宋','宋诗','song-poetry','','[]','秋日同文館，興賢道與光。',48,'全唐诗/poet.song.62000.json','["秋日同文館，興賢道與光。", "雄奇思汝潁，浮巧笑齊梁。", "綠醑傾蛆甕，青燈拆米囊。", "雅談揮玉麈，未厭漏聲長。"]'),
('239fa6a0-1fe8-4443-9cc3-8063168efeeb','和鄧慎思詩呈同院諸公三首  其三','余幹','宋','宋诗','song-poetry','','[]','秋日同文館，掄才又一回。',48,'全唐诗/poet.song.62000.json','["秋日同文館，掄才又一回。", "楩柟輸海徼，金玉振巖隈。", "富贍看先達，清新畏後來。", "百朋行可錫，所樂在多才。"]'),
('23ce5c5d-10a3-4a10-89b5-99dad050317d','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其一','余幹','宋','宋诗','song-poetry','','[]','零露沾明砌，凄風入邃闈。',48,'全唐诗/poet.song.62000.json','["零露沾明砌，凄風入邃闈。", "添愁蟲勸織，驚夢鳥催歸。", "哀調孤吹笛，寒聲遠搗衣。", "飄蓬雖已久，今夜覺分違。"]'),
('18745195-a638-435f-a6f1-592a39a76d69','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其二','余幹','宋','宋诗','song-poetry','','[]','引類憑先進，搜材及寸長。',48,'全唐诗/poet.song.62000.json','["引類憑先進，搜材及寸長。", "隔簾愁晝暝，隠几怯秋凉。", "化力人難測，機心我已忘。", "封侯良可待，誰有不龜方。"]'),
('4d94e5ca-7595-497d-a626-c0f852e58815','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其三','余幹','宋','宋诗','song-poetry','','[]','簾幕深常閉，門庭閴未開。',48,'全唐诗/poet.song.62000.json','["簾幕深常閉，門庭閴未開。", "愁將河女隔，喜見月娥來。", "騷客吟冰柱，仙官醉玉杯。", "蹇修那可得，笑齒竟誰媒。"]'),
('20b26aa0-8977-4cae-9743-7b24a5cc72a6','和鄧慎思初入試院','余幹','宋','宋诗','song-poetry','','[]','江南嘗應檄書行，多向西風拂露英。',64,'全唐诗/poet.song.62000.json','["江南嘗應檄書行，多向西風拂露英。", "薄暮解裝融祖寺，侵晨揮策楚王城。", "明蟾又見中秋色，哀雁仍聞半夜聲。", "懷舊感新搔短髮，歸時應有二毛生。"]'),
('dff26a0e-ccad-4fdd-951c-dac2a410ce98','試院即事呈諸公','余幹','宋','宋诗','song-poetry','','[]','去家策馬上長河，逆旅光陰忽忽過。',64,'全唐诗/poet.song.62000.json','["去家策馬上長河，逆旅光陰忽忽過。", "陳迹不堪追放浪，新才仍復委搜羅。", "雅談幸有青雲士，佳句寧無白雪歌。", "此興非憑吟笑遣，未應能奈客愁何。"]'),
('4b617e54-b81b-44b3-b2cf-d65b589b6bf4','和鄧慎思重九考罷試卷書呈同院諸公','余幹','宋','宋诗','song-poetry','','[]','庭實方期國士充，知音須辦鐸符鐘。',64,'全唐诗/poet.song.62000.json','["庭實方期國士充，知音須辦鐸符鐘。", "孔融愛客樽常滿，摩詰思親節又逢。", "鳥養任真終自適，彘謀傷性竟誰從。", "開門預計無多日，猶起清愁暮靄濃。"]'),
('849f8a2f-6ce5-4beb-96d2-6557d66a2bed','和鄧慎思同舍問及故山景物用鍾字韵詩以答','余幹','宋','宋诗','song-poetry','','[]','煙霞曾是踏諸峰，翻作清歌笑玉鐘。',64,'全唐诗/poet.song.62000.json','["煙霞曾是踏諸峰，翻作清歌笑玉鐘。", "幾代孫經桃塢隔，千年壇憶華山逢。", "美才方赴鳴騶召，逸興何由稅駕從。", "我亦江鄉成阻闊，西風歸意浩然濃。"]'),
('4a07b99d-152c-4461-8fcf-25f16de73013','和曹子方呈鄧張晁蔡','余幹','宋','宋诗','song-poetry','','[]','可畏日輪如赤釜，頼有羣仙司下土。',128,'全唐诗/poet.song.62000.json','["可畏日輪如赤釜，頼有羣仙司下土。", "稍從寥廓湧濃雲，旋向塵埃洒甘雨。", "松蘿既女更施澤，山木欲童俄得乳。", "馬牛暫息要途勞，魚鼈頓舒炎海苦。", "野鸛那虛屋上鳴，穴狸不繆山中語。", "清風豈假白羽搖，輕汗寧沾翠綃舞。", "已憐爽氣滿襟袖，更喜餘霞照庭戶。", "後朝便足閱英才，爲指帡幪設千俎。"]'),
('f606be6f-a45e-41e2-8e17-938d891175be','次韵天啟戲爲禪句之作','余幹','宋','宋诗','song-poetry','','[]','一片木柴投向釜，不是知音色如土。',128,'全唐诗/poet.song.62000.json','["一片木柴投向釜，不是知音色如土。", "道途謾用運三車，根性終然資一雨。", "相逢倘獲個中人，涓滴何辭北馿乳。", "善才童子天質奇，拋官遠遁修行苦。", "果向北山曾遇人，便解捐書尋一語。", "而今脫却七斤衫，相見山山惟作舞。", "秋闈何幸相握手，未厭夜深來叩戶。", "莫愁客至將何待，困有眠牀饑有俎。"]'),
('ad696358-ad3e-4241-9e9b-022ed701819c','次韵贈無咎學士','余幹','宋','宋诗','song-poetry','','[]','毗陵城如金斗方，往事歷歷那能忘。',352,'全唐诗/poet.song.62000.json','["毗陵城如金斗方，往事歷歷那能忘。", "相逢童子佩蘭芳，秀髮人指誰家郎。", "未幾重見突而長，即今不覺秋蓬蒼。", "戲笑豈復爲兒狂，追昔宓子初登堂。", "辭鋒峭拔森刀槍，器識沉遠包氐羌。", "陽秋寧肯露否臧，有子遊學先聚糧。", "相將百里陟岵岡，邂逅一挹坐僧牀。", "大辯傾注如無旁，天馬方謂先騫驤。", "觀魚誰復駐濠隍，瓜期受代垂趨裝。", "當路奏牘交稱揚，行將超擢奄云亡。", "坐令志氣不得償，傳家豈詫錢一囊。", "諸兒經行名州鄉，挾書繼踵諸父行。", "旋見天衢飛驌驦，論治直要超周商。", "術卑效淺笑杜房，况是亨運遭興王。", "致君紹祖邦家光，何止追考歸焚黄。", "邃庭朝露明芸香，異書滿閣秋氣凉。", "詠歌間成隨豆觴，讀之如欲凌雲翔。", "暫近大手離未央，□□□□□□望。", "挈篋來寄深閨霜，賓興賢能視文章。", "尊尚周孔麾韓莊，搜奇殆有通夕忙。", "英游疑動聚星祥，我歸復翳環堵牆。", "世味已能如飲漿，羲皇上人琴一張。"]'),
('3c3baf76-741f-460d-8d8f-b246ce09d6b6','龍南玉石巖','鍾伷','宋','宋诗','song-poetry','','[]','萬石結叢林，縈回鳥道深。',48,'全唐诗/poet.song.62000.json','["萬石結叢林，縈回鳥道深。", "山高雲漠漠，洞古綠陰陰。", "壁擁虯龍篆，崖懸鐘鼓音。", "不須愁日暮，勝景且追尋。"]'),
('ebb9f13e-9874-4abf-9d0a-e5af672033f5','府舍西軒作','劉概','宋','宋诗','song-poetry','','[]','昔年曾作瀟湘客，憔悴東秦歸未得。',48,'全唐诗/poet.song.62000.json','["昔年曾作瀟湘客，憔悴東秦歸未得。", "西軒忽見好溪山，如何尚有楚鄉憶。", "讀書誤人四十年，有時醉把闌干拍。"]'),
('5d95236b-f5c6-4d89-a1ac-a92a7d65551e','贈新住靈巖長老','劉概','宋','宋诗','song-poetry','','[]','岑崟千嶂插青霄，殿閣崢嶸霽靄交。',64,'全唐诗/poet.song.62000.json','["岑崟千嶂插青霄，殿閣崢嶸霽靄交。", "已化靈蛇留徑迹，雙飛白鶴上雲巢。", "萬家香火春迎社，一派泉聲夜滌庖。", "投錫此來當有意，獨存秘宇在巖坳。"]'),
('4777da10-08fa-4a8e-8f28-17fc7f99df3e','奉和御製頒賜荔枝','余深','宋','宋诗','song-poetry','','[]','結實寧辭火後山，移根今照日華丹。',64,'全唐诗/poet.song.62000.json','["結實寧辭火後山，移根今照日華丹。", "來從南海航千里，賜比西山藥一丸。", "封植自憐依禁籞，芬芳無復耀幽蘭。", "萬年枝上風光別，嘗奉宣和燕暇看。"]'),
('cefa0dbe-ab34-489a-a0b4-7e64746a1b83','奉和駕幸西池','余深','宋','宋诗','song-poetry','','[]','春深瓊苑百花明，拂曉鑾輿下太清。',64,'全唐诗/poet.song.62000.json','["春深瓊苑百花明，拂曉鑾輿下太清。", "綵仗六軍嚴禁衛，虹橋千步跨仙瀛。", "講脩禊事垂遊豫，欲與民心樂治平。", "扈蹕兩經來此地，獨慚衰颯玷恩榮。"]'),
('7525d32e-e45f-4b77-a1ce-dd989034fe7f','奉和御製上巳日賜宴二首  其一','余深','宋','宋诗','song-poetry','','[]','晴日氛暄埽，都人祓禊初。',48,'全唐诗/poet.song.62000.json','["晴日氛暄埽，都人祓禊初。", "湛恩施雨露，清宴集冠裾。", "風織波紋細，晴牽柳線舒。", "太平多盛事，恩許樂于胥。"]'),
('2af8236b-27bb-4cab-a67d-f54d63b86327','奉和御製上巳日賜宴二首  其二','余深','宋','宋诗','song-poetry','','[]','紀元新曆布，修禊暮春初。',48,'全唐诗/poet.song.62000.json','["紀元新曆布，修禊暮春初。", "愷樂傳恩斝，榮光動拜裾。", "宸章爭日麗，聖澤與陽舒。", "欲識天臨遠，殊方屬象胥。"]'),
('cb184678-b6c1-458f-b8a9-1c7fc68d4ce5','奉和御製中伏入延福宮納凉','余深','宋','宋诗','song-poetry','','[]','節逢中伏許休閒，錫宴清都絳闕間。',64,'全唐诗/poet.song.62000.json','["節逢中伏許休閒，錫宴清都絳闕間。", "俯仰自驚希世遇，低徊終愧異恩頒。", "連雲竹影含風遠，撲面荷香擁棹還。", "施厚眷深知未報，獨憐疲瘁已衰顔。"]'),
('bf99273a-dc6e-4dff-9c99-d99d5741483d','奉和御製睿謨殿賜宴','余深','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','睿謨賜宴預英良，翠輦鳴鞘出紫房。',64,'全唐诗/poet.song.62000.json','["睿謨賜宴預英良，翠輦鳴鞘出紫房。", "閬苑羣仙環帝所，洞庭萬橘薦秋香。", "芬芳殽實容饕腹，咫尺天威許捧觴。", "日暮歸來自天上，恍然塵慮頓消忘。"]'),
('2443f3b1-9f2c-4226-8cec-6305c14a1894','奉和御製御樓及睿謨殿觀燈  其一','余深','宋','宋诗','song-poetry','','[]','觚稜金碧雪消殘，燈火東風破暮寒。',64,'全唐诗/poet.song.62000.json','["觚稜金碧雪消殘，燈火東風破暮寒。", "扇影開雲瞻日表，月華如露泛仙盤。", "天顔有喜同遊豫，雅俗多歡樂治安。", "航海陪臣驚遠目，蓬瀛今向帝城看。"]'),
('463f2835-0d7f-4b60-a3b9-3acb259ad376','奉和御製御樓及睿謨殿觀燈  其二','余深','宋','宋诗','song-poetry','','[]','元宵欲近臘光殘，宮殿森嚴夜氣寒。',64,'全唐诗/poet.song.62000.json','["元宵欲近臘光殘，宮殿森嚴夜氣寒。", "金碧相輝花影動，雲烟低覆瑞光盤。", "臣心共慶千齡會，國勢方隆九鼎安。", "寶祚化成天上事，恍疑身在夢中看。"]'),
('12cd8b35-9ba2-4a45-ad06-522f87dff203','奉和角樓特宴','余深','宋','宋诗','song-poetry','','[]','東樓預宴對天顔，身世渾疑在廣寒。',64,'全唐诗/poet.song.62000.json','["東樓預宴對天顔，身世渾疑在廣寒。", "妙舞清歌來禁殿，江苞海錯入珍盤。", "民心康樂時光好，樂奏和平化國安。", "詔許景龍歸緩轡，都民竟作異恩看。"]'),
('bc53334f-cdf7-486f-bfcc-0594c1deb70f','奉和御製佑神觀觀燈從駕','余深','宋','宋诗','song-poetry','','[]','月華迎仗翠輿還，冉冉春光暖破寒。',64,'全唐诗/poet.song.62000.json','["月華迎仗翠輿還，冉冉春光暖破寒。", "蓮炬浮雲星漢遠，鼇峰徹夜燭龍盤。", "况逢節好民風樂，自是祥多國祚安。", "萬井謳歌歸聖德，年年長擁路旁看。"]'),
('d1ae84be-b3de-411d-88f3-c0a44f8df9d2','奉和御製禁苑花開社日錫宴穠華閣  其一','余深','宋','宋诗','song-poetry','','[]','蓬壺何幸又重來，湛露濃恩宴喜開。',32,'全唐诗/poet.song.62000.json','["蓬壺何幸又重來，湛露濃恩宴喜開。", "延福宮中聽度曲，仙桃花下許傳盃。"]'),
('79265ce2-e568-4c17-8a50-8a471f44d4bb','奉和御製禁苑花開社日錫宴穠華閣  其二','余深','宋','宋诗','song-poetry','','[]','文杏夭桃次第開，宣遊叨豫賞花來。',32,'全唐诗/poet.song.62000.json','["文杏夭桃次第開，宣遊叨豫賞花來。", "飲歸帝所層城暮，恍若鈞天一夢回。"]'),
('ba680468-3292-47d1-ba49-2a17104e3ad9','奉和御製禁苑花開社日錫宴穠華閣  其三','余深','宋','宋诗','song-poetry','','[]','閬山縈繞鎖春風，竹密花深隠映中。',32,'全唐诗/poet.song.62000.json','["閬山縈繞鎖春風，竹密花深隠映中。", "行到夾城催錫宴，穠華西畔看繁紅。"]'),
('bbbbd337-3883-48ba-95f2-26eddb5c7b6a','奉和御製宣召遊龍德西園','余深','宋','宋诗','song-poetry','','[]','禁籞秋光睹物華，飄然清思浩無涯。',32,'全唐诗/poet.song.62000.json','["禁籞秋光睹物華，飄然清思浩無涯。", "沙邊橋下淺深水，岸側竹間紅白花。"]'),
('47ca4866-e3b0-4c6c-9475-c276aea06b7b','奉和御製龍池','余深','宋','宋诗','song-poetry','','[]','萬國恩波浸太平，清風和氣入歡聲。',32,'全唐诗/poet.song.62000.json','["萬國恩波浸太平，清風和氣入歡聲。", "一詩榮遇真千載，共慶壬辰值此生。"]'),
('b9321941-2e82-4603-9250-04f496a3e1cf','奉和御製重陽宴西園','余深','宋','宋诗','song-poetry','','[]','黄英紫蕊映雕觴，拂拂風生酒面光。',32,'全唐诗/poet.song.62000.json','["黄英紫蕊映雕觴，拂拂風生酒面光。", "佳節難逢恩更厚，坐令秋律變春陽。"]'),
('1c930e8b-6950-4dd5-ac6d-3241ac302860','感憤','翁績','宋','宋诗','song-poetry','','[]','千里寒沙遺白骨，一番新鬼哭黄雲。',32,'全唐诗/poet.song.62000.json','["千里寒沙遺白骨，一番新鬼哭黄雲。", "偷生同惡終相蔽，安得忠誠達聖君。"]'),
('337f077f-f379-4dd1-8770-40a984b5901d','次韵和翟公巽猩猩毛筆','何去非','宋','宋诗','song-poetry','','[]','貌妍足巧語，軀惡招歋歈。',168,'全唐诗/poet.song.62000.json','["貌妍足巧語，軀惡招歋歈。", "賦形具人獸，寧脫荆榛居。", "肉嘗登俎鼎，餉餽傳甘腴。", "失計墮醉鄉，顛躓無與扶。", "柔毫傳束縛，航海歸仙癯。", "浴質逸少池，摛藻知章湖。", "殺身固有用，賦芧從衆狙。", "坐令宣城工，無復誇栗鬚。", "文房甲四寶，萬兔慚蒙膚。", "數管友十年，閉門賦三都。", "之子信豪邁，嗜學每致劬。", "未冠游膠庠，已推經行儒。", "蓬山天祿閣，崢嶸凌碧虛。", "期予早登躡，同舍校魯魚。"]'),
('5cbadb14-4c68-4215-b842-69449b8a30e8','鳴絃峰','查許國','宋','宋诗','song-poetry','','[]','木葉蕭蕭江水清，幅巾藜杖繞山行。',32,'全唐诗/poet.song.62000.json','["木葉蕭蕭江水清，幅巾藜杖繞山行。", "忽然行到山深處，聽得鳴絃一兩聲。"]'),
('6f8ac273-dab2-4c48-8b7a-dfd02a3eecdb','寄賀方回','某女','宋','宋诗','song-poetry','','[]','獨倚危闌淚滿襟，小園春色嬾追尋。',32,'全唐诗/poet.song.62000.json','["獨倚危闌淚滿襟，小園春色嬾追尋。", "深恩縱似丁香結，難展芭蕉一寸心。"]'),
('f40bbb06-2e71-4df3-906e-ac5c11ea4665','莊嚴寺海棠洞','王瑜','宋','宋诗','song-poetry','','[]','千株相對復相重，裊娜繁枝夾路紅。',32,'全唐诗/poet.song.62000.json','["千株相對復相重，裊娜繁枝夾路紅。", "疑是當時錦步障，至是留得罩春風。"]'),
('4ab900c5-4b6f-43ed-87f5-56d8f099c184','遊華清留絕句','王瑜','宋','宋诗','song-poetry','','[]','廢宇頹垣不復新，朝元輦道盡荆榛。',32,'全唐诗/poet.song.62000.json','["廢宇頹垣不復新，朝元輦道盡荆榛。", "惟餘一派溫湯水，長與行人洗路塵。"]'),
('dee1d279-7d66-416e-9c65-9bd97f640cb0','書詩話後','劉和叔','宋','宋诗','song-poetry','','[]','坐井而觀天，遂亦作天論。',24,'全唐诗/poet.song.62000.json','["坐井而觀天，遂亦作天論。", "客問天方圓，低頭慙客問。"]'),
('98cc72ec-89e9-43a5-9338-c52645dab4a1','妾薄命二首  其一','陳師道','宋','宋诗','song-poetry','','[]','主家十二樓，一身當三千。',72,'全唐诗/poet.song.62000.json','["主家十二樓，一身當三千。", "古來妾薄命，事主不盡年。", "起舞爲主壽，相送南陽阡。", "忍著主衣裳，爲人作春妍。", "有聲當徹天，有淚當徹泉。", "死者恐無知，妾身長自憐。"]'),
('7cf91f63-64ec-49fc-9eeb-c517f7d0f8ce','妾薄命二首  其二','陳師道','宋','宋诗','song-poetry','','[]','葉落風不起，山空花自紅。',72,'全唐诗/poet.song.62000.json','["葉落風不起，山空花自紅。", "捐世不待老，惠妾無其終。", "一死尚可忍，百歲何當窮。", "天地豈不寬，妾身自不容。", "死者如有知，殺身以相從。", "向來歌舞處，夜雨鳴寒蛩。"]'),
('cd88a553-658c-4a4a-8118-04896fe75a46','南豐先生挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','早棄人間事，真從地下游。',48,'全唐诗/poet.song.62000.json','["早棄人間事，真從地下游。", "丘原無起日，江漢有東流。", "身世從違裏，功名取次休。", "不應須禮樂，始作後程仇。"]'),
('6f922b6f-5a80-4d18-868f-c763d63f38e3','南豐先生挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','精爽回長夜，衣冠出廣庭。',48,'全唐诗/poet.song.62000.json','["精爽回長夜，衣冠出廣庭。", "勳庸留琬琰，形像付丹青。", "道喪餘篇翰，人亡更典刑。", "侯芭才一足，白首太玄經。"]'),
('2495c3fe-d06e-4d43-8f0c-2d7ecff816d1','送外舅郭大夫槩西川提點刑獄','陳師道','宋','宋诗','song-poetry','','[]','丈人東南來，復作西南去。',120,'全唐诗/poet.song.62000.json','["丈人東南來，復作西南去。", "連年萬里別，更覺貧賤苦。", "王事有期程，親年當喜懼。", "畏與妻子別，已復迫曛暮。", "何者最可憐，兒生未知父。", "盜賊非人情，蠻夷正狼顧。", "功名何用多，莫作分外慮。", "萬里早歸來，九折慎馳騖。", "嫁女不離家，生男已當戶。", "曲逆老不侯，知人公豈誤。"]'),
('adcab296-4f96-4bbe-9484-8a91fec646a0','送內','陳師道','宋','宋诗','song-poetry','','[]','麀麌顧其子，燕雀各有隨。',96,'全唐诗/poet.song.62000.json','["麀麌顧其子，燕雀各有隨。", "與子爲夫婦，五年三別離。", "兒女豈不懷，母老妹已笄。", "父子各從母，可喜亦可悲。", "關河萬里道，子去何當歸。", "三歲不可道，白首以爲期。", "百畝未爲多，數口可無饑。", "吞聲不敢盡，欲怨當歸誰。"]'),
('484a29f5-75f3-4e8d-9b35-36fe1dc94f54','別三子','陳師道','宋','宋诗','song-poetry','','[]','夫婦死同穴，父子貧賤離。',120,'全唐诗/poet.song.62000.json','["夫婦死同穴，父子貧賤離。", "天下寧有此，昔聞今見之。", "母前三子後，熟視不得追。", "嗟乎胡不仁，使我至於斯。", "有女初束髮，已知生離悲。", "枕我不肯起，畏我從此辭。", "大兒學語言，拜揖未勝衣。", "喚耶我欲去，此語那可思。", "小兒襁褓間，抱負有母慈。", "汝哭猶在耳，我懷人得知。"]'),
('83348e03-9230-4c1b-951d-0d254f902baa','寄外舅郭大夫二首  其一','陳師道','宋','宋诗','song-poetry','','[]','巴蜀通歸使，妻孥且舊居。',48,'全唐诗/poet.song.62000.json','["巴蜀通歸使，妻孥且舊居。", "深知報消息，不忍問何如。", "身健何妨遠，情親未肯疏。", "功名欺老病，淚盡數行書。"]'),
('afb7968a-3757-4265-a2d8-875959ddcceb','寄外舅郭大夫二首  其二','陳師道','宋','宋诗','song-poetry','','[]','丈人魯諸生，明刑如皋陶。',48,'全唐诗/poet.song.62000.json','["丈人魯諸生，明刑如皋陶。", "幸寬右顧憂，未惜一身遥。", "西南萬里行，可以斷繩橋。", "慎勿用惠文，神母仁如堯。"]'),
('118321fc-258d-43aa-8c03-983fd36da319','城南寓居','陳師道','宋','宋诗','song-poetry','','[]','游子暮何歸，韋杜城南村。',48,'全唐诗/poet.song.62000.json','["游子暮何歸，韋杜城南村。", "秋水深可測，挽衣踏行雲。", "道暗失歸處，棲鳥故不喧。", "牛羊閉籬落，稚子猶在門。"]'),
('601b0aa5-b521-4c02-9056-e16c52df039d','江湖堂','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','莫愛西湖好，涓涓去不迴。',24,'全唐诗/poet.song.62000.json','["莫愛西湖好，涓涓去不迴。", "無情是江水，猶解及時來。"]'),
('0e7837e2-1590-4ac9-983f-9108c68d96ec','憶少子','陳師道','宋','宋诗','song-poetry','','[]','端也早豐下，歲晚未可量。',48,'全唐诗/poet.song.62000.json','["端也早豐下，歲晚未可量。", "我老不自食，安得如我長。", "呱呱棄不子，退省未始忘。", "吾母亦念我，與爾寧相望。"]'),
('25f9ade9-83c6-4b3e-8221-2027b2fd05d6','眠雲齋','陳師道','宋','宋诗','song-poetry','','[]','已是登臨晚，長須愛惜春。',24,'全唐诗/poet.song.62000.json','["已是登臨晚，長須愛惜春。", "終當捐世事，來作卧雲人。"]'),
('7c977d0b-9555-4b05-8b16-f34ed55bcdd7','贈二蘇公','陳師道','宋','宋诗','song-poetry','','[]','岷峨之山中巴江，桂椒柟櫨楓柞樟。',296,'全唐诗/poet.song.62000.json','["岷峨之山中巴江，桂椒柟櫨楓柞樟。", "青金黄玉丹砂良，獸皮鳥羽不足當。", "異人間出駭四方，嚴王陳李司馬揚。", "一翁二季對相望，奇寶橫道驥伏箱。", "誰其識者有歐陽，大科異等固其常。", "小却盛之白玉堂，典謨頌雅用所長。", "度越周漢登虞唐，千載之下有素王。", "平陳鄭毛視荒荒，後生不作諸老亡。", "文體變化未可量，萬口一律如吃羌。", "妖狐幻人犬陸梁，虎豹却走逢牛羊。", "上帝惠顧祓不祥，天門夜下龍虎章。", "前驅吳回後炎皇，絳旂丹轂朱冠裳。", "從以甲胄萬鬼行，乘風縱燎無留藏。", "天高地下日月光，授公以柄扶病傷。", "士如稻苗待公秧，臨流不渡公爲航。", "如大醫王治膏肓，外證已解中尚彊。", "探囊一試黄昏湯，一洗十年新學腸。", "老生塞口不敢嘗，向來狂殺今尚狂，請公別試囊中方。"]'),
('f3e05165-ef20-49b6-880b-42e9fefbb21b','暑雨','陳師道','宋','宋诗','song-poetry','','[]','密雨吹不斷，貧居常閉門。',48,'全唐诗/poet.song.62000.json','["密雨吹不斷，貧居常閉門。", "東溟容有限，西極更能存。", "束濕炊懸釜，翻牀補壞垣。", "倒身無著處，呵手不成溫。"]'),
('10bc3c0e-88d8-4bd8-b3aa-ab1e46a28410','送江楚州','陳師道','宋','宋诗','song-poetry','','[]','濠梁初得意，闕里舊論詩。',48,'全唐诗/poet.song.62000.json','["濠梁初得意，闕里舊論詩。", "晚歲何多難，經年始一辭。", "淮人饑饉後，良吏拊循時。", "欲託山陽簿，翁歸不受私。"]'),
('6f4b5d39-2fee-4030-8907-0b4984a8a4bf','山口','陳師道','宋','宋诗','song-poetry','','[]','湖闊疑無地，河回忽見山。',48,'全唐诗/poet.song.62000.json','["湖闊疑無地，河回忽見山。", "登臨聊自試，衰疾致身閑。", "四壁寧虞盜，多方莫駐顔。", "無風回遠笛，有月待人還。"]'),
('7b4885ea-c2ee-491f-8913-c9e93d817997','晁無咎張文潛見過','陳師道','宋','宋诗','song-poetry','','[]','白社雙林去，高軒二妙來。',48,'全唐诗/poet.song.62000.json','["白社雙林去，高軒二妙來。", "排門衝鳥雀，揮壁带塵埃。", "不憚除堂費，深愁載酒回。", "功名付公等，歸路在蓬萊。"]'),
('45785209-b542-4530-823d-40fb3ba5669b','示三子','陳師道','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u601d\u4eb2"]','去遠即相忘，歸近不可忍。',48,'全唐诗/poet.song.62000.json','["去遠即相忘，歸近不可忍。", "兒女已在眼，眉目略不省。", "喜極不得語，淚盡方一哂。", "了知不是夢，忽忽心未穩。"]'),
('0bda785b-8987-40e8-8588-b8982bea7ec7','次韵答邢居實二首  其一','陳師道','宋','宋诗','song-poetry','','[]','漢庭用少公何在，不使羣飛接羽翰。',32,'全唐诗/poet.song.62000.json','["漢庭用少公何在，不使羣飛接羽翰。", "今代貴人須白髮，掛冠高處未宜彈。"]'),
('5f3a56de-e982-4a26-87bf-958db0740163','次韵答邢居實二首  其二','陳師道','宋','宋诗','song-poetry','','[]','秋來爲客意何如，千里山河信不疏。',32,'全唐诗/poet.song.62000.json','["秋來爲客意何如，千里山河信不疏。", "昔日老人今則少，不妨紅葉閉門書。"]'),
('2166fc50-7c49-44bc-b269-307c327ee05c','丞相溫公挽詞三首  其一','陳師道','宋','宋诗','song-poetry','','[]','恭默思良弼，詩書正百工。',48,'全唐诗/poet.song.62000.json','["恭默思良弼，詩書正百工。", "事多違謝傅，天遽奪楊公。", "一代風流盡，三師禮數崇。", "若無天下議，美惡併成空。"]'),
('d3e3aea3-15e7-4320-9575-5992cab0dc70','丞相溫公挽詞三首  其二','陳師道','宋','宋诗','song-poetry','','[]','百姓歸周老，三年待魯儒。',48,'全唐诗/poet.song.62000.json','["百姓歸周老，三年待魯儒。", "世方隨日化，身已要人扶。", "玉几雖來晚，明堂訖授圖。", "心知死諸葛，終不羨曹蜍。"]'),
('f4061a39-78a3-4cca-8c74-17aac714dd02','丞相溫公挽詞三首  其三','陳師道','宋','宋诗','song-poetry','','[]','少學真成己，中年託著書。',48,'全唐诗/poet.song.62000.json','["少學真成己，中年託著書。", "輟耕扶日月，起廢極吹噓。", "得志寧論晚，成功不願餘。", "一爲天下慟，不敢愛吾廬。"]'),
('5ced5313-d050-4617-875f-8a8d28d225a6','次韵答學者四首  其一','陳師道','宋','宋诗','song-poetry','','[]','津津爽氣貫眉目，十五男兒萬里身。',32,'全唐诗/poet.song.62000.json','["津津爽氣貫眉目，十五男兒萬里身。", "筆下倒傾三峽水，胸中別作一家春。"]'),
('3fec02a6-302f-43e8-8b53-df513a38bcdc','次韵答學者四首  其二','陳師道','宋','宋诗','song-poetry','','[]','黄塵投老得何郎，准擬明年共我長。',32,'全唐诗/poet.song.62000.json','["黄塵投老得何郎，准擬明年共我長。", "熏沐不爲杯酒汙，飛揚未許老夫量。"]'),
('9429777b-c399-4193-a0ba-b7801d1a3258','次韵答學者四首  其三','陳師道','宋','宋诗','song-poetry','','[]','暗中摸索不難知，眼裏輪囷却見稀。',32,'全唐诗/poet.song.62000.json','["暗中摸索不難知，眼裏輪囷却見稀。", "行地徑須先八駿，刺天終不羨羣飛。"]'),
('45a6afb8-5787-4878-8203-7d187bc31f1d','次韵答學者四首  其四','陳師道','宋','宋诗','song-poetry','','[]','太阿無前鋒不缺，鉛刀不堪供一切。',32,'全唐诗/poet.song.62000.json','["太阿無前鋒不缺，鉛刀不堪供一切。", "至柔繞指剛則折，善而藏之光奪月。"]'),
('fcc42fbb-7e4d-465d-b86a-1a2f78bd21b3','次韵秦覯聽雁聞雞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','行斷哀多影不留，有人中夜攬衣裘。',32,'全唐诗/poet.song.62000.json','["行斷哀多影不留，有人中夜攬衣裘。", "筆頭細字真堪怨，眼裏長檠不解愁。"]'),
('7e18e7b9-25e2-4766-b766-6682e1ac5488','次韵秦覯聽雁聞雞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','立馬階除待一鳴，何如春夢不聞聲。',32,'全唐诗/poet.song.62000.json','["立馬階除待一鳴，何如春夢不聞聲。", "固知雞口羞牛後，不待鳴羣已可驚。"]'),
('3502a3ce-ceba-4bda-ab9e-0778ca65ea86','嘲秦覯','陳師道','宋','宋诗','song-poetry','','[]','長鋏歸來夜帳空，衡陽回雁耳偏聰。',32,'全唐诗/poet.song.62000.json','["長鋏歸來夜帳空，衡陽回雁耳偏聰。", "若爲借與春風看，無限珠璣咳唾中。"]'),
('1d21a8eb-2938-4cbd-b6c1-8465833d2896','和豫章公黄梅二首  其一','陳師道','宋','宋诗','song-poetry','','[]','寒裏一枝春，白間千點黄。',24,'全唐诗/poet.song.62000.json','["寒裏一枝春，白間千點黄。", "道人不好色，行處若爲香。"]'),
('01eac134-ee7b-4fa8-ab96-f72f824e987a','和豫章公黄梅二首  其二','陳師道','宋','宋诗','song-poetry','','[]','色輕花更艷，體弱香自永。',24,'全唐诗/poet.song.62000.json','["色輕花更艷，體弱香自永。", "玉質金作裳，山明風弄影。"]'),
('a8a97dbb-9128-41b8-8901-8ab3274e0e01','答張文潛','陳師道','宋','宋诗','song-poetry','','[]','我貧無一錐，所向皆四壁。',48,'全唐诗/poet.song.62000.json','["我貧無一錐，所向皆四壁。", "瀛洲足風露，胡不減饑色。", "昔聞杜氏子，剪髻事尊客。", "君婦定不賢，三梳奉巾櫛。"]'),
('3775a7ce-85fa-49fd-a20e-04b2e681e950','九日寄秦覯','陳師道','宋','宋诗','song-poetry','','["\u5199\u666f", "\u52c9\u52b1", "\u6292\u60c5", "\u91cd\u9633\u8282", "\u53cb\u4eba"]','疾風回雨水明霞，沙步叢祠欲莫鴉。',64,'全唐诗/poet.song.62000.json','["疾風回雨水明霞，沙步叢祠欲莫鴉。", "九日清樽欺白髮，十年爲客負黄花。", "登高懷遠心如在，向老逢辰意有加。", "淮海少年天下士，獨能無地落烏紗。"]'),
('e73df8d9-0d43-40e3-8bdf-cd152cdd1ee2','巨野','陳師道','宋','宋诗','song-poetry','','[]','餘力唐虞後，沉人海岱西。',48,'全唐诗/poet.song.62000.json','["餘力唐虞後，沉人海岱西。", "不應容桀黠，寧復有青齊。", "燈火魚成市，帆檣藕带泥。", "十年塵霧底，瞥眼怪鳧鷖。"]'),
('88b6e62c-6680-486e-9bc5-fb81737dbcc2','追呼行','陳師道','宋','宋诗','song-poetry','','[]','去年米賤家賜粟，百萬官倉不餘掬。',96,'全唐诗/poet.song.62000.json','["去年米賤家賜粟，百萬官倉不餘掬。", "青錢隨賜費追呼，昔日剜瘡今補肉。", "今年夏旱秋水生，江淮轉粟千里行。", "不應遠水救近渴，空倉四壁雀不鳴。", "似聞爲政不爲費，兩不相傷兩相濟。", "十年斂積用一朝，驚濤破山風動地。"]'),
('85b39c1e-bfb5-423f-baec-97b928bbd812','雪後黄樓寄負山居士','陳師道','宋','宋诗','song-poetry','','[]','林廬煙不起，城郭歲將窮。',48,'全唐诗/poet.song.62000.json','["林廬煙不起，城郭歲將窮。", "雲日明松雪，溪山進晚風。", "人行圖畫裏，鳥度醉吟中。", "不盡山陰興，天留憶戴公。"]'),
('612c1233-82a5-4b02-b66a-b81c968f52c2','秋懷示黄預','陳師道','宋','宋诗','song-poetry','','[]','窗鳴風歷耳，道壞草侵衣。',48,'全唐诗/poet.song.62000.json','["窗鳴風歷耳，道壞草侵衣。", "月到千家靜，林昏一鳥歸。", "冥冥塵外趣，稍稍眼中稀。", "送老須公等，秋棋未解圍。"]'),
('f33cf072-d085-465d-8567-02e85373a159','送張支使','陳師道','宋','宋诗','song-poetry','','[]','曠度逢知晚，高才處下難。',48,'全唐诗/poet.song.62000.json','["曠度逢知晚，高才處下難。", "清秋一鶚上，拭目萬人看。", "白酒初同醉，黄花已戒寒。", "憑將衰老事，一一報長安。"]'),
('60b4b250-13fe-4569-8092-f54b5592fd32','送杜侍御純陝西轉運','陳師道','宋','宋诗','song-poetry','','[]','餽糧千里古無策，木牛流馬功不極。',208,'全唐诗/poet.song.62000.json','["餽糧千里古無策，木牛流馬功不極。", "邊頭數米換黄金，將軍汗馬未伏櫪。", "黠羌人面作胡語，鳥雀貪生爾如許。", "熊虎可避蝱可驅，覆巢熏穴意何如。", "漢虜相當庸可盡，聊城正用一封書。", "巧手莫爲無麵餠，誰能留渴須遠井。", "國家有急君得辭，徐人不勞扣關請。", "隴上壯士莫捫舌，河西狂王防係頸。", "向來此地幾送迎，草間翁仲口不瘖。", "十年兩熟飽可待，一歲四守人何心。", "老稚持車車不留，歸人不行行轉頭。", "關中正須蕭丞相，省內早要富民侯。", "可同一夫在所憫，歲晚得無溝壑憂。"]'),
('a902f336-b41c-4e9c-9595-9d734451a47b','送楊侍禁兼寄顔黄二公二首  其一','陳師道','宋','宋诗','song-poetry','','[]','相逢今已晚，同府尚經年。',48,'全唐诗/poet.song.62000.json','["相逢今已晚，同府尚經年。", "衆口不成虎，諸公更薦賢。", "兩親須薄祿，一障欲乘邊。", "往問顔夫子，何妨試著鞭。"]'),
('14fec06b-2968-4844-bf9e-992af097aa76','送楊侍禁兼寄顔黄二公二首  其二','陳師道','宋','宋诗','song-poetry','','[]','多問黄居士，終年欠一書。',48,'全唐诗/poet.song.62000.json','["多問黄居士，終年欠一書。", "因人候消息，有使報何如。", "向晚逢楊子，真堪託後車。", "親年方頼祿，不惜借吹噓。"]'),
('5c5f3c9f-cc11-4518-aa5c-578648722af8','送外舅郭大夫夔路提點刑獄','陳師道','宋','宋诗','song-poetry','','[]','天險連三峽，官曹據上游。',48,'全唐诗/poet.song.62000.json','["天險連三峽，官曹據上游。", "百年雙鬢白，萬里一身浮。", "可使人無訟，寧須意外憂。", "平生晏平仲，能費幾狐裘。"]'),
('328cc434-79b3-4d61-b8b0-069e91a49f31','謝人寄酒','陳師道','宋','宋诗','song-poetry','','[]','舊香餘味記黄封，厭見春泥滿眼紅。',32,'全唐诗/poet.song.62000.json','["舊香餘味記黄封，厭見春泥滿眼紅。", "千乘莫從公子後，百壺能爲故人東。"]'),
('ed102c5a-90c9-43eb-b8c0-c1bd95306e3a','從蘇公登後樓','陳師道','宋','宋诗','song-poetry','','[]','倏作三年別，才堪一解顔。',48,'全唐诗/poet.song.62000.json','["倏作三年別，才堪一解顔。", "樓孤带清洛，林缺見巴山。", "五月池無水，千年鶴自還。", "白鷗沒浩蕩，愛惜鬢毛斑。"]'),
('9674bb61-147b-40a7-ab90-f455168b4d2f','送蘇公知杭州','陳師道','宋','宋诗','song-poetry','','[]','平生羊荆州，追送不作遠。',72,'全唐诗/poet.song.62000.json','["平生羊荆州，追送不作遠。", "豈不畏簡書，放麑誠不忍。", "一代不數人，百年能幾見。", "昔如馬口銜，今爲禁門鍵。", "一雨五月凉，中宵大江滿。", "風帆目力短，江空歲年晚。"]'),
('92344770-036a-4fe3-a796-1929f7ec0d5e','送秦覯二首  其一','陳師道','宋','宋诗','song-poetry','','[]','士有從師樂，諸兒却未知。',48,'全唐诗/poet.song.62000.json','["士有從師樂，諸兒却未知。", "欲行天下獨，信有俗間疑。", "秋入川原秀，風連鼓角悲。", "目前㹠犬類，未必慰親思。"]'),
('b3fe1f1c-bb88-49d2-8720-86b8bfed6da7','送秦覯二首  其二','陳師道','宋','宋诗','song-poetry','','[]','師法時難得，親年富有餘。',48,'全唐诗/poet.song.62000.json','["師法時難得，親年富有餘。", "端爲李君御，盡讀鄴侯書。", "結友真莫逆，論才有不如。", "折腰終不補，可但曳長裾。"]'),
('0a666682-61f4-4bba-a0db-c23c8d101aa9','和江秀才獻花三首  其一','陳師道','宋','宋诗','song-poetry','','[]','風雨東籬冷落看，清溪水落玉峰寒。',32,'全唐诗/poet.song.62000.json','["風雨東籬冷落看，清溪水落玉峰寒。", "酒家不辦當壚費，乞與先生種杏壇。"]'),
('c11400bc-52f5-43fc-82ba-4db7714ed220','和江秀才獻花三首  其二','陳師道','宋','宋诗','song-poetry','','[]','疏花得雨數枝黄，白髮緣愁百尺長。',32,'全唐诗/poet.song.62000.json','["疏花得雨數枝黄，白髮緣愁百尺長。", "要與老生同一醉，故留秋意作重陽。"]'),
('ddd9fb38-106a-4697-898b-6f19572b2773','和江秀才獻花三首  其三','陳師道','宋','宋诗','song-poetry','','[]','江公孤憤不宜秋，吟作秋蟲到白頭。',32,'全唐诗/poet.song.62000.json','["江公孤憤不宜秋，吟作秋蟲到白頭。", "過我可爲千日醉，從公難作百錢游。"]'),
('79a7e620-22c3-4f8d-8404-56f9906b254e','次韵李節推九日登南山','陳師道','宋','宋诗','song-poetry','','["\u5199\u666f", "\u767b\u9ad8", "\u6292\u6000", "\u91cd\u9633\u8282"]','平林廣野騎臺荒，山寺鳴鐘報夕陽。',64,'全唐诗/poet.song.62000.json','["平林廣野騎臺荒，山寺鳴鐘報夕陽。", "人事自生今日意，寒花只作去年香。", "巾欹更覺霜侵鬢，語妙何妨石作腸。", "落木無邊江不盡，此身此日更須忙。"]'),
('fc9366ac-97d5-4779-9276-c92d9565ff4f','別負山居士','陳師道','宋','宋诗','song-poetry','','[]','田園相與老，此別意如何。',48,'全唐诗/poet.song.62000.json','["田園相與老，此別意如何。", "更病可無酒，猶寒已自和。", "高名胡未廣，詩興尚能多。", "沙草東山路，猶須一再過。"]'),
('6172cbbc-b4e4-4256-a312-5bf618585f70','送趙教授','陳師道','宋','宋诗','song-poetry','','[]','束髮相看到白頭，了知公鬢不勝憂。',64,'全唐诗/poet.song.62000.json','["束髮相看到白頭，了知公鬢不勝憂。", "可堪親老須三釜，又著儒冠忍一羞。", "平世功名須晚節，向來旬月取封侯。", "北州豪傑知誰健，乞我黄淤十里秋。"]'),
('5bb1b8d7-3e80-4c50-807c-74ba86a1e965','次韵春懷','陳師道','宋','宋诗','song-poetry','','[]','欲作歸田計，無如二頃何。',48,'全唐诗/poet.song.62000.json','["欲作歸田計，無如二頃何。", "折腰方頼祿，拭面未傷和。", "日下烏聲樂，塵生鳥跡多。", "渡頭留小楫，乘興得相過。"]'),
('d2b9a3f5-b124-4c97-99fb-4525de138ee9','黄梅五首  其一','陳師道','宋','宋诗','song-poetry','','[]','異色深宜晚，生香故觸人。',24,'全唐诗/poet.song.62000.json','["異色深宜晚，生香故觸人。", "不施千點白，別作一家春。"]'),
('24ae8c09-7e03-4721-b217-bd1df488b0b0','黄梅五首  其二','陳師道','宋','宋诗','song-poetry','','[]','舊鬢千絲白，新梅百葉黄。',24,'全唐诗/poet.song.62000.json','["舊鬢千絲白，新梅百葉黄。", "留花如有待，迷國更須香。"]'),
('c460e3cc-16b7-4ce2-8fe0-fcff44e941ab','黄梅五首  其三','陳師道','宋','宋诗','song-poetry','','[]','冉冉梢頭綠，婷婷花下人。',24,'全唐诗/poet.song.62000.json','["冉冉梢頭綠，婷婷花下人。", "欲傳千里信，暗折一枝春。"]'),
('0b4af324-6114-4047-8b2d-23c9d0347d8c','黄梅五首  其四','陳師道','宋','宋诗','song-poetry','','[]','黄裏含真意，春容带薄寒。',24,'全唐诗/poet.song.62000.json','["黄裏含真意，春容带薄寒。", "欲知誰稱面，徧插一枝看。"]'),
('b8e18969-4aeb-48c5-932e-173a6de62e71','黄梅五首  其五','陳師道','宋','宋诗','song-poetry','','[]','花裏重重葉，釵頭點點黄。',24,'全唐诗/poet.song.62000.json','["花裏重重葉，釵頭點點黄。", "祇應報春信，故作著人香。"]'),
('32db3851-2852-4bd3-9f39-5c448b8404db','田家','陳師道','宋','宋诗','song-poetry','','[]','雞鳴人當行，犬鳴人當歸。',48,'全唐诗/poet.song.62000.json','["雞鳴人當行，犬鳴人當歸。", "秋來公事急，出處不待時。", "昨夜三尺雨，竈下已生泥。", "人言田家樂，爾苦人得知。"]'),
('84a7560c-8da3-466e-a607-6fa8d207ee2d','巨野二首  其一','陳師道','宋','宋诗','song-poetry','','[]','紅落芙蕖晚，青深蒲稗秋。',24,'全唐诗/poet.song.62000.json','["紅落芙蕖晚，青深蒲稗秋。", "平湖無過鳥，鳴鼓有行舟。"]'),
('8c02117c-ffd3-43f0-97d4-5e61fa155416','巨野二首  其二','陳師道','宋','宋诗','song-poetry','','[]','蒲港侵衣綠，蓮塘亂眼紅。',24,'全唐诗/poet.song.62000.json','["蒲港侵衣綠，蓮塘亂眼紅。", "將身供世事，結纜待回風。"]'),
('5c2869ec-83a0-4988-bcde-0de835e6915e','別叔父錄曹','陳師道','宋','宋诗','song-poetry','','[]','爲吏專文法，成家託弟昆。',48,'全唐诗/poet.song.62000.json','["爲吏專文法，成家託弟昆。", "三年如昨日，一笑更何言。", "扶老須微祿，移官實至恩。", "兩疏元父子，何日復東轅。"]'),
('5052813f-05b0-4afa-b4b8-cccc4ef12eb4','出清口','陳師道','宋','宋诗','song-poetry','','[]','家世山東飽耕稼，晚託一舟順流下。',112,'全唐诗/poet.song.62000.json','["家世山東飽耕稼，晚託一舟順流下。", "漁溝寒餠不下筯，推柂轉頭更五夜。", "平明放溜出清口，霜落潮回霧連野。", "平淮一夢三十里，有日無風神所借。", "似憐憂患滿人間，百孔千瘡容一罅。", "文章末技將自效，語不驚人神可嚇。", "子女玉帛君所餘，寄聲白鳥煩多謝。"]'),
('a0f1e2c1-9daf-4093-a1b7-a438de6d4660','泛淮','陳師道','宋','宋诗','song-poetry','','[]','冬暖仍初日，潮回更下風。',48,'全唐诗/poet.song.62000.json','["冬暖仍初日，潮回更下風。", "鳥飛雲水裏，人語櫓聲中。", "平野容回顧，無山會有終。", "倚檣聊自逸，吟嘯不須工。"]'),
('42a5df3a-36ef-4a5e-a7ea-f8eea50fab44','猴馬','陳師道','宋','宋诗','song-poetry','','[]','沐猴自戲馬自驚，圉人未解猴馬情。',64,'全唐诗/poet.song.62000.json','["沐猴自戲馬自驚，圉人未解猴馬情。", "猴其天資馬何罪，意欲防患猶傷生。", "異類相宜亦相失，同類相傷非所及。", "志行萬里困一誤，吐豆齕荄甘伏櫪。"]'),
('60d3502e-9160-4f41-86bf-ba2b88da9d03','徐氏閑軒','陳師道','宋','宋诗','song-poetry','','[]','倦游梁楚愛吾廬，老寄山林孰與娛。',64,'全唐诗/poet.song.62000.json','["倦游梁楚愛吾廬，老寄山林孰與娛。", "想見杖藜臨過鳥，更能赤手縛於菟。", "君寧平世輕三釜，我亦東原有一區。", "擬買嬋娟作歸計，可無堆玉斗量珠。"]');
